        private bool TryReorderTextAnnotation(TextAnnotation annotation, Func<TextAnnotation, bool> reorderAction)
        {
            if (annotation == null || reorderAction == null)
            {
                return false;
            }

            EnsureTextAnnotationId(annotation);

            if (!EnsureCurrentPageEditable(true))
            {
                return true;
            }

            if (annotation.AnnotationIsLocked)
            {
                MessageBox.Show(
                    this,
                    string.Format(LocalizedText("Msg_TextPositionInfo"), LocalizedText("Msg_TextAnnotation_Locked")),
                    Resources.Title_Info,
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information);
                return true;
            }

            if (!reorderAction(annotation))
            {
                return true;
            }

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
            return true;
        }

        private void ShowTextOrderMenu(TextAnnotation annotation)
        {
            if (annotation == null)
            {
                return;
            }

            var menu = new ContextMenuStrip();
            menu.Items.Add(LocalizedText("Order_BringToFront"), null, (_, __) => TryReorderTextAnnotation(annotation, BringTextAnnotationToFront));
            menu.Items.Add(LocalizedText("Order_MoveForward"), null, (_, __) => TryReorderTextAnnotation(annotation, MoveTextAnnotationForward));
            menu.Items.Add(LocalizedText("Order_MoveBackward"), null, (_, __) => TryReorderTextAnnotation(annotation, MoveTextAnnotationBackward));
            menu.Items.Add(LocalizedText("Order_SendToBack"), null, (_, __) => TryReorderTextAnnotation(annotation, SendTextAnnotationToBack));

            Point location = pdfViewer.PointToClient(Cursor.Position);
            menu.Show(pdfViewer, location);
        }

        private bool TryPasteObjectsFromInternalClipboard()
        {
            if (objectClipboardSnapshot == null || objectClipboardSnapshot.Items.Count == 0)
            {
                return false;
            }

            if (pdf == null || numPages <= 0)
            {
                return false;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return true;
            }

            bool isSingleRasterPaste =
                objectClipboardSnapshot.Items.Count == 1 &&
                objectClipboardSnapshot.Items[0] != null &&
                objectClipboardSnapshot.Items[0].Type == ObjectClipboardItemType.Raster &&
                objectClipboardSnapshot.Items[0].Raster != null;

            float offset = 12f * (objectClipboardPasteCount + 1);
            float baseX = objectClipboardSnapshot.SourceBounds.X + offset;
            float baseY = objectClipboardSnapshot.SourceBounds.Y + offset;
            DateTime now = DateTime.UtcNow;

            var pastedTextAnnotations = new List<TextAnnotation>();
            var pastedRasterObjects = new List<RasterObject>();
            var pastedArrowObjects = new List<ArrowObject>();
            var pastedVectorShapes = new List<VectorShapeObject>();

            foreach (ObjectClipboardItem item in objectClipboardSnapshot.Items)
            {
                if (item == null)
                {
                    continue;
                }

                switch (item.Type)
                {
                    case ObjectClipboardItemType.Text:
                    {
                        if (item.Text == null)
                        {
                            break;
                        }

                        RectangleF bounds = new RectangleF(
                            baseX + item.Bounds.X,
                            baseY + item.Bounds.Y,
                            item.Bounds.Width,
                            item.Bounds.Height);
                        bounds = ConstrainAnnotationBoundsToViewer(bounds);
                        var textCopy = new TextAnnotation
                        {
                            Id = Guid.NewGuid().ToString("N"),
                            PageNumber = currentPage,
                            AnnotationText = item.Text.AnnotationText,
                            AnnotationFont = CloneFontSafe(item.Text.AnnotationFont),
                            AnnotationColor = item.Text.AnnotationColor,
                            AnnotationBackgroundColorArgb = item.Text.AnnotationBackgroundColorArgb,
                            AnnotationContentMode = item.Text.AnnotationContentMode,
                            AnnotationRichText = item.Text.AnnotationRichText,
                            AnnotationAlignment = item.Text.AnnotationAlignment,
                            AnnotationRotation = item.Text.AnnotationRotation,
                            AnnotationBounds = bounds,
                            AnnotationIsLocked = item.Text.AnnotationIsLocked
                        };
                        StampTextAnnotationCreated(textCopy);
                        textAnnotations.Add(textCopy);
                        pastedTextAnnotations.Add(textCopy);
                        break;
                    }
                    case ObjectClipboardItemType.Raster:
                    {
                        if (item.Raster == null)
                        {
                            break;
                        }

                        RectangleF bounds;
                        if (isSingleRasterPaste)
                        {
                            var pageSize = GetPageSizeWithOffset(currentPage);
                            float centerX = pageSize.Width / 2f;
                            float centerY = pageSize.Height / 2f;
                            bounds = new RectangleF(
                                centerX - (item.Bounds.Width / 2f),
                                centerY - (item.Bounds.Height / 2f),
                                item.Bounds.Width,
                                item.Bounds.Height);
                        }
                        else
                        {
                            bounds = new RectangleF(
                                baseX + item.Bounds.X,
                                baseY + item.Bounds.Y,
                                item.Bounds.Width,
                                item.Bounds.Height);
                        }

                        var rasterCopy = new RasterObject
                        {
                            Id = Guid.NewGuid().ToString("N"),
                            PageNumber = currentPage,
                            Bounds = bounds,
                            InitialBounds = bounds,
                            Rotation = item.Raster.Rotation,
                            Opacity = item.Raster.Opacity,
                            TransparentBackground = item.Raster.TransparentBackground,
                            LockAspect = item.Raster.LockAspect,
                            IsLocked = item.Raster.IsLocked,
                            SourceType = item.Raster.SourceType,
                            FilePath = item.Raster.FilePath,
                            EmbeddedBytes = item.Raster.EmbeddedBytes == null ? null : (byte[])item.Raster.EmbeddedBytes.Clone(),
                            MimeType = item.Raster.MimeType,
                            CreatedAtUtc = now,
                            UpdatedAtUtc = now
                        };
                        ConstrainRasterObjectToPage(rasterCopy);
                        rasterCopy.InitialBounds = rasterCopy.Bounds;
                        rasterObjects.Add(rasterCopy);
                        pastedRasterObjects.Add(rasterCopy);
                        break;
                    }
                    case ObjectClipboardItemType.Arrow:
                    {
                        if (item.Arrow == null)
                        {
                            break;
                        }

                        var arrowCopy = new ArrowObject
                        {
                            Id = Guid.NewGuid().ToString("N"),
                            PageNumber = currentPage,
                            Start = new PointF(baseX + item.Arrow.Start.X, baseY + item.Arrow.Start.Y),
                            End = new PointF(baseX + item.Arrow.End.X, baseY + item.Arrow.End.Y),
                            LineColorArgb = item.Arrow.LineColorArgb,
                            Thickness = NormalizeArrowThickness(item.Arrow.Thickness),
                            HeadLength = NormalizeArrowHeadLength(item.Arrow.HeadLength),
                            HeadWidth = NormalizeArrowHeadWidth(item.Arrow.HeadWidth),
                            IsLocked = item.Arrow.IsLocked,
                            CreatedAtUtc = now,
                            UpdatedAtUtc = now
                        };
                        ConstrainArrowToPage(arrowCopy);
                        arrowObjects.Add(arrowCopy);
                        pastedArrowObjects.Add(arrowCopy);
                        break;
                    }
                    case ObjectClipboardItemType.VectorShape:
                    {
                        if (item.VectorShape == null)
                        {
                            break;
                        }

                        var vectorCopy = new VectorShapeObject
                        {
                            Id = Guid.NewGuid().ToString("N"),
                            PageNumber = currentPage,
                            ShapeType = item.VectorShape.ShapeType,
                            Points = (item.VectorShape.Points ?? new List<PointF>())
                                .Select(point => new PointF(baseX + point.X, baseY + point.Y))
                                .ToList(),
                            StrokeColorArgb = item.VectorShape.StrokeColorArgb,
                            StrokeWidth = NormalizeVectorStrokeWidth(item.VectorShape.StrokeWidth),
                            FillColorArgb = item.VectorShape.FillColorArgb,
                            FillPatternColorArgb = item.VectorShape.FillPatternColorArgb,
                            FillOpacity = NormalizeVectorFillOpacity(item.VectorShape.FillOpacity),
                            StrokeStyle = item.VectorShape.StrokeStyle,
                            FillPattern = item.VectorShape.FillPattern,
                            IsLocked = item.VectorShape.IsLocked,
                            CreatedAtUtc = now,
                            UpdatedAtUtc = now
                        };
                        NormalizeVectorShape(vectorCopy);
                        ConstrainVectorShapeToPage(vectorCopy);
                        vectorShapes.Add(vectorCopy);
                        pastedVectorShapes.Add(vectorCopy);
                        break;
                    }
                }
            }

            int pastedCount = pastedTextAnnotations.Count + pastedRasterObjects.Count + pastedArrowObjects.Count + pastedVectorShapes.Count;
            if (pastedCount <= 0)
            {
                return true;
            }

            EnsureObjectLayerOrder();
            foreach (TextAnnotation textAnnotation in pastedTextAnnotations)
            {
                BringTextAnnotationToFront(textAnnotation);
            }
            foreach (RasterObject rasterObject in pastedRasterObjects)
            {
                BringRasterObjectToFront(rasterObject);
            }
            foreach (ArrowObject arrowObject in pastedArrowObjects)
            {
                BringArrowObjectToFront(arrowObject);
            }
            foreach (VectorShapeObject vectorShapeObject in pastedVectorShapes)
            {
                BringVectorShapeToFront(vectorShapeObject);
            }

            ClearGroupSelection();
            selectedTextAnnotation = null;
            selectedRasterObject = null;
            selectedArrowObject = null;
            selectedVectorShape = null;
            ResetTextRotationInteractionState();
            ResetRasterInteractionState();
            ResetArrowInteractionState();
            ResetVectorInteractionState();
            ResetGroupMoveState();

            if (pastedCount == 1)
            {
                if (pastedTextAnnotations.Count == 1)
                {
                    selectedTextAnnotation = pastedTextAnnotations[0];
                }
                else if (pastedRasterObjects.Count == 1)
                {
                    selectedRasterObject = pastedRasterObjects[0];
                }
                else if (pastedArrowObjects.Count == 1)
                {
                    selectedArrowObject = pastedArrowObjects[0];
                }
                else if (pastedVectorShapes.Count == 1)
                {
                    selectedVectorShape = pastedVectorShapes[0];
                }
            }
            else
            {
                foreach (TextAnnotation textAnnotation in pastedTextAnnotations)
                {
                    selectedTextAnnotations.Add(textAnnotation);
                }
                foreach (RasterObject rasterObject in pastedRasterObjects)
                {
                    selectedRasterObjectIds.Add(rasterObject.Id);
                }
                foreach (ArrowObject arrowObject in pastedArrowObjects)
                {
                    selectedArrowObjectIds.Add(arrowObject.Id);
                }
                foreach (VectorShapeObject vectorShape in pastedVectorShapes)
                {
                    selectedVectorShapeIds.Add(vectorShape.Id);
                }
            }

            objectClipboardPasteCount++;
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            UpdateCurrentPageObjectsMarker();
            pdfViewer.Invalidate();
            return true;
        }

        private void ClearGroupSelection()
        {
            selectedTextAnnotations.Clear();
            selectedRasterObjectIds.Clear();
            selectedArrowObjectIds.Clear();
            selectedVectorShapeIds.Clear();
        }

        private void ResetGroupMoveState()
        {
            isMovingObjectGroup = false;
            groupMoveChanged = false;
            groupMoveEntries.Clear();
            groupMoveStartMouseDoc = PointF.Empty;
            groupMoveInitialBounds = RectangleF.Empty;
            groupMoveMinDx = 0f;
            groupMoveMaxDx = 0f;
            groupMoveMinDy = 0f;
            groupMoveMaxDy = 0f;
        }

        private void PromoteSingleSelectionsToGroup()
        {
            if (selectedTextAnnotation != null && selectedTextAnnotation.PageNumber == currentPage)
            {
                selectedTextAnnotations.Add(selectedTextAnnotation);
            }

            if (selectedRasterObject != null && selectedRasterObject.PageNumber == currentPage && !string.IsNullOrWhiteSpace(selectedRasterObject.Id))
            {
                selectedRasterObjectIds.Add(selectedRasterObject.Id);
            }

            if (selectedArrowObject != null && selectedArrowObject.PageNumber == currentPage && !string.IsNullOrWhiteSpace(selectedArrowObject.Id))
            {
                selectedArrowObjectIds.Add(selectedArrowObject.Id);
            }

            if (selectedVectorShape != null && selectedVectorShape.PageNumber == currentPage && !string.IsNullOrWhiteSpace(selectedVectorShape.Id))
            {
                selectedVectorShapeIds.Add(selectedVectorShape.Id);
            }

            selectedTextAnnotation = null;
            selectedRasterObject = null;
            selectedArrowObject = null;
            selectedVectorShape = null;
        }

        private void CollapseGroupSelectionToSingleIfNeeded()
        {
            if (GetGroupSelectionCount() != 1)
            {
                return;
            }

            TextAnnotation onlyText = selectedTextAnnotations.FirstOrDefault();
            if (onlyText != null)
            {
                selectedTextAnnotation = onlyText;
                selectedRasterObject = null;
                selectedArrowObject = null;
                ClearGroupSelection();
                return;
            }

            string rasterId = selectedRasterObjectIds.FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(rasterId))
            {
                selectedRasterObject = rasterObjects.FirstOrDefault(r => r != null && r.Id == rasterId);
                selectedTextAnnotation = null;
                selectedArrowObject = null;
                ClearGroupSelection();
                return;
            }

            string arrowId = selectedArrowObjectIds.FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(arrowId))
            {
                selectedArrowObject = arrowObjects.FirstOrDefault(a => a != null && a.Id == arrowId);
                selectedTextAnnotation = null;
                selectedRasterObject = null;
                ClearGroupSelection();
                return;
            }

            string vectorId = selectedVectorShapeIds.FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(vectorId))
            {
                selectedVectorShape = vectorShapes.FirstOrDefault(v => v != null && v.Id == vectorId);
                selectedTextAnnotation = null;
                selectedRasterObject = null;
                selectedArrowObject = null;
                ClearGroupSelection();
            }
        }

        private bool TryGetHitArrowAtPoint(Point location, out ArrowObject hitArrow)
        {
            hitArrow = arrowObjects
                .Where(obj => obj != null && obj.PageNumber == currentPage)
                .Reverse()
                .FirstOrDefault(obj => IsPointNearArrowLine(obj, location) || TryGetArrowHandleAtPoint(obj, location, out _));
            return hitArrow != null;
        }

        private bool TryGetHitRasterAtPoint(Point location, out RasterObject hitRaster)
        {
            hitRaster = rasterObjects
                .Where(obj => obj != null && obj.PageNumber == currentPage)
                .Reverse()
                .FirstOrDefault(obj => IsPointInsideRasterObject(obj, location));
            return hitRaster != null;
        }

        private bool TryGetHitTextAtPoint(Point location, float dpiX, float dpiY, out TextAnnotation hitText)
        {
            hitText = textAnnotations
                .Where(a => a != null && a.PageNumber == currentPage)
                .Reverse()
                .FirstOrDefault(a => GetAnnotationScreenRect(a, dpiX, dpiY).Contains(location));
            return hitText != null;
        }

        private static RectangleF GetVectorShapeBounds(IList<PointF> points)
        {
            if (points == null || points.Count == 0)
            {
                return RectangleF.Empty;
            }

            float minX = float.MaxValue;
            float minY = float.MaxValue;
            float maxX = float.MinValue;
            float maxY = float.MinValue;
            foreach (PointF point in points)
            {
                minX = Math.Min(minX, point.X);
                minY = Math.Min(minY, point.Y);
                maxX = Math.Max(maxX, point.X);
                maxY = Math.Max(maxY, point.Y);
            }

            if (minX == float.MaxValue || minY == float.MaxValue || maxX == float.MinValue || maxY == float.MinValue)
            {
                return RectangleF.Empty;
            }

            return RectangleF.FromLTRB(minX, minY, maxX, maxY);
        }

        private bool IsPointNearVectorShape(VectorShapeObject vectorShape, Point location)
        {
            if (vectorShape == null || vectorShape.PageNumber != currentPage || vectorShape.Points == null || vectorShape.Points.Count < 2)
            {
                return false;
            }

            VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
            PointF[] points = BuildVectorShapeRenderPoints(shapeType, vectorShape.Points)
                .Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor))
                .ToArray();
            if (points.Length < 2)
            {
                return false;
            }

            float tolerance = Math.Max(6f, (NormalizeVectorStrokeWidth(vectorShape.StrokeWidth) * scaleFactor) + 2f);
            var locationF = new PointF(location.X, location.Y);
            bool closedShape = IsShapeClosed(shapeType);
            using (var path = new GraphicsPath())
            using (var outlinePen = new Pen(System.Drawing.Color.Black, tolerance * 2f))
            {
                outlinePen.LineJoin = LineJoin.Round;
                outlinePen.StartCap = LineCap.Round;
                outlinePen.EndCap = LineCap.Round;

                if (closedShape && points.Length >= 3)
                {
                    path.AddPolygon(points);
                    if (path.IsVisible(locationF))
                    {
                        return true;
                    }

                    return path.IsOutlineVisible(locationF, outlinePen);
                }

                path.AddLines(points);
                if (path.IsOutlineVisible(locationF, outlinePen))
                {
                    return true;
                }

                for (int i = 1; i < points.Length; i++)
                {
                    if (DistancePointToSegment(locationF, points[i - 1], points[i]) <= tolerance)
                    {
                        return true;
                    }
                }
            }

            return false;
        }

        private bool TryGetHitVectorShapeAtPoint(Point location, out VectorShapeObject hitVectorShape)
        {
            hitVectorShape = null;
            EnsureObjectLayerOrder();

            foreach (var layer in objectLayerOrder.AsEnumerable().Reverse())
            {
                if (layer == null || layer.Type != LayerObjectType.VectorShape || string.IsNullOrWhiteSpace(layer.Id))
                {
                    continue;
                }

                VectorShapeObject candidate = vectorShapes.FirstOrDefault(v => v != null && v.PageNumber == currentPage && string.Equals(v.Id, layer.Id, StringComparison.Ordinal));
                if (candidate == null)
                {
                    continue;
                }

                if (IsPointNearVectorShape(candidate, location))
                {
                    hitVectorShape = candidate;
                    return true;
                }
            }

            return false;
        }

        private bool TryHandleObjectDoubleClick(Point location)
        {
            if (TryGetHitVectorShapeAtPoint(location, out VectorShapeObject hitVectorShape) && hitVectorShape != null)
            {
                EditVectorShapeObject(hitVectorShape);
                return true;
            }

            if (TryGetHitArrowAtPoint(location, out ArrowObject hitArrow) && hitArrow != null)
            {
                EditArrowObject(hitArrow);
                return true;
            }

            if (TryGetHitRasterAtPoint(location, out RasterObject hitRaster) && hitRaster != null)
            {
                EditRasterObject(hitRaster);
                return true;
            }

            return false;
        }

        private bool TryToggleGroupSelectionAtPoint(Point location, float dpiX, float dpiY)
        {
            if (TryGetHitVectorShapeAtPoint(location, out VectorShapeObject hitVectorShape))
            {
                EnsureVectorShapeId(hitVectorShape);
                PromoteSingleSelectionsToGroup();
                if (!string.IsNullOrWhiteSpace(hitVectorShape.Id) && !selectedVectorShapeIds.Add(hitVectorShape.Id))
                {
                    selectedVectorShapeIds.Remove(hitVectorShape.Id);
                }
                CollapseGroupSelectionToSingleIfNeeded();
                return true;
            }

            if (TryGetHitArrowAtPoint(location, out ArrowObject hitArrow))
            {
                EnsureArrowObjectId(hitArrow);
                PromoteSingleSelectionsToGroup();
                if (!string.IsNullOrWhiteSpace(hitArrow.Id) && !selectedArrowObjectIds.Add(hitArrow.Id))
                {
                    selectedArrowObjectIds.Remove(hitArrow.Id);
                }
                CollapseGroupSelectionToSingleIfNeeded();
                return true;
            }

            if (TryGetHitRasterAtPoint(location, out RasterObject hitRaster))
            {
                EnsureRasterObjectId(hitRaster);
                PromoteSingleSelectionsToGroup();
                if (!string.IsNullOrWhiteSpace(hitRaster.Id) && !selectedRasterObjectIds.Add(hitRaster.Id))
                {
                    selectedRasterObjectIds.Remove(hitRaster.Id);
                }
                CollapseGroupSelectionToSingleIfNeeded();
                return true;
            }

            if (TryGetHitTextAtPoint(location, dpiX, dpiY, out TextAnnotation hitText))
            {
                PromoteSingleSelectionsToGroup();
                if (!selectedTextAnnotations.Add(hitText))
                {
                    selectedTextAnnotations.Remove(hitText);
                }
                CollapseGroupSelectionToSingleIfNeeded();
                return true;
            }

            return false;
        }

        private bool TryBeginGroupMove(Point location, float dpiX, float dpiY)
        {
            if (GetGroupSelectionCount() < 2)
            {
                return false;
            }

            bool hitSelected = false;
            if (TryGetHitVectorShapeAtPoint(location, out VectorShapeObject hitVectorShape) &&
                hitVectorShape != null &&
                !string.IsNullOrWhiteSpace(hitVectorShape.Id) &&
                selectedVectorShapeIds.Contains(hitVectorShape.Id))
            {
                hitSelected = true;
            }
            else if (TryGetHitArrowAtPoint(location, out ArrowObject hitArrow) &&
                hitArrow != null &&
                !string.IsNullOrWhiteSpace(hitArrow.Id) &&
                selectedArrowObjectIds.Contains(hitArrow.Id))
            {
                hitSelected = true;
            }
            else if (TryGetHitRasterAtPoint(location, out RasterObject hitRaster) &&
                hitRaster != null &&
                !string.IsNullOrWhiteSpace(hitRaster.Id) &&
                selectedRasterObjectIds.Contains(hitRaster.Id))
            {
                hitSelected = true;
            }
            else if (TryGetHitTextAtPoint(location, dpiX, dpiY, out TextAnnotation hitText) &&
                hitText != null &&
                selectedTextAnnotations.Contains(hitText))
            {
                hitSelected = true;
            }

            if (!hitSelected)
            {
                return false;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return true;
            }

            bool hasLockedSelection =
                selectedTextAnnotations.Any(t => t != null && t.PageNumber == currentPage && t.AnnotationIsLocked) ||
                selectedRasterObjectIds.Any(id => rasterObjects.Any(r => r != null && r.PageNumber == currentPage && r.Id == id && r.IsLocked)) ||
                selectedArrowObjectIds.Any(id => arrowObjects.Any(a => a != null && a.PageNumber == currentPage && a.Id == id && a.IsLocked)) ||
                selectedVectorShapeIds.Any(id => vectorShapes.Any(v => v != null && v.PageNumber == currentPage && v.Id == id && v.IsLocked));

            if (hasLockedSelection)
            {
                MessageBox.Show(
                    this,
                    string.Format(LocalizedText("Msg_TextPositionInfo"), LocalizedText("Msg_TextAnnotation_Locked")),
                    Resources.Title_Info,
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information);
                return true;
            }

            groupMoveEntries.Clear();
            float minX = float.MaxValue;
            float minY = float.MaxValue;
            float maxX = float.MinValue;
            float maxY = float.MinValue;

            foreach (var text in selectedTextAnnotations.Where(t => t != null && t.PageNumber == currentPage && !t.AnnotationIsLocked))
            {
                RectangleF bounds = text.AnnotationBounds;
                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.Text,
                    Text = text,
                    Bounds = bounds
                });

                minX = Math.Min(minX, bounds.Left);
                minY = Math.Min(minY, bounds.Top);
                maxX = Math.Max(maxX, bounds.Right);
                maxY = Math.Max(maxY, bounds.Bottom);
            }

            foreach (var rasterId in selectedRasterObjectIds)
            {
                RasterObject raster = rasterObjects.FirstOrDefault(r => r != null && r.PageNumber == currentPage && r.Id == rasterId && !r.IsLocked);
                if (raster == null)
                {
                    continue;
                }

                RectangleF bounds = raster.Bounds;
                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.Raster,
                    Raster = raster,
                    Bounds = bounds
                });

                minX = Math.Min(minX, bounds.Left);
                minY = Math.Min(minY, bounds.Top);
                maxX = Math.Max(maxX, bounds.Right);
                maxY = Math.Max(maxY, bounds.Bottom);
            }

            foreach (var arrowId in selectedArrowObjectIds)
            {
                ArrowObject arrow = arrowObjects.FirstOrDefault(a => a != null && a.PageNumber == currentPage && a.Id == arrowId && !a.IsLocked);
                if (arrow == null)
                {
                    continue;
                }

                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.Arrow,
                    Arrow = arrow,
                    Start = arrow.Start,
                    End = arrow.End
                });

                float arrowMinX = Math.Min(arrow.Start.X, arrow.End.X);
                float arrowMaxX = Math.Max(arrow.Start.X, arrow.End.X);
                float arrowMinY = Math.Min(arrow.Start.Y, arrow.End.Y);
                float arrowMaxY = Math.Max(arrow.Start.Y, arrow.End.Y);
                minX = Math.Min(minX, arrowMinX);
                minY = Math.Min(minY, arrowMinY);
                maxX = Math.Max(maxX, arrowMaxX);
                maxY = Math.Max(maxY, arrowMaxY);
            }

            foreach (var vectorId in selectedVectorShapeIds)
            {
                VectorShapeObject vector = vectorShapes.FirstOrDefault(v => v != null && v.PageNumber == currentPage && v.Id == vectorId && !v.IsLocked);
                if (vector == null)
                {
                    continue;
                }

                RectangleF bounds = GetVectorShapeBounds(vector.Points);
                if (bounds.IsEmpty)
                {
                    continue;
                }
                groupMoveEntries.Add(new GroupMoveEntry
                {
                    Type = GroupMoveObjectType.VectorShape,
                    VectorShape = vector,
                    Points = (vector.Points ?? new List<PointF>()).Select(p => p).ToList(),
                    Bounds = bounds
                });

                minX = Math.Min(minX, bounds.Left);
                minY = Math.Min(minY, bounds.Top);
                maxX = Math.Max(maxX, bounds.Right);
                maxY = Math.Max(maxY, bounds.Bottom);
            }

            if (groupMoveEntries.Count == 0 || minX == float.MaxValue || minY == float.MaxValue)
            {
                return true;
            }

            groupMoveInitialBounds = RectangleF.FromLTRB(minX, minY, maxX, maxY);
            groupMoveMinDx = float.NegativeInfinity;
            groupMoveMaxDx = float.PositiveInfinity;
            groupMoveMinDy = float.NegativeInfinity;
            groupMoveMaxDy = float.PositiveInfinity;

            float clientWidth = pdfViewer.ClientSize.Width;
            float clientHeight = pdfViewer.ClientSize.Height;
            var pageSize = GetPageSizeWithOffset(currentPage);

            foreach (GroupMoveEntry entry in groupMoveEntries)
            {
                switch (entry.Type)
                {
                    case GroupMoveObjectType.Text:
                        float textMinX = -(entry.Bounds.Width * 72f / dpiX / 2f);
                        float textMaxX = (clientWidth / scaleFactor) - (entry.Bounds.Width * 72f / dpiX / 2f);
                        float textMinY = -(entry.Bounds.Height * 72f / dpiX / 2f);
                        float textMaxY = (clientHeight / scaleFactor) - (entry.Bounds.Height * 72f / dpiX / 2f);
                        groupMoveMinDx = Math.Max(groupMoveMinDx, textMinX - entry.Bounds.X);
                        groupMoveMaxDx = Math.Min(groupMoveMaxDx, textMaxX - entry.Bounds.X);
                        groupMoveMinDy = Math.Max(groupMoveMinDy, textMinY - entry.Bounds.Y);
                        groupMoveMaxDy = Math.Min(groupMoveMaxDy, textMaxY - entry.Bounds.Y);
                        break;
                    case GroupMoveObjectType.Raster:
                        groupMoveMinDx = Math.Max(groupMoveMinDx, -entry.Bounds.Left);
                        groupMoveMaxDx = Math.Min(groupMoveMaxDx, pageSize.Width - entry.Bounds.Right);
                        groupMoveMinDy = Math.Max(groupMoveMinDy, -entry.Bounds.Top);
                        groupMoveMaxDy = Math.Min(groupMoveMaxDy, pageSize.Height - entry.Bounds.Bottom);
                        break;
                    case GroupMoveObjectType.Arrow:
                        float arrowMinX = Math.Min(entry.Start.X, entry.End.X);
                        float arrowMaxX = Math.Max(entry.Start.X, entry.End.X);
                        float arrowMinY = Math.Min(entry.Start.Y, entry.End.Y);
                        float arrowMaxY = Math.Max(entry.Start.Y, entry.End.Y);
                        groupMoveMinDx = Math.Max(groupMoveMinDx, -arrowMinX);
                        groupMoveMaxDx = Math.Min(groupMoveMaxDx, pageSize.Width - arrowMaxX);
                        groupMoveMinDy = Math.Max(groupMoveMinDy, -arrowMinY);
                        groupMoveMaxDy = Math.Min(groupMoveMaxDy, pageSize.Height - arrowMaxY);
                        break;
                    case GroupMoveObjectType.VectorShape:
                        groupMoveMinDx = Math.Max(groupMoveMinDx, -entry.Bounds.Left);
                        groupMoveMaxDx = Math.Min(groupMoveMaxDx, pageSize.Width - entry.Bounds.Right);
                        groupMoveMinDy = Math.Max(groupMoveMinDy, -entry.Bounds.Top);
                        groupMoveMaxDy = Math.Min(groupMoveMaxDy, pageSize.Height - entry.Bounds.Bottom);
                        break;
                }
            }

            groupMoveStartMouseDoc = new PointF(location.X / scaleFactor, location.Y / scaleFactor);
            BeginUndoCapture("Move object group");
            isMovingObjectGroup = true;
            groupMoveChanged = false;
            this.Cursor = Cursors.SizeAll;
            return true;
        }

