        private static PointF GetRotationOffsetForBounds(int rotation, float width, float height)
        {
            rotation = NormalizeRotation(rotation);
            if (rotation == 0)
                return new PointF(0f, 0f);

            float angle = (float)(rotation * Math.PI / 180.0);
            float cos = (float)Math.Cos(angle);
            float sin = (float)Math.Sin(angle);

            PointF[] points =
            {
                new PointF(0f, 0f),
                new PointF(width, 0f),
                new PointF(width, height),
                new PointF(0f, height)
            };

            float minX = float.MaxValue;
            float minY = float.MaxValue;
            foreach (PointF pt in points)
            {
                float x = pt.X * cos - pt.Y * sin;
                float y = pt.X * sin + pt.Y * cos;
                if (x < minX)
                    minX = x;
                if (y < minY)
                    minY = y;
            }

            return new PointF(-minX, -minY);
        }

        private static void ApplyAnnotationFromDialog(TextAnnotation annotation, EditTextDialog dlg)
        {
            SizeF textSize = dlg.IsRichTextMode
                ? GetRichAnnotationSize(dlg.AnnotationText, dlg.AnnotationRichText, dlg.AnnotationFont, dlg.AnnotationRotation)
                : GetAnnotationSize(dlg.AnnotationText, dlg.AnnotationFont, dlg.AnnotationRotation);
            annotation.AnnotationText = dlg.AnnotationText;
            annotation.AnnotationFont = dlg.AnnotationFont;
            annotation.AnnotationColor = dlg.AnnotationColor;
            annotation.AnnotationBackgroundColorArgb = dlg.AnnotationBackgroundColor.ToArgb();
            annotation.AnnotationContentMode = dlg.IsRichTextMode ? "rich" : "plain";
            annotation.AnnotationRichText = dlg.IsRichTextMode ? dlg.AnnotationRichText : null;
            annotation.AnnotationAlignment = dlg.AnnotationAlignment;
            annotation.AnnotationRotation = dlg.AnnotationRotation;
            annotation.AnnotationBounds = new RectangleF(
                annotation.AnnotationBounds.X,
                annotation.AnnotationBounds.Y,
                textSize.Width,
                textSize.Height
            );
            TouchTextAnnotation(annotation);
        }

        private static System.Drawing.Color GetAnnotationBackgroundColor(TextAnnotation annotation)
        {
            if (annotation == null)
            {
                return System.Drawing.Color.Transparent;
            }

            try
            {
                return System.Drawing.Color.FromArgb(annotation.AnnotationBackgroundColorArgb);
            }
            catch
            {
                return System.Drawing.Color.Transparent;
            }
        }

        private static bool IsRichTextMode(TextAnnotation annotation)
        {
            return annotation != null &&
                   string.Equals(annotation.AnnotationContentMode, "rich", StringComparison.OrdinalIgnoreCase) &&
                   !string.IsNullOrWhiteSpace(annotation.AnnotationRichText);
        }

        private static void LogDebug(string message)
        {
            if (!DebugLogEnabled || string.IsNullOrWhiteSpace(message))
            {
                return;
            }

            try
            {
                string line = $"{DateTime.Now:yyyy-MM-dd HH:mm:ss.fff} {message}{Environment.NewLine}";
                File.AppendAllText(DebugLogPath, line);
            }
            catch
            {
                // Ignore logging failures.
            }
        }

        private void OpenDiagnosticLogIfEnabled()
        {
            if (!DebugLogEnabled)
            {
                return;
            }

            try
            {
                if (!File.Exists(DebugLogPath))
                {
                    return;
                }

                ProcessStartInfo psi = new ProcessStartInfo
                {
                    FileName = "notepad.exe",
                    Arguments = $"\"{DebugLogPath}\"",
                    UseShellExecute = false
                };
                Process.Start(psi);
            }
            catch (Exception ex)
            {
                LogDebug($"Open diagnostic log failed: {ex.Message}");
            }
        }

        private void PersistCurrentPageToProjectFile()
        {
            if (numPages <= 0)
                return;

            string projectPath = !string.IsNullOrWhiteSpace(lastSavedProjectName)
                ? lastSavedProjectName
                : inputProjectPath;

            if (string.IsNullOrWhiteSpace(projectPath) || !File.Exists(projectPath))
                return;

            try
            {
                string json = File.ReadAllText(projectPath);
                JObject root = JObject.Parse(json);
                int pageToSave = Math.Max(1, Math.Min(currentPage, numPages));
                root["CurrentPage"] = pageToSave;
                CaptureCurrentViewState(out float zoomFactor, out int scrollX, out int scrollY);
                CaptureRightPanelsViewState(out int? pagesListTopPage, out int? thumbnailsTopPage);
                root["ZoomFactor"] = zoomFactor;
                root["ScrollX"] = scrollX;
                root["ScrollY"] = scrollY;
                root["PagesListTopPage"] = pagesListTopPage.HasValue ? JToken.FromObject(pagesListTopPage.Value) : JValue.CreateNull();
                root["ThumbnailsTopPage"] = thumbnailsTopPage.HasValue ? JToken.FromObject(thumbnailsTopPage.Value) : JValue.CreateNull();
                File.WriteAllText(projectPath, root.ToString(Formatting.Indented));
            }
            catch
            {
                // Keep closing flow even if project update fails.
            }
        }

        private void AddEditAnnotation(TextAnnotation annotation = null, string initialText = null)
        {
            DeactivateObjectCreationModes();

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            using (EditTextDialog dlg = new EditTextDialog())
            {
                // If we are editing an existing annotation â€“ set default values in the dialog
                if (annotation != null)
                {
                    dlg.AnnotationText = annotation.AnnotationText;
                    dlg.AnnotationFont = annotation.AnnotationFont;
                    dlg.AnnotationColor = annotation.AnnotationColor;
                    dlg.AnnotationBackgroundColor = GetAnnotationBackgroundColor(annotation);
                    dlg.IsRichTextMode = string.Equals(annotation.AnnotationContentMode, "rich", StringComparison.OrdinalIgnoreCase);
                    dlg.AnnotationRichText = annotation.AnnotationRichText;
                    dlg.AnnotationAlignment = annotation.AnnotationAlignment;
                    dlg.AnnotationRotation = annotation.AnnotationRotation;
                    dlg.ApplyChanges = () =>
                    {
                        ApplyAnnotationFromDialog(annotation, dlg);
                        pdfViewer.Invalidate();
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                    };
                }
                else if (!string.IsNullOrWhiteSpace(initialText))
                {
                    dlg.AnnotationText = initialText;
                }

                if (dlg.ShowDialog(this) == DialogResult.OK)
                {
                    // Calculate text size using the selected font
                    SizeF textSize = dlg.IsRichTextMode
                        ? GetRichAnnotationSize(dlg.AnnotationText, dlg.AnnotationRichText, dlg.AnnotationFont, dlg.AnnotationRotation)
                        : GetAnnotationSize(dlg.AnnotationText, dlg.AnnotationFont, dlg.AnnotationRotation);

                    float boxWidth = textSize.Width;
                    float boxHeight = textSize.Height;

                    if (annotation != null)
                    {
                        // Edit mode â€“ updating existing annotation,
                        // preserving its original position (X, Y) and updating dimensions
                        ApplyAnnotationFromDialog(annotation, dlg);
                    }
                    else
                    {
                        // Add mode â€“ creating new annotation
                        TextAnnotation newAnnotation = new TextAnnotation
                        {
                            PageNumber = currentPage,
                            AnnotationText = dlg.AnnotationText,
                            AnnotationFont = dlg.AnnotationFont,
                            AnnotationColor = dlg.AnnotationColor,
                            AnnotationBackgroundColorArgb = dlg.AnnotationBackgroundColor.ToArgb(),
                            AnnotationContentMode = dlg.IsRichTextMode ? "rich" : "plain",
                            AnnotationRichText = dlg.IsRichTextMode ? dlg.AnnotationRichText : null,
                            AnnotationAlignment = dlg.AnnotationAlignment,
                            AnnotationRotation = dlg.AnnotationRotation
                        };
                        newAnnotation.AnnotationBounds = GetCenteredAnnotationBounds(boxWidth, boxHeight);

                        // Add the new annotation to the list
                        StampTextAnnotationCreated(newAnnotation);
                        textAnnotations.Add(newAnnotation);

                        

                        PageItemStatus status = allPageStatuses[currentPage - 1];
                        status.HasObjects = true;

                        if ((string)filterComboBox.SelectedItem == allComboItem)
                        {
                            ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                            UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                            pagesListView.Invalidate(currentItem.Bounds);
                        }
                        else
                        {
                            // rebuild list according to filter
                            ApplyFilter((string)filterComboBox.SelectedItem);
                        }


                    }

                    pdfViewer.Invalidate();

                    projectWasChangedAfterLastSave = true;
                    saveProjectButton.Enabled = true;
                    saveProjectMenuItem.Enabled = true;

                }
            }
        }

        private RectangleF GetCenteredAnnotationBounds(float width, float height)
        {
            ZoomPanel panel = mainAppSplitContainer.Panel2.Controls[0] as ZoomPanel;
            if (panel == null)
            {
                return new RectangleF(0f, 0f, width, height);
            }

            if (scaleFactor <= 0f)
            {
                return new RectangleF(0f, 0f, width, height);
            }

            int panelW = panel.ClientSize.Width;
            int panelH = panel.ClientSize.Height;
            int imgW = pdfViewer.Width;
            int imgH = pdfViewer.Height;
            int viewW = Math.Min(panelW, imgW);
            int viewH = Math.Min(panelH, imgH);
            int scrollX = panel.HorizontalScroll.Value;
            int scrollY = panel.VerticalScroll.Value;
            float docCenterX = (scrollX + viewW / 2f) / scaleFactor;
            float docCenterY = (scrollY + viewH / 2f) / scaleFactor;
            float x = docCenterX - width / 2f;
            float y = docCenterY - height / 2f;

            return new RectangleF(x, y, width, height);
        }

        private void DuplicateAnnotation(TextAnnotation source)
        {
            if (source == null)
                return;
            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            RectangleF copyBounds = source.AnnotationBounds;
            copyBounds.Offset(12f, 12f);
            copyBounds = ConstrainAnnotationBoundsToViewer(copyBounds);
            string duplicateGroupId = CreateDuplicateGroupId();

            TextAnnotation copy = new TextAnnotation
            {
                PageNumber = currentPage,
                AnnotationText = source.AnnotationText,
                AnnotationFont = source.AnnotationFont,
                AnnotationColor = source.AnnotationColor,
                AnnotationBackgroundColorArgb = source.AnnotationBackgroundColorArgb,
                AnnotationContentMode = source.AnnotationContentMode,
                AnnotationRichText = source.AnnotationRichText,
                AnnotationAlignment = source.AnnotationAlignment,
                AnnotationRotation = source.AnnotationRotation,
                AnnotationIsLocked = source.AnnotationIsLocked,
                AnnotationBounds = copyBounds,
                DuplicateGroupId = duplicateGroupId
            };

            StampTextAnnotationCreated(copy);
            textAnnotations.Add(copy);
            ClearGroupSelection();
            selectedTextAnnotation = copy;
            selectedRasterObject = null;
            selectedArrowObject = null;
            selectedVectorShape = null;

            PageItemStatus status = allPageStatuses[currentPage - 1];
            status.HasObjects = true;

            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                pagesListView.Invalidate(currentItem.Bounds);
            }
            else
            {
                ApplyFilter((string)filterComboBox.SelectedItem);
            }

            pdfViewer.Invalidate();
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
        }

        private RectangleF ConstrainAnnotationBoundsToViewer(RectangleF bounds)
        {
            if (pdfViewer == null || scaleFactor <= 0f)
            {
                return bounds;
            }

            float dpiX;
            using (Graphics g = pdfViewer.CreateGraphics())
            {
                dpiX = g.DpiX;
            }

            float clientWidth = pdfViewer.ClientSize.Width;
            float clientHeight = pdfViewer.ClientSize.Height;

            float minX = -(bounds.Width * 72f / dpiX / 2f);
            float maxX = (clientWidth / scaleFactor) - (bounds.Width * 72f / dpiX / 2f);
            float minY = -(bounds.Height * 72f / dpiX / 2f);
            float maxY = (clientHeight / scaleFactor) - (bounds.Height * 72f / dpiX / 2f);

            float x = bounds.X;
            float y = bounds.Y;

            if (x < minX) x = minX;
            if (x > maxX) x = maxX;
            if (y < minY) y = minY;
            if (y > maxY) y = maxY;

            return new RectangleF(x, y, bounds.Width, bounds.Height);
        }

        private void UpdateCurrentPageObjectsMarker()
        {
            if (currentPage < 1 || currentPage > allPageStatuses.Count)
            {
                return;
            }

            PageItemStatus status = allPageStatuses[currentPage - 1];
            status.HasObjects = HasAnyObjectsOnPage(currentPage);

            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                pagesListView.Invalidate(currentItem.Bounds);
            }
            else
            {
                ApplyFilter((string)filterComboBox.SelectedItem);
            }
        }

        private bool DeleteTextObjectWithConfirmation(TextAnnotation annotation)
        {
            if (annotation == null)
            {
                return false;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return true;
            }

            DialogResult result = MessageBox.Show(
                this,
                Resources.Msg_Confirm_DeleteTextAnnotation,
                Resources.Title_Confirmation,
                MessageBoxButtons.YesNo,
                MessageBoxIcon.Exclamation,
                MessageBoxDefaultButton.Button2);

            if (result != DialogResult.Yes)
            {
                return true;
            }

            textAnnotations.Remove(annotation);
            if (selectedTextAnnotation != null && ReferenceEquals(selectedTextAnnotation, annotation))
            {
                selectedTextAnnotation = null;
            }
            selectedTextAnnotations.Remove(annotation);

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            UpdateCurrentPageObjectsMarker();
            pdfViewer.Invalidate();
            return true;
        }

