        private bool SaveProjectForClose()
        {
            if (!HasUnsavedProjectContent())
            {
                return true;
            }

            if (string.IsNullOrWhiteSpace(lastSavedProjectName) && string.IsNullOrWhiteSpace(inputProjectPath))
            {
                SaveProjectAs();
            }
            else
            {
                SaveProjectButton_Click(this, EventArgs.Empty);
            }

            return !HasUnsavedProjectContent();
        }

        private bool HasAnyObjectsOnPage(int pageNumber)
        {
            return textAnnotations.Any(a => a.PageNumber == pageNumber)
                || commentAnnotations.Any(c => c != null && c.PageNumber == pageNumber)
                || rasterObjects.Any(r => r.PageNumber == pageNumber)
                || arrowObjects.Any(a => a.PageNumber == pageNumber)
                || vectorShapes.Any(v => v != null && v.PageNumber == pageNumber);
        }

        private void OpenPdfFromPath(string filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath))
            {
                return;
            }

            if (!ConfirmOpenNewPdf())
            {
                return;
            }

            inputPdfPath = filePath;
            LoadPdf();
        }

        private void CloseCurrentDocument()
        {
            if (pdf == null)
            {
                return;
            }

            if (!ConfirmCloseDocument())
            {
                return;
            }

            try
            {
                pdf.Close();
            }
            catch
            {
            }

            renderTimer.Stop();
            pagingTimer.Stop();
            zoomTimer.Stop();
            CancelPreviewRender();

            pdf = null;
            inputPdfPath = string.Empty;
            inputProjectPath = string.Empty;
            userPassword = string.Empty;
            userNewPassword = null;
            numPages = 0;
            currentPage = 1;
            scaleFactor = 0;
            pendingScaleFactor = 0;

            pageRotationOffsets.Clear();
            ClearRedactionBlocks();
            ClearPagesToRemove();
            ClearTextAnnotations();
            ClearCommentAnnotations();
            ClearRasterObjects();
            ClearArrowObjects();
            ClearVectorShapes();
            PdfTextSearcher.ClearCache();
            signaturesToRemove.Clear();
            hasCustomSignatureSelection = false;
            autoFootnotesEnabled = Properties.Settings.Default.AutoFootnotesEnabled;
            addObjectsByPageRotationEnabled = true;
            allPageStatuses.Clear();
            pagesListView.Clear();
            searchTextBox.Text = string.Empty;
            searchResultLabel.Text = string.Empty;
            ClearSearchResult();

            isDrawing = false;
            isCommentCreationMode = false;
            currentSelection = System.Drawing.Rectangle.Empty;
            zoomPending = false;

            pdfViewer.Image = null;
            pdfViewer.SizeMode = PictureBoxSizeMode.Normal;
            ZoomPanel panel = mainAppSplitContainer.Panel2.Controls[0] as ZoomPanel;
            if (panel is ZoomPanel)
            {
                panel.AutoScrollPosition = new System.Drawing.Point(0, 0);
                pdfViewer.Size = panel.ClientSize;
            }

            groupBoxFilter.Visible = false;
            pagesTabControl.Visible = false;
            ResetThumbnailPanel();
