        // Update navigation buttons state
        private void UpdateNavigationButtons(int numPage)
        {
            // Enable First/Previous only when not on the first page
            buttonFirst.Enabled = numPage > 1;
            buttonPrevious.Enabled = numPage > 1;

            // If the currently displayed page is not the last, enable buttons to navigate to next/last page.
            buttonNextPage.Enabled = numPage < numPages;
            buttonLast.Enabled = numPage < numPages;

            bool isMarked = pagesToRemove.Contains(numPage);
            UpdateRemovePageButtonVisual(isMarked);
            UpdateCurrentPageEditLockState();
        }

        private bool IsCurrentPageMarkedForDeletion()
        {
            return currentPage >= 1 && pagesToRemove.Contains(currentPage);
        }

        private void UpdateCurrentPageEditLockState()
        {
            bool pdfLoaded = pdf != null && numPages > 0 && currentPage >= 1 && currentPage <= numPages;
            bool pageMarkedForDeletion = pdfLoaded && IsCurrentPageMarkedForDeletion();
            bool canEditCurrentPage = pdfLoaded && !pageMarkedForDeletion;

            markerRadioButton.Enabled = canEditCurrentPage;
            boxRadioButton.Enabled = canEditCurrentPage;
            addTextMenuItem.Enabled = canEditCurrentPage;
            if (addRasterImageToolStripMenuItem != null)
            {
                addRasterImageToolStripMenuItem.Enabled = canEditCurrentPage;
            }
            if (pasteObjectFromClipboardToolStripMenuItem != null)
            {
                pasteObjectFromClipboardToolStripMenuItem.Enabled = canEditCurrentPage;
            }
            if (addArrowToolStripMenuItem != null)
            {
                addArrowToolStripMenuItem.Enabled = canEditCurrentPage;
            }
            if (addShapeToolStripMenuItem != null)
            {
                addShapeToolStripMenuItem.Enabled = canEditCurrentPage;
            }
            if (addCommentToolStripMenuItem != null)
            {
                addCommentToolStripMenuItem.Enabled = canEditCurrentPage;
            }
            rotatePageMenuItem.Enabled = canEditCurrentPage;
            searchToSelectionButton.Enabled = canEditCurrentPage && groupBoxSearch.Enabled;

            bool hasSelectionsForThisPage = pdfLoaded && redactionBlocks.Any(rb => rb.PageNumber == currentPage);
            clearPageButton.Enabled = canEditCurrentPage && hasSelectionsForThisPage;

            if (!canEditCurrentPage)
            {
                isDrawing = false;
                isMoving = false;
                annotationToMove = null;
                textMoveMouseOffset = PointF.Empty;
                currentSelection = RectangleF.Empty;
                ResetArrowInteractionState();
                ResetRasterInteractionState();
                ResetVectorInteractionState();
                selectedVectorShape = null;
                EndCommentCreationMode();
                this.Cursor = Cursors.Default;
            }

            pdfViewer?.Invalidate();
        }

        private bool EnsureCurrentPageEditable(bool showMessage)
        {
            if (!IsCurrentPageMarkedForDeletion())
            {
                return true;
            }

            if (showMessage)
            {
                ShowInfoMessage(LocalizedText("Msg_PageMarkedForDeletion_UnmarkToEdit"));
            }
            return false;
        }

        private void RotateCurrentPageClockwise()
        {
            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            if (pdf == null)
                return;

            var pageSize = GetPageSizeWithOffset(currentPage);
            if (pageSize.Width <= 0 || pageSize.Height <= 0)
                return;
            int currentOffset = GetRotationOffset(currentPage);
            int rotatedOffset = NormalizeRotation(currentOffset + 90);

            float dpiX;
            float dpiY;
            using (Graphics g = pdfViewer.CreateGraphics())
            {
                dpiX = g.DpiX;
                dpiY = g.DpiY;
            }
            float pxToPtX = 72f / dpiX;
            float pxToPtY = 72f / dpiY;

            foreach (var block in redactionBlocks.Where(b => b.PageNumber == currentPage))
            {
                block.Bounds = RotateRectClockwise(block.Bounds, pageSize.Width, pageSize.Height);
                TouchRedactionBlock(block);
            }

            // Comment annotations are intentionally not rotated with page rotation.
            // This keeps their coordinates unchanged until the dedicated rotation model is reintroduced.

            foreach (var annotation in textAnnotations.Where(a => a.PageNumber == currentPage))
            {
                RectangleF boundsPt = new RectangleF(
                    annotation.AnnotationBounds.X,
                    annotation.AnnotationBounds.Y,
                    annotation.AnnotationBounds.Width * pxToPtX,
                    annotation.AnnotationBounds.Height * pxToPtY
                );

                boundsPt = RotateRectClockwise(boundsPt, pageSize.Width, pageSize.Height);

                annotation.AnnotationBounds = new RectangleF(
                    boundsPt.X,
                    boundsPt.Y,
                    boundsPt.Width / pxToPtX,
                    boundsPt.Height / pxToPtY
                );

                // Keep annotation rotation relative to the page orientation
                annotation.AnnotationRotation = NormalizeRotation(annotation.AnnotationRotation + 90);
                TouchTextAnnotation(annotation);
            }

            // Update page rotation offset before object constraints.
            // Objects are transformed using pre-rotation page size above, but clamped against post-rotation page size.
            SetRotationOffset(currentPage, rotatedOffset);

            foreach (var rasterObject in rasterObjects.Where(r => r.PageNumber == currentPage))
            {
                RectangleF bounds = rasterObject.Bounds;
                float centerX = bounds.X + (bounds.Width / 2f);
                float centerY = bounds.Y + (bounds.Height / 2f);
                float rotatedCenterX = pageSize.Height - centerY;
                float rotatedCenterY = centerX;

                rasterObject.Bounds = new RectangleF(
                    rotatedCenterX - (bounds.Width / 2f),
                    rotatedCenterY - (bounds.Height / 2f),
                    bounds.Width,
                    bounds.Height);
                // Keep raster as a rigid body with page rotation (no aspect distortion).
                rasterObject.Rotation = NormalizeRotation(rasterObject.Rotation + 90);
                ConstrainRasterObjectToPage(rasterObject);
                rasterObject.UpdatedAtUtc = DateTime.UtcNow;
            }

            foreach (var arrowObject in arrowObjects.Where(a => a.PageNumber == currentPage))
            {
                PointF start = arrowObject.Start;
                PointF end = arrowObject.End;
                arrowObject.Start = new PointF(pageSize.Height - start.Y, start.X);
                arrowObject.End = new PointF(pageSize.Height - end.Y, end.X);
                ConstrainArrowToPage(arrowObject);
                arrowObject.Thickness = NormalizeArrowThickness(arrowObject.Thickness);
                arrowObject.HeadLength = NormalizeArrowHeadLength(arrowObject.HeadLength);
                arrowObject.HeadWidth = NormalizeArrowHeadWidth(arrowObject.HeadWidth);
                if (!IsArrowColorValid(arrowObject))
                {
                    arrowObject.LineColorArgb = DefaultArrowColor.ToArgb();
                }
                arrowObject.UpdatedAtUtc = DateTime.UtcNow;
            }

            foreach (var vectorShape in vectorShapes.Where(v => v != null && v.PageNumber == currentPage))
            {
                vectorShape.Points = (vectorShape.Points ?? new List<PointF>())
                    .Select(p => new PointF(pageSize.Height - p.Y, p.X))
                    .ToList();
                NormalizeVectorShape(vectorShape);
                ConstrainVectorShapeToPage(vectorShape);
                vectorShape.UpdatedAtUtc = DateTime.UtcNow;
            }

            currentSelection = RectangleF.Empty;
            commentNoteRectsDoc.Clear();
            commentPreviewOverlayReady = false;

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;

            PageItemStatus status = allPageStatuses[currentPage - 1];
            status.HasRotation = pageRotationOffsets.ContainsKey(currentPage);
            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                pagesListView.Invalidate(currentItem.Bounds);
            }
            else
            {
                ApplyFilter((string)filterComboBox.SelectedItem);
            }

            ReloadRefreshCurrentPage();
            pendingScaleFactor = scaleFactor;
            pdfViewer.Invalidate();
        }


        private void PreviousPage()
        {
            currentPage -= 1;
            if (currentPage < 1)
            {
                currentPage = 1;
            }
            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                pagesListView.Items[currentPage - 1].Selected = true;
                pagesListView.Items[currentPage - 1].EnsureVisible();
            }
            else
            {
                ListViewItem currentItem = FindListViewItemByPageNumber(currentPage);
                if (currentItem != null)
                {
                    currentItem.Selected = true;
                    currentItem.EnsureVisible();
                }
                else
                {
                    pagesListView.SelectedItems.Clear();
                }
                ReloadRefreshCurrentPage();
            }
            // Update button states
            UpdateNavigationButtons(currentPage);
        }

        private void NextPage()
        {
            currentPage += 1;
            if (currentPage > numPages)
            {
                currentPage = numPages;
            }

            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                pagesListView.Items[currentPage - 1].Selected = true;
                pagesListView.Items[currentPage - 1].EnsureVisible();
            }
            else
            {
                ListViewItem currentItem = FindListViewItemByPageNumber(currentPage);
                if (currentItem != null)
                {
                    currentItem.Selected = true;
                    currentItem.EnsureVisible();
                }
                else
                {
                    pagesListView.SelectedItems.Clear();
                }
                ReloadRefreshCurrentPage();
            }

            // Update button states
            UpdateNavigationButtons(currentPage);
        }

