        private RectangleF CalculateFootnoteBadgeRect(
            RectangleF selectionRect,
            float badgeWidth,
            float badgeHeight,
            int rotationOffset,
            float margin,
            bool clampToViewer,
            out float rotationCompensation)
        {
            rotationCompensation = 0f;
            float badgeX = selectionRect.Left - badgeWidth - margin;
            float badgeY = selectionRect.Top - badgeHeight - margin;

            if (clampToViewer)
            {
                if (badgeX < 0f)
                {
                    badgeX = Math.Min(
                        pdfViewer.ClientSize.Width - badgeWidth,
                        selectionRect.Left + margin);
                }
                if (badgeX + badgeWidth > pdfViewer.ClientSize.Width)
                {
                    badgeX = Math.Max(0f, pdfViewer.ClientSize.Width - badgeWidth);
                }
                if (badgeY < 0f)
                {
                    badgeY = Math.Min(
                        pdfViewer.ClientSize.Height - badgeHeight,
                        selectionRect.Top + margin);
                }
                if (badgeY + badgeHeight > pdfViewer.ClientSize.Height)
                {
                    badgeY = Math.Max(0f, pdfViewer.ClientSize.Height - badgeHeight);
                }
            }

            return new RectangleF(badgeX, badgeY, badgeWidth, badgeHeight);
        }

        private static PointF GetFootnoteAnchorPointForPdfExport(RectangleF selectionRect, int rotationOffset)
        {
            switch (NormalizeRotation(rotationOffset))
            {
                case 90:
                    return new PointF(selectionRect.Right, selectionRect.Bottom);
                case 180:
                    return new PointF(selectionRect.Left, selectionRect.Bottom);
                case 270:
                    return new PointF(selectionRect.Left, selectionRect.Top);
                case 0:
                default:
                    return new PointF(selectionRect.Right, selectionRect.Top);
            }
        }

        private static PointF ApplyFootnoteAnchorGapForPdfExport(PointF anchorPoint, int rotationOffset)
        {
            switch (NormalizeRotation(rotationOffset))
            {
                case 90:
                    return new PointF(anchorPoint.X, anchorPoint.Y + FootnoteMarkerGapPx);
                case 180:
                    return new PointF(anchorPoint.X - FootnoteMarkerGapPx, anchorPoint.Y);
                case 270:
                    return new PointF(anchorPoint.X, anchorPoint.Y - FootnoteMarkerGapPx);
                case 0:
                default:
                    return new PointF(anchorPoint.X + FootnoteMarkerGapPx, anchorPoint.Y);
            }
        }

        private void DrawCornerDebugMarkersOnPreview(Graphics graphics, RectangleF rect)
        {
            if (!DebugLogEnabled || graphics == null || rect.Width <= 0f || rect.Height <= 0f)
            {
                return;
            }

            using (var debugFont = new Font(this.Font.FontFamily, Math.Max(7f, this.Font.SizeInPoints - 1f), FontStyle.Bold))
            using (var debugBrush = new SolidBrush(System.Drawing.Color.Red))
            {
                PointF[] corners = new[]
                {
                    new PointF(rect.Left, rect.Top),
                    new PointF(rect.Right, rect.Top),
                    new PointF(rect.Right, rect.Bottom),
                    new PointF(rect.Left, rect.Bottom)
                };

                for (int i = 0; i < corners.Length; i++)
                {
                    graphics.DrawString((i + 1).ToString(CultureInfo.InvariantCulture), debugFont, debugBrush, corners[i].X + 1f, corners[i].Y + 1f);
                }
            }
        }

        private void DrawCornerDebugMarkersOnPdf(
            iText.Kernel.Pdf.Canvas.PdfCanvas pdfCanvas,
            PdfFont font,
            RectangleF selectionRect,
            int pageNumber,
            int rotation,
            bool includeBaseRotation)
        {
            if (!DebugLogEnabled || pdfCanvas == null || font == null || selectionRect.Width <= 0f || selectionRect.Height <= 0f)
            {
                return;
            }

            PointF[] corners = new[]
            {
                new PointF(selectionRect.Left, selectionRect.Top),
                new PointF(selectionRect.Right, selectionRect.Top),
                new PointF(selectionRect.Right, selectionRect.Bottom),
                new PointF(selectionRect.Left, selectionRect.Bottom)
            };

            pdfCanvas.SaveState();
            pdfCanvas.SetFillColor(new DeviceRgb(220, 0, 0));
            pdfCanvas.BeginText();
            pdfCanvas.SetFontAndSize(font, 7f);

            for (int i = 0; i < corners.Length; i++)
            {
                PointF cornerPdf = ConvertPointToPdfCoordinates(corners[i], pageNumber, rotation, includeBaseRotation);
                pdfCanvas.SetTextMatrix(1, 0, 0, 1, cornerPdf.X, cornerPdf.Y);
                pdfCanvas.ShowText((i + 1).ToString(CultureInfo.InvariantCulture));
            }

            pdfCanvas.EndText();
            pdfCanvas.RestoreState();
        }

        private void RenderVectorShapesToPdf(
            iText.Kernel.Pdf.PdfDocument pdfDoc,
            ISet<int> pagesWithBakedRotation,
            IEnumerable<VectorShapeObject> shapes)
        {
            if (pdfDoc == null || shapes == null)
            {
                return;
            }

            foreach (var vectorShape in shapes)
            {
                if (vectorShape == null || vectorShape.Points == null || vectorShape.Points.Count < 2)
                {
                    continue;
                }

                int pageNumber = vectorShape.PageNumber;
                if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
                {
                    continue;
                }

                bool baseRotationBaked = pagesWithBakedRotation != null && pagesWithBakedRotation.Contains(pageNumber);
                int rotation = baseRotationBaked ? GetRotationOffset(pageNumber) : GetEffectiveRotationDegrees(pageNumber);
                bool includeBaseRotation = !baseRotationBaked;
                var page = pdfDoc.GetPage(pageNumber);
                var pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(page);

                VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
                VectorShapeStrokeKind strokeKind = ParseVectorStrokeKind(vectorShape.StrokeStyle);
                List<PointF> viewPoints = BuildVectorShapeRenderPoints(shapeType, vectorShape.Points);
                List<PointF> pdfPoints = viewPoints
                    .Select(point => ConvertPointToPdfCoordinates(point, pageNumber, rotation, includeBaseRotation))
                    .ToList();
                if (pdfPoints.Count < 2)
                {
                    continue;
                }

                bool isClosed = IsShapeClosed(shapeType);
                bool supportsFill = ShapeTypeSupportsFill(shapeType);
                bool hasStroke = HasVisibleVectorColor(vectorShape.StrokeColorArgb);
                float fillOpacity = supportsFill ? NormalizeVectorFillOpacity(vectorShape.FillOpacity) : 0f;
                bool hasFill = supportsFill && HasVisibleVectorColor(vectorShape.FillColorArgb) && fillOpacity > 0f;
                VectorFillPatternKind fillPattern = ParseVectorFillPattern(vectorShape.FillPattern);
                bool hasPatternColor = HasVisibleVectorColor(vectorShape.FillPatternColorArgb);
                if (!hasStroke && !hasFill)
                {
                    continue;
                }

                pdfCanvas.SaveState();
                if (hasStroke)
                {
                    System.Drawing.Color strokeColor = System.Drawing.Color.FromArgb(vectorShape.StrokeColorArgb);
                    float strokeWidth = NormalizeVectorStrokeWidth(vectorShape.StrokeWidth);
                    pdfCanvas.SetStrokeColor(new DeviceRgb(strokeColor.R, strokeColor.G, strokeColor.B));
                    pdfCanvas.SetLineWidth(strokeWidth);
                    pdfCanvas.SetLineJoinStyle(iText.Kernel.Pdf.Canvas.PdfCanvasConstants.LineJoinStyle.ROUND);
                    pdfCanvas.SetLineCapStyle(iText.Kernel.Pdf.Canvas.PdfCanvasConstants.LineCapStyle.ROUND);
                    switch (strokeKind)
                    {
                        case VectorShapeStrokeKind.Dash:
                            pdfCanvas.SetLineDash(6f, 4f);
                            break;
                        case VectorShapeStrokeKind.Dot:
                            pdfCanvas.SetLineDash(1.5f, 3f);
                            break;
                        case VectorShapeStrokeKind.DashDot:
                            pdfCanvas.SetLineDash(new float[] { 6f, 3f, 1.5f, 3f }, 0f);
                            break;
                        case VectorShapeStrokeKind.DashDotDot:
                            pdfCanvas.SetLineDash(new float[] { 6f, 3f, 1.5f, 3f, 1.5f, 3f }, 0f);
                            break;
                    }
                }

                if (isClosed && pdfPoints.Count >= 3)
                {
                    if (hasFill && fillPattern != VectorFillPatternKind.Solid && hasPatternColor)
                    {
                        if (hasStroke)
                        {
                            pdfCanvas.MoveTo(pdfPoints[0].X, pdfPoints[0].Y);
                            for (int i = 1; i < pdfPoints.Count; i++)
                            {
                                pdfCanvas.LineTo(pdfPoints[i].X, pdfPoints[i].Y);
                            }
                            pdfCanvas.ClosePathStroke();
                        }

                        System.Drawing.Color fillColor = System.Drawing.Color.FromArgb(vectorShape.FillColorArgb);
                        System.Drawing.Color patternColor = System.Drawing.Color.FromArgb(vectorShape.FillPatternColorArgb);
                        DrawVectorHatchFillToPdf(pdfCanvas, pdfPoints, fillColor, patternColor, fillOpacity, fillPattern);
                    }
                    else if (hasFill && hasStroke)
                    {
                        pdfCanvas.MoveTo(pdfPoints[0].X, pdfPoints[0].Y);
                        for (int i = 1; i < pdfPoints.Count; i++)
                        {
                            pdfCanvas.LineTo(pdfPoints[i].X, pdfPoints[i].Y);
                        }
                        System.Drawing.Color fillColor = System.Drawing.Color.FromArgb(vectorShape.FillColorArgb);
                        pdfCanvas.SetFillColor(new DeviceRgb(fillColor.R, fillColor.G, fillColor.B));
                        var fillState = new PdfExtGState().SetFillOpacity(fillOpacity);
                        pdfCanvas.SetExtGState(fillState);
                        pdfCanvas.ClosePathFillStroke();
                    }
                    else if (hasFill)
                    {
                        pdfCanvas.MoveTo(pdfPoints[0].X, pdfPoints[0].Y);
                        for (int i = 1; i < pdfPoints.Count; i++)
                        {
                            pdfCanvas.LineTo(pdfPoints[i].X, pdfPoints[i].Y);
                        }
                        System.Drawing.Color fillColor = System.Drawing.Color.FromArgb(vectorShape.FillColorArgb);
                        pdfCanvas.SetFillColor(new DeviceRgb(fillColor.R, fillColor.G, fillColor.B));
                        var fillState = new PdfExtGState().SetFillOpacity(fillOpacity);
                        pdfCanvas.SetExtGState(fillState);
                        pdfCanvas.Fill();
                    }
                    else if (hasStroke)
                    {
                        pdfCanvas.MoveTo(pdfPoints[0].X, pdfPoints[0].Y);
                        for (int i = 1; i < pdfPoints.Count; i++)
                        {
                            pdfCanvas.LineTo(pdfPoints[i].X, pdfPoints[i].Y);
                        }
                        pdfCanvas.ClosePathStroke();
                    }
                }
                else if (hasStroke)
                {
                    pdfCanvas.MoveTo(pdfPoints[0].X, pdfPoints[0].Y);
                    for (int i = 1; i < pdfPoints.Count; i++)
                    {
                        pdfCanvas.LineTo(pdfPoints[i].X, pdfPoints[i].Y);
                    }
                    pdfCanvas.Stroke();
                }

                pdfCanvas.RestoreState();
            }
        }

        private void DrawVectorHatchFillToPdf(
            iText.Kernel.Pdf.Canvas.PdfCanvas pdfCanvas,
            IList<PointF> polygon,
            System.Drawing.Color fillColor,
            System.Drawing.Color patternColor,
            float fillOpacity,
            VectorFillPatternKind fillPattern)
        {
            if (pdfCanvas == null || polygon == null || polygon.Count < 3)
            {
                return;
            }

            float minX = polygon.Min(p => p.X);
            float maxX = polygon.Max(p => p.X);
            float minY = polygon.Min(p => p.Y);
            float maxY = polygon.Max(p => p.Y);
            float width = maxX - minX;
            float height = maxY - minY;
            if (width <= 0.01f || height <= 0.01f)
            {
                return;
            }

            float spacing = 6f;
            float margin = Math.Max(width, height) + spacing;

            pdfCanvas.SaveState();
            pdfCanvas.MoveTo(polygon[0].X, polygon[0].Y);
            for (int i = 1; i < polygon.Count; i++)
            {
                pdfCanvas.LineTo(polygon[i].X, polygon[i].Y);
            }
            pdfCanvas.LineTo(polygon[0].X, polygon[0].Y);
            pdfCanvas.Clip();
            pdfCanvas.EndPath();

            var backgroundFillState = new PdfExtGState().SetFillOpacity(fillOpacity);
            pdfCanvas.SetExtGState(backgroundFillState);
            pdfCanvas.SetFillColor(new DeviceRgb(fillColor.R, fillColor.G, fillColor.B));
            pdfCanvas.Rectangle(minX - margin, minY - margin, width + (2f * margin), height + (2f * margin));
            pdfCanvas.Fill();

            if (fillPattern == VectorFillPatternKind.Dot)
            {
                var fillState = new PdfExtGState().SetFillOpacity(fillOpacity);
                pdfCanvas.SetExtGState(fillState);
                pdfCanvas.SetFillColor(new DeviceRgb(patternColor.R, patternColor.G, patternColor.B));
                float radius = 0.65f;
                for (float y = minY - margin; y <= maxY + margin; y += spacing)
                {
                    for (float x = minX - margin; x <= maxX + margin; x += spacing)
                    {
                        pdfCanvas.Circle(x, y, radius);
                    }
                }
                pdfCanvas.Fill();
                pdfCanvas.RestoreState();
                return;
            }

            var strokeState = new PdfExtGState().SetStrokeOpacity(fillOpacity);
            pdfCanvas.SetExtGState(strokeState);
            pdfCanvas.SetStrokeColor(new DeviceRgb(patternColor.R, patternColor.G, patternColor.B));
            pdfCanvas.SetLineWidth(0.7f);

            if (fillPattern == VectorFillPatternKind.Diagonal)
            {
                for (float x = minX - margin; x <= maxX + margin; x += spacing)
                {
                    pdfCanvas.MoveTo(x, minY - margin);
                    pdfCanvas.LineTo(x + height + (margin * 2f), maxY + margin);
                }
            }
            else
            {
                for (float y = minY - margin; y <= maxY + margin; y += spacing)
                {
                    pdfCanvas.MoveTo(minX - margin, y);
                    pdfCanvas.LineTo(maxX + margin, y);
                }
                for (float x = minX - margin; x <= maxX + margin; x += spacing)
                {
                    pdfCanvas.MoveTo(x, minY - margin);
                    pdfCanvas.LineTo(x, maxY + margin);
                }
            }

            pdfCanvas.Stroke();
            pdfCanvas.RestoreState();
        }

        private void RenderRasterObjectToPdf(
            iText.Kernel.Pdf.PdfDocument pdfDoc,
            ISet<int> pagesWithBakedRotation,
            RasterObject rasterObject)
        {
            if (pdfDoc == null || rasterObject == null)
            {
                return;
            }

            int pageNumber = rasterObject.PageNumber;
            if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
            {
                return;
            }

            if (!TryCreateRasterImageData(rasterObject, out iText.IO.Image.ImageData imageData))
            {
                return;
            }

            bool baseRotationBaked = pagesWithBakedRotation != null && pagesWithBakedRotation.Contains(pageNumber);
            int rotation = baseRotationBaked ? GetRotationOffset(pageNumber) : GetEffectiveRotationDegrees(pageNumber);
            var page = pdfDoc.GetPage(pageNumber);
            var pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(page);
            RectangleF viewBounds = rasterObject.Bounds;
            if (viewBounds.Width <= 0f || viewBounds.Height <= 0f)
            {
                return;
            }

            PointF centerView = new PointF(
                viewBounds.X + (viewBounds.Width / 2f),
                viewBounds.Y + (viewBounds.Height / 2f));
            PointF halfWidthVector = RotateVector(new PointF(viewBounds.Width / 2f, 0f), NormalizeRotation(rasterObject.Rotation));
            PointF halfHeightVector = RotateVector(new PointF(0f, viewBounds.Height / 2f), NormalizeRotation(rasterObject.Rotation));

            PointF topLeftView = new PointF(
                centerView.X - halfWidthVector.X - halfHeightVector.X,
                centerView.Y - halfWidthVector.Y - halfHeightVector.Y);
            PointF topRightView = new PointF(
                centerView.X + halfWidthVector.X - halfHeightVector.X,
                centerView.Y + halfWidthVector.Y - halfHeightVector.Y);
            PointF bottomLeftView = new PointF(
                centerView.X - halfWidthVector.X + halfHeightVector.X,
                centerView.Y - halfWidthVector.Y + halfHeightVector.Y);
            PointF bottomRightView = new PointF(
                centerView.X + halfWidthVector.X + halfHeightVector.X,
                centerView.Y + halfWidthVector.Y + halfHeightVector.Y);

            PointF topLeftPdf = ConvertPointToPdfCoordinates(topLeftView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
            PointF topRightPdf = ConvertPointToPdfCoordinates(topRightView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
            PointF bottomLeftPdf = ConvertPointToPdfCoordinates(bottomLeftView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
            PointF bottomRightPdf = ConvertPointToPdfCoordinates(bottomRightView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);

            float a = bottomRightPdf.X - bottomLeftPdf.X;
            float b = bottomRightPdf.Y - bottomLeftPdf.Y;
            float c = topLeftPdf.X - bottomLeftPdf.X;
            float d = topLeftPdf.Y - bottomLeftPdf.Y;
            float e = bottomLeftPdf.X;
            float f = bottomLeftPdf.Y;

            if (DebugLogEnabled)
            {
                LogDebug(
                    $"RasterExport page={pageNumber} bounds={viewBounds} rotObj={NormalizeRotation(rasterObject.Rotation)} pageRot={rotation} " +
                    $"tl={topLeftPdf.X:0.###},{topLeftPdf.Y:0.###} tr={topRightPdf.X:0.###},{topRightPdf.Y:0.###} bl={bottomLeftPdf.X:0.###},{bottomLeftPdf.Y:0.###} br={bottomRightPdf.X:0.###},{bottomRightPdf.Y:0.###} " +
                    $"matrix=[{a:0.#####} {b:0.#####} {c:0.#####} {d:0.#####} {e:0.###} {f:0.###}]");
            }

            float opacity = NormalizeOpacity(rasterObject.Opacity);
            if (opacity >= 0.999f)
            {
                pdfCanvas.AddImageWithTransformationMatrix(imageData, a, b, c, d, e, f, false);
            }
            else
            {
                var extGState = new PdfExtGState()
                    .SetFillOpacity(opacity)
                    .SetStrokeOpacity(opacity);
                pdfCanvas.SaveState();
                pdfCanvas.SetExtGState(extGState);
                pdfCanvas.AddImageWithTransformationMatrix(imageData, a, b, c, d, e, f, false);
                pdfCanvas.RestoreState();
            }
        }

        private void RenderArrowObjectToPdf(
            iText.Kernel.Pdf.PdfDocument pdfDoc,
            ISet<int> pagesWithBakedRotation,
            ArrowObject arrowObject)
        {
            if (pdfDoc == null || arrowObject == null)
            {
                return;
            }

            int pageNumber = arrowObject.PageNumber;
            if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
            {
                return;
            }

            bool baseRotationBaked = pagesWithBakedRotation != null && pagesWithBakedRotation.Contains(pageNumber);
            int rotation = baseRotationBaked ? GetRotationOffset(pageNumber) : GetEffectiveRotationDegrees(pageNumber);
            var page = pdfDoc.GetPage(pageNumber);
            var pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(page);
            PointF startView = arrowObject.Start;
            PointF endView = arrowObject.End;
            PointF startPdf = ConvertPointToPdfCoordinates(startView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
            PointF endPdf = ConvertPointToPdfCoordinates(endView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);

            float thickness = NormalizeArrowThickness(arrowObject.Thickness);
            float headLength = NormalizeArrowHeadLength(arrowObject.HeadLength);
            float headWidth = NormalizeArrowHeadWidth(arrowObject.HeadWidth);
            System.Drawing.Color lineColor = GetArrowColor(arrowObject);
            var deviceColor = new DeviceRgb(lineColor.R, lineColor.G, lineColor.B);

            pdfCanvas.SaveState();
            pdfCanvas.SetLineWidth(thickness);
            pdfCanvas.SetLineCapStyle(iText.Kernel.Pdf.Canvas.PdfCanvasConstants.LineCapStyle.ROUND);
            pdfCanvas.SetLineJoinStyle(iText.Kernel.Pdf.Canvas.PdfCanvasConstants.LineJoinStyle.ROUND);
            pdfCanvas.SetStrokeColor(deviceColor);
            pdfCanvas.SetFillColor(deviceColor);

            if (TryBuildArrowHead(startView, endView, headLength, headWidth, out PointF leftView, out PointF rightView, out PointF lineEndView))
            {
                PointF lineEndPdf = ConvertPointToPdfCoordinates(lineEndView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
                PointF leftPdf = ConvertPointToPdfCoordinates(leftView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
                PointF rightPdf = ConvertPointToPdfCoordinates(rightView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);

                pdfCanvas.MoveTo(startPdf.X, startPdf.Y);
                pdfCanvas.LineTo(lineEndPdf.X, lineEndPdf.Y);
                pdfCanvas.Stroke();

                pdfCanvas.MoveTo(endPdf.X, endPdf.Y);
                pdfCanvas.LineTo(leftPdf.X, leftPdf.Y);
                pdfCanvas.LineTo(rightPdf.X, rightPdf.Y);
                pdfCanvas.Fill();
            }
            else
            {
                pdfCanvas.MoveTo(startPdf.X, startPdf.Y);
                pdfCanvas.LineTo(endPdf.X, endPdf.Y);
                pdfCanvas.Stroke();
            }

            pdfCanvas.RestoreState();
        }

        private Dictionary<string, int> BuildLegalBasisFootnoteNumberMap(IEnumerable<RedactionBlock> blocks = null)
        {
            var map = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            IEnumerable<RedactionBlock> sourceBlocks = blocks ?? redactionBlocks;
            if (sourceBlocks == null)
            {
                return map;
            }

            List<string> usedBasisIds = sourceBlocks
                .Where(block => block != null && block.BasisIds != null)
                .SelectMany(block => block.BasisIds)
                .Where(id => !string.IsNullOrWhiteSpace(id))
                .Select(id => id.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            if (usedBasisIds.Count == 0)
            {
                return map;
            }

            var usedBasisIdSet = new HashSet<string>(usedBasisIds, StringComparer.OrdinalIgnoreCase);
            var orderedAllBases = GetOrderedLegalBasesForIndexing();
            int nextNumber = 1;

            // Footnote numbering is independent from legal-basis ordering in UI/context menu.
            // We keep basis order stable (global+local ordering), but compress numbering to used items only: 1..N.
            foreach (var basis in orderedAllBases)
            {
                if (basis == null || string.IsNullOrWhiteSpace(basis.Id))
                {
                    continue;
                }

                string basisId = basis.Id.Trim();
                if (!usedBasisIdSet.Contains(basisId) || map.ContainsKey(basisId))
                {
                    continue;
                }

                map[basisId] = nextNumber++;
            }

            // Any unknown/custom IDs that are used in blocks but not present in current catalogs.
            foreach (string basisId in usedBasisIds.Where(id => !map.ContainsKey(id)))
            {
                map[basisId] = nextNumber++;
            }

            return map;
        }

        private bool TryBuildFootnoteMarkerText(RedactionBlock block, IDictionary<string, int> basisNumberMap, out string markerText)
        {
            markerText = null;
            if (block == null)
            {
                return false;
            }

            List<int> markerNumbers = new List<int>();

            if (block.BasisIds != null && basisNumberMap != null && basisNumberMap.Count > 0)
            {
                foreach (string basisId in block.BasisIds)
                {
                    if (string.IsNullOrWhiteSpace(basisId))
                    {
                        continue;
                    }

                    if (basisNumberMap.TryGetValue(basisId.Trim(), out int number) && !markerNumbers.Contains(number))
                    {
                        markerNumbers.Add(number);
                    }
                }
            }

            if (markerNumbers.Count == 0 && block.FootnoteNumber.HasValue && block.FootnoteNumber.Value > 0)
            {
                markerNumbers.Add(block.FootnoteNumber.Value);
            }

            if (markerNumbers.Count == 0)
            {
                return false;
            }

            markerNumbers.Sort();
            markerText = markerNumbers.Count == 1
                ? $"[{markerNumbers[0]}]"
                : "[" + string.Join(",", markerNumbers) + "]";
            return true;
        }

        private List<(int Number, string Text)> BuildFootnoteSummaryEntries(
            IList<RedactionBlock> blocksWithFootnotes,
            IDictionary<string, int> basisNumberMap)
        {
            var entries = new List<(int Number, string Text)>();

            if (basisNumberMap != null && basisNumberMap.Count > 0)
            {
                foreach (var pair in basisNumberMap.OrderBy(p => p.Value))
                {
                    string text;
                    if (legalBasesById.TryGetValue(pair.Key, out LegalBasisDefinition legalBasis))
                    {
                        text = !string.IsNullOrWhiteSpace(legalBasis.FullCitation)
                            ? legalBasis.FullCitation
                            : legalBasis.Title;
                    }
                    else
                    {
                        text = pair.Key;
                    }

                    entries.Add((pair.Value, text));
                }

                return entries;
            }

            List<int> usedNumbers = (blocksWithFootnotes ?? new List<RedactionBlock>())
                .Where(block => block != null && block.FootnoteNumber.HasValue && block.FootnoteNumber.Value > 0)
                .Select(block => block.FootnoteNumber.Value)
                .Distinct()
                .OrderBy(number => number)
                .ToList();

            foreach (int number in usedNumbers)
            {
                entries.Add((number, GetFallbackFootnoteDetailText(number)));
            }

            return entries;
        }

        private string ResolveExclusionAuthorityForSummary(IList<RedactionBlock> blocksWithFootnotes)
        {
            if (!string.IsNullOrWhiteSpace(exclusionAuthorityName))
            {
                return exclusionAuthorityName.Trim();
            }

            foreach (var block in blocksWithFootnotes ?? new List<RedactionBlock>())
            {
                if (!string.IsNullOrWhiteSpace(block?.InterestSubject))
                {
                    return block.InterestSubject.Trim();
                }
            }

            return string.Empty;
        }

        private void RenderFootnoteMarkersToPdf(
            iText.Kernel.Pdf.PdfDocument pdfDoc,
            ISet<int> pagesWithBakedRotation,
            IList<RedactionBlock> blocksWithFootnotes,
            IDictionary<string, int> basisNumberMap,
            IDictionary<RedactionBlock, RectangleF> redactionVisualPdfBoundsByBlock)
        {
            if (pdfDoc == null || blocksWithFootnotes == null || blocksWithFootnotes.Count == 0)
            {
                return;
            }

            PdfFont markerFont = PdfFontFactory.CreateFont(iText.IO.Font.Constants.StandardFonts.HELVETICA, "Cp1250");
            const float markerFontSize = 6f;

            foreach (var block in blocksWithFootnotes)
            {
                if (!TryBuildFootnoteMarkerText(block, basisNumberMap, out string markerText))
                {
                    continue;
                }

                int pageNumber = block.PageNumber;
                if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
                {
                    continue;
                }

                bool baseRotationBaked = pagesWithBakedRotation != null && pagesWithBakedRotation.Contains(pageNumber);
                int rotation = baseRotationBaked ? GetRotationOffset(pageNumber) : GetEffectiveRotationDegrees(pageNumber);
                int markerAnchorRotation = addObjectsByPageRotationEnabled ? rotation : 0;
                bool includeBaseRotation = !baseRotationBaked;
                iText.Kernel.Pdf.PdfPage page = pdfDoc.GetPage(pageNumber);
                RectangleF markerAnchorRect = GetFootnoteMarkerAnchorRect(
                    block,
                    page,
                    pageNumber,
                    rotation,
                    includeBaseRotation,
                    redactionVisualPdfBoundsByBlock);
                float markerWidth = Math.Max(8f, markerFont.GetWidth(markerText, markerFontSize));
                float markerHeight = markerFontSize + 1f;
                PointF markerViewPoint;
                if (!addObjectsByPageRotationEnabled)
                {
                    // Flat mode: same visual rule as 0 deg (right side, non-rotated marker).
                    markerViewPoint = new PointF(
                        markerAnchorRect.Right + FootnoteMarkerGapPx,
                        markerAnchorRect.Top + (markerAnchorRect.Height / 2f) - markerHeight);
                }
                else
                {
                    markerViewPoint = GetFootnoteAnchorPointForPdfExport(markerAnchorRect, markerAnchorRotation);
                    markerViewPoint = ApplyFootnoteAnchorGapForPdfExport(markerViewPoint, markerAnchorRotation);
                }

                // For tall visual redaction rectangles, use edge anchoring instead of vertical centering.
                if (addObjectsByPageRotationEnabled &&
                    markerAnchorRect.Height >= (markerHeight * 2f))
                {
                    int normalizedAnchorRotation = NormalizeRotation(markerAnchorRotation);
                    // Keep corner anchoring consistent with rotation-aware preview.
                    // Preserve 2px gap for 90/270 like in standard anchor-gap rules.
                    float anchoredY;
                    if (normalizedAnchorRotation == 90)
                    {
                        anchoredY = markerAnchorRect.Bottom + FootnoteMarkerGapPx;
                    }
                    else if (normalizedAnchorRotation == 180)
                    {
                        anchoredY = markerAnchorRect.Bottom;
                    }
                    else if (normalizedAnchorRotation == 270)
                    {
                        anchoredY = markerAnchorRect.Top - FootnoteMarkerGapPx;
                    }
                    else
                    {
                        anchoredY = markerAnchorRect.Top;
                    }
                    markerViewPoint = new PointF(markerViewPoint.X, anchoredY);
                }
                RectangleF badgeRect = new RectangleF(
                    markerViewPoint.X,
                    markerViewPoint.Y,
                    markerWidth,
                    markerHeight);

                PointF markerPdfPoint = ConvertPointToPdfCoordinates(
                    markerViewPoint,
                    pageNumber,
                    rotation,
                    includeBaseRotation: includeBaseRotation);

                float markerTextRotationRadians = 0f;
                if (!addObjectsByPageRotationEnabled)
                {
                    // Flat mode: keep index orientation like 0 deg preview.
                    // Start with explicit per-angle handling (can be tuned per rotation in next steps).
                    switch (NormalizeRotation(rotation))
                    {
                        case 90:
                            markerTextRotationRadians = (float)(Math.PI / 2.0);
                            break;
                        case 180:
                            markerTextRotationRadians = (float)Math.PI;
                            break;
                        case 270:
                            markerTextRotationRadians = (float)(-Math.PI / 2.0);
                            break;
                        default:
                            markerTextRotationRadians = 0f;
                            break;
                    }
                }

                if (DebugLogEnabled)
                {
                    LogDebug(
                        $"FootnoteExport page={pageNumber} footnote={markerText} rot={NormalizeRotation(rotation)} anchorRot={NormalizeRotation(markerAnchorRotation)} " +
                        $"selection={FormatRectFInvariant(markerAnchorRect)} badge={FormatRectFInvariant(badgeRect)} " +
                        $"viewPoint={FormatPointFInvariant(markerViewPoint)} pdfPoint={FormatPointFInvariant(markerPdfPoint)} " +
                        $"textW={markerWidth.ToString("0.###", CultureInfo.InvariantCulture)} " +
                        $"textH={markerHeight.ToString("0.###", CultureInfo.InvariantCulture)} " +
                        $"anchorUsed={FormatPointFInvariant(markerViewPoint)} " +
                        $"anchorTL={FormatPointFInvariant(new PointF(markerAnchorRect.Left, markerAnchorRect.Top))} " +
                        $"anchorTR={FormatPointFInvariant(new PointF(markerAnchorRect.Right, markerAnchorRect.Top))} " +
                        $"comp=0");
                }

                using (var layoutCanvas = new Canvas(new iText.Kernel.Pdf.Canvas.PdfCanvas(page), page.GetPageSize()))
                {
                    var markerParagraph = new iText.Layout.Element.Paragraph(markerText)
                        .SetMargin(0)
                        .SetPadding(0)
                        .SetMultipliedLeading(1f)
                        .SetFont(markerFont)
                        .SetFontSize(markerFontSize)
                        .SetFontColor(new DeviceRgb(0, 0, 0));

                    layoutCanvas.ShowTextAligned(
                        markerParagraph,
                        markerPdfPoint.X,
                        markerPdfPoint.Y,
                        pageNumber,
                        iText.Layout.Properties.TextAlignment.LEFT,
                        iText.Layout.Properties.VerticalAlignment.TOP,
                        markerTextRotationRadians);
                }

                DrawCornerDebugMarkersOnPdf(
                    new iText.Kernel.Pdf.Canvas.PdfCanvas(page),
                    markerFont,
                    markerAnchorRect,
                    pageNumber,
                    rotation,
                    includeBaseRotation);
            }
        }

        private RectangleF GetFootnoteMarkerAnchorRect(
            RedactionBlock block,
            iText.Kernel.Pdf.PdfPage page,
            int pageNumber,
            int rotation,
            bool includeBaseRotation,
            IDictionary<RedactionBlock, RectangleF> redactionVisualPdfBoundsByBlock)
        {
            if (block == null || page == null)
            {
                return RectangleF.Empty;
            }

            RectangleF anchorRect = block.Bounds;

            RectangleF sourcePdfRect = ConvertToPdfCoordinates(
                block.Bounds,
                pageNumber,
                rotation,
                includeBaseRotation);
            RectangleF visualPdfRect = sourcePdfRect;
            RectangleF cachedVisualRect = sourcePdfRect;
            bool hasCachedVisualRect = redactionVisualPdfBoundsByBlock != null &&
                                       redactionVisualPdfBoundsByBlock.TryGetValue(block, out cachedVisualRect);
            if (hasCachedVisualRect)
            {
                visualPdfRect = cachedVisualRect;
            }

            anchorRect = ConvertPdfToViewCoordinates(
                visualPdfRect,
                pageNumber,
                rotation,
                includeBaseRotation);

            int normalizedRotation = NormalizeRotation(rotation);

            if (DebugLogEnabled)
            {
                LogDebug(
                    $"FootnoteAnchor page={pageNumber} rot={normalizedRotation} includeBase={includeBaseRotation} " +
                    $"blockView={FormatRectFInvariant(block.Bounds)} sourcePdf={FormatRectFInvariant(sourcePdfRect)} " +
                    $"visualPdf={FormatRectFInvariant(visualPdfRect)} fromCache={hasCachedVisualRect} marker={block.IsMarkerSelection} " +
                    $"anchorView={FormatRectFInvariant(anchorRect)}");
            }

            return anchorRect;
        }

        private void AppendFootnotesSummaryPageIfNeeded(
            iText.Kernel.Pdf.PdfDocument pdfDoc,
            IList<RedactionBlock> blocksWithFootnotes,
            IDictionary<string, int> basisNumberMap)
        {
            if (pdfDoc == null || blocksWithFootnotes == null || blocksWithFootnotes.Count == 0)
            {
                return;
            }

            List<(int Number, string Text)> summaryEntries = BuildFootnoteSummaryEntries(blocksWithFootnotes, basisNumberMap);
            if (summaryEntries.Count == 0)
            {
                return;
            }

            PdfFont titleFont = PdfFontFactory.CreateFont(iText.IO.Font.Constants.StandardFonts.HELVETICA_BOLD, "Cp1250");
            PdfFont bodyFont = PdfFontFactory.CreateFont(iText.IO.Font.Constants.StandardFonts.HELVETICA, "Cp1250");
            PdfFont italicFont = PdfFontFactory.CreateFont(iText.IO.Font.Constants.StandardFonts.HELVETICA_OBLIQUE, "Cp1250");

            iText.Kernel.Pdf.PdfPage page = pdfDoc.AddNewPage(iText.Kernel.Geom.PageSize.A4);
            var pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(page);
            float left = 50f;
            float top = page.GetPageSize().GetTop() - 56f;
            float maxTextWidth = page.GetPageSize().GetWidth() - (left * 2f);
            const float titleFontSize = 15f;
            const float bodyFontSize = 11f;
            const float lineHeight = 16f;
            float currentY = top;

            pdfCanvas.BeginText();
            pdfCanvas.SetFontAndSize(titleFont, titleFontSize);
            pdfCanvas.MoveText(left, currentY);
            pdfCanvas.ShowText(LocalizedText("Footnotes_SummaryTitle"));
            pdfCanvas.EndText();

            currentY -= lineHeight * 1.5f;

            bool requiresAuthorityLine = (blocksWithFootnotes ?? new List<RedactionBlock>())
                .Any(block => BlockRequiresInterestSubject(block));
            if (requiresAuthorityLine)
            {
                pdfCanvas.BeginText();
                pdfCanvas.SetFontAndSize(italicFont, bodyFontSize);
                pdfCanvas.MoveText(left, currentY);
                pdfCanvas.ShowText(GetExclusionAuthoritySummaryLine(ResolveExclusionAuthorityForSummary(blocksWithFootnotes)));
                pdfCanvas.EndText();

                currentY -= lineHeight * 2f;
            }
            else
            {
                currentY -= lineHeight;
            }

            foreach (var entry in summaryEntries)
            {
                string line = $"[{entry.Number}] {entry.Text}";
                var wrappedLines = WrapTextToWidth(bodyFont, line, bodyFontSize, maxTextWidth);
                if (wrappedLines.Count == 0)
                {
                    wrappedLines.Add(line);
                }

                foreach (string wrappedLine in wrappedLines)
                {
                    if (currentY < 50f)
                    {
                        page = pdfDoc.AddNewPage(iText.Kernel.Geom.PageSize.A4);
                        pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(page);
                        currentY = page.GetPageSize().GetTop() - 56f;
                    }

                    pdfCanvas.BeginText();
                    pdfCanvas.SetFontAndSize(bodyFont, bodyFontSize);
                    pdfCanvas.MoveText(left, currentY);
                    pdfCanvas.ShowText(wrappedLine);
                    pdfCanvas.EndText();
                    currentY -= lineHeight;
                }

                currentY -= 6f;
            }
        }

        private void RenderCommentAnnotationsToPdf(
            iText.Kernel.Pdf.PdfDocument pdfDoc,
            ISet<int> pagesWithBakedRotation,
            ISet<int> removedPages,
            ISet<int> excludedPages = null)
        {
            if (pdfDoc == null || commentAnnotations == null || commentAnnotations.Count == 0)
            {
                return;
            }

            List<CommentAnnotation> exportComments = commentAnnotations
                .Where(c => c != null && c.PageNumber >= 1 && c.PageNumber <= pdfDoc.GetNumberOfPages())
                .Where(c => removedPages == null || !removedPages.Contains(c.PageNumber))
                .Where(c => excludedPages == null || !excludedPages.Contains(c.PageNumber))
                .OrderBy(c => c.PageNumber)
                .ThenBy(c => c.Bounds.Top)
                .ThenBy(c => c.Bounds.Left)
                .ToList();
            if (exportComments.Count == 0)
            {
                return;
            }

            PdfFont noteFont = PdfFontFactory.CreateFont(iText.IO.Font.Constants.StandardFonts.HELVETICA, "Cp1250");
            const float noteFontSize = 7f;
            const float notePadding = 2.5f;
            var highlightState = new PdfExtGState().SetFillOpacity(1f);
            highlightState.GetPdfObject().Put(PdfName.BM, PdfName.Multiply);
            var noteFillState = new PdfExtGState().SetFillOpacity(0.82f);

            foreach (var pageGroup in exportComments.GroupBy(c => c.PageNumber))
            {
                int pageNumber = pageGroup.Key;
                iText.Kernel.Pdf.PdfPage page = pdfDoc.GetPage(pageNumber);
                if (page == null)
                {
                    continue;
                }

                bool baseRotationBaked = pagesWithBakedRotation != null && pagesWithBakedRotation.Contains(pageNumber);
                int rotation = baseRotationBaked ? GetRotationOffset(pageNumber) : GetEffectiveRotationDegrees(pageNumber);
                bool includeBaseRotation = !baseRotationBaked;
                var viewSize = GetPageSizeWithOffset(pageNumber);
                float viewWidth = Math.Max(1f, viewSize.Width);
                float viewHeight = Math.Max(1f, viewSize.Height);
                float margin = 6f;
                float noteGap = 4f;
                float defaultNoteWidth = 50f;
                float nextAutoY = margin;

                var pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(page);
                using (var layoutCanvas = new Canvas(pdfCanvas, page.GetPageSize()))
                {
                    int noteIndex = 0;
                    foreach (var comment in pageGroup.OrderBy(c => c.Bounds.Top).ThenBy(c => c.Bounds.Left))
                    {
                        System.Drawing.Color highlightColorDrawing = GetCommentHighlightColor(comment);
                        System.Drawing.Color textColorDrawing = GetCommentTextColor(comment);
                        var noteColor = new DeviceRgb(highlightColorDrawing.R, highlightColorDrawing.G, highlightColorDrawing.B);
                        var noteTextColor = new DeviceRgb(textColorDrawing.R, textColorDrawing.G, textColorDrawing.B);
                        RectangleF sourcePdfRect = ConvertToPdfCoordinates(
                            comment.Bounds,
                            pageNumber,
                            rotation,
                            includeBaseRotation);
                        iText.Kernel.Geom.Rectangle highlightRectangle = new iText.Kernel.Geom.Rectangle(
                            sourcePdfRect.X,
                            sourcePdfRect.Y,
                            sourcePdfRect.Width,
                            sourcePdfRect.Height);
                        highlightRectangle = ExpandMarkerCleanupRectangleToTextBounds(
                            page,
                            highlightRectangle,
                            pageNumber,
                            rotation,
                            comment.IsMarkerSelection ? "comment-marker" : "comment-box");
                        RectangleF highlightViewRect = ConvertPdfToViewCoordinates(
                            ConvertToItTextRectangleF(highlightRectangle),
                            pageNumber,
                            rotation,
                            includeBaseRotation);

                        pdfCanvas.SaveState();
                        pdfCanvas.SetExtGState(highlightState);
                        pdfCanvas.SetFillColor(noteColor);
                        pdfCanvas.Rectangle(
                            highlightRectangle.GetX(),
                            highlightRectangle.GetY(),
                            highlightRectangle.GetWidth(),
                            highlightRectangle.GetHeight());
                        pdfCanvas.Fill();
                        pdfCanvas.RestoreState();

                        noteIndex++;
                        string noteTextValue = string.IsNullOrWhiteSpace(comment.CommentText)
                            ? GetDefaultCommentText()
                            : comment.CommentText.Replace("\r\n", "\n").Replace("\r", "\n").Trim();
                        string noteText = $"{noteIndex}. {noteTextValue}";
                        float noteWidth = Math.Max(40f, Math.Min(240f, comment.NoteWidth ?? defaultNoteWidth));

                        List<string> wrappedLines = WrapTextToWidth(
                            noteFont,
                            noteText,
                            noteFontSize,
                            Math.Max(30f, noteWidth - (notePadding * 2f)));
                        if (wrappedLines.Count == 0)
                        {
                            wrappedLines.Add(noteText);
                        }

                        float lineHeight = noteFontSize + 1.2f;
                        float autoNoteHeight = Math.Max(16f, (wrappedLines.Count * lineHeight) + (notePadding * 2f));
                        float noteHeight = Math.Max(12f, Math.Min(200f, comment.NoteHeight ?? autoNoteHeight));
                        float noteX;
                        float noteY;
                        if (comment.NoteX.HasValue && comment.NoteY.HasValue)
                        {
                            noteX = comment.NoteX.Value;
                            noteY = comment.NoteY.Value;
                        }
                        else
                        {
                            noteX = viewWidth - margin - noteWidth;
                            float preferredY = highlightViewRect.Top - (noteHeight * 0.2f);
                            noteY = Math.Max(preferredY, nextAutoY);
                            nextAutoY = noteY + noteHeight + noteGap;
                        }
                        noteX = Math.Max(margin, Math.Min(viewWidth - margin - noteWidth, noteX));
                        noteY = Math.Max(margin, Math.Min(viewHeight - margin - noteHeight, noteY));
                        RectangleF noteViewRect = new RectangleF(noteX, noteY, noteWidth, noteHeight);

                        RectangleF notePdfRect = ConvertToPdfCoordinates(
                            noteViewRect,
                            pageNumber,
                            rotation,
                            includeBaseRotation);

                        pdfCanvas.SaveState();
                        pdfCanvas.SetExtGState(noteFillState);
                        pdfCanvas.SetFillColor(noteColor);
                        pdfCanvas.Rectangle(notePdfRect.X, notePdfRect.Y, notePdfRect.Width, notePdfRect.Height);
                        pdfCanvas.Fill();
                        pdfCanvas.RestoreState();

                        pdfCanvas.SaveState();
                        pdfCanvas.SetStrokeColor(noteColor);
                        pdfCanvas.SetLineWidth(0.6f);
                        pdfCanvas.Rectangle(notePdfRect.X, notePdfRect.Y, notePdfRect.Width, notePdfRect.Height);
                        pdfCanvas.Stroke();
                        pdfCanvas.RestoreState();

                        PointF connectorFromView = new PointF(
                            highlightViewRect.Right,
                            highlightViewRect.Top + (highlightViewRect.Height / 2f));
                        PointF connectorToView = new PointF(
                            noteViewRect.Left,
                            noteViewRect.Top + (noteViewRect.Height / 2f));
                        PointF connectorFromPdf = ConvertPointToPdfCoordinates(
                            connectorFromView,
                            pageNumber,
                            rotation,
                            includeBaseRotation);
                        PointF connectorToPdf = ConvertPointToPdfCoordinates(
                            connectorToView,
                            pageNumber,
                            rotation,
                            includeBaseRotation);

                        pdfCanvas.SaveState();
                        pdfCanvas.SetStrokeColor(noteColor);
                        pdfCanvas.SetLineWidth(1.4f);
                        pdfCanvas.MoveTo(connectorFromPdf.X, connectorFromPdf.Y);
                        pdfCanvas.LineTo(connectorToPdf.X, connectorToPdf.Y);
                        pdfCanvas.Stroke();
                        pdfCanvas.RestoreState();

                        int normalizedPageRotation = NormalizeRotation(rotation);
                        int commentTextRotation;
                        switch (normalizedPageRotation)
                        {
                            case 0:
                                commentTextRotation = 0;
                                break;
                            case 90:
                                commentTextRotation = 90;
                                break;
                            case 180:
                                commentTextRotation = 180;
                                break;
                            case 270:
                                commentTextRotation = 270;
                                break;
                            default:
                                commentTextRotation = 0;
                                break;
                        }

                        bool verticalText = commentTextRotation == 90 || commentTextRotation == 270;
                        float wrapWidth = verticalText
                            ? Math.Max(20f, notePdfRect.Height - (notePadding * 2f))
                            : Math.Max(20f, notePdfRect.Width - (notePadding * 2f));
                        List<string> wrappedLinesPdf = WrapTextToWidth(
                            noteFont,
                            noteText,
                            noteFontSize,
                            wrapWidth);
                        if (wrappedLinesPdf.Count == 0)
                        {
                            wrappedLinesPdf.Add(noteText);
                        }

                        pdfCanvas.SaveState();
                        pdfCanvas.BeginText();
                        pdfCanvas.SetFillColor(noteTextColor);
                        pdfCanvas.SetFontAndSize(noteFont, noteFontSize);

                        for (int lineIndex = 0; lineIndex < wrappedLinesPdf.Count; lineIndex++)
                        {
                            string line = wrappedLinesPdf[lineIndex];
                            float lineX;
                            float lineY;
                            switch (commentTextRotation)
                            {
                                case 0:
                                    lineX = notePdfRect.X + notePadding;
                                    lineY = notePdfRect.Y + notePdfRect.Height - notePadding - noteFontSize - (lineIndex * lineHeight);
                                    if (lineY < notePdfRect.Y + notePadding)
                                    {
                                        continue;
                                    }
                                    pdfCanvas.SetTextMatrix(1f, 0f, 0f, 1f, lineX, lineY);
                                    break;
                                case 90:
                                    lineX = notePdfRect.X + notePadding + noteFontSize + (lineIndex * lineHeight);
                                    if (lineX > notePdfRect.Right - notePadding)
                                    {
                                        continue;
                                    }
                                    lineY = notePdfRect.Y + notePadding;
                                    pdfCanvas.SetTextMatrix(0f, 1f, -1f, 0f, lineX, lineY);
                                    break;
                                case 180:
                                    lineX = notePdfRect.Right - notePadding;
                                    lineY = notePdfRect.Y + notePadding + noteFontSize + (lineIndex * lineHeight);
                                    if (lineY > notePdfRect.Bottom - notePadding)
                                    {
                                        continue;
                                    }
                                    pdfCanvas.SetTextMatrix(-1f, 0f, 0f, -1f, lineX, lineY);
                                    break;
                                case 270:
                                default:
                                    lineX = notePdfRect.X + notePadding + noteFontSize + (lineIndex * lineHeight);
                                    if (lineX > notePdfRect.Right - notePadding)
                                    {
                                        continue;
                                    }
                                    lineY = notePdfRect.Bottom - notePadding;
                                    pdfCanvas.SetTextMatrix(0f, -1f, 1f, 0f, lineX, lineY);
                                    break;
                            }
                            pdfCanvas.ShowText(line);
                        }

                        pdfCanvas.EndText();
                        pdfCanvas.RestoreState();
                    }
                }
            }
        }

        private void RemoveRedactionBlock(RedactionBlock blockToRemove)
        {
            if (blockToRemove == null)
            {
                return;
            }

            renderTimer.Stop();
            if (!redactionBlocks.Remove(blockToRemove))
            {
                return;
            }

            PageItemStatus status = allPageStatuses[currentPage - 1];
            RedactionBlock blocksByPage = redactionBlocks.FirstOrDefault(block => block.PageNumber == currentPage);
            if (blocksByPage == null)
            {
                status.HasSelections = false;

                if ((string)filterComboBox.SelectedItem == allComboItem)
                {
                    ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                    UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                    pagesListView.Invalidate(currentItem.Bounds);
                }
                else
                {
                    // Rebuild list according to active filter.
                    ApplyFilter((string)filterComboBox.SelectedItem);
                }
            }

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            UpdateSelectionNavigationButtons();
            renderTimer.Stop();
            renderTimer.Start();
            pdfViewer.Invalidate();
        }

        private void LogFootnoteBadgeLayoutIfNeeded(string markerText, RedactionBlock block, RectangleF selectionRect, RectangleF badgeRect, int rotationOffset, float rotationCompensation)
        {
            if (!DebugLogEnabled || block == null || string.IsNullOrWhiteSpace(markerText))
            {
                return;
            }

            if (rotationOffset != 90 && rotationOffset != 270)
            {
                return;
            }

            float topDelta = badgeRect.Top - selectionRect.Top;
            string key = string.Format(
                CultureInfo.InvariantCulture,
                "{0}|{1}|{2}|{3}|{4}",
                block.PageNumber,
                markerText,
                rotationOffset,
                FormatRectFInvariant(selectionRect),
                FormatRectFInvariant(badgeRect));

            if (string.Equals(lastFootnoteBadgeLayoutLogKey, key, StringComparison.Ordinal))
            {
                return;
            }

            lastFootnoteBadgeLayoutLogKey = key;
            LogDebug(
                $"FootnoteBadge page={block.PageNumber} footnote={markerText} rot={rotationOffset} " +
                $"selection={FormatRectFInvariant(selectionRect)} badge={FormatRectFInvariant(badgeRect)} " +
                $"topDelta={topDelta.ToString("0.###", CultureInfo.InvariantCulture)} comp={rotationCompensation.ToString("0.###", CultureInfo.InvariantCulture)} scale={scaleFactor.ToString("0.###", CultureInfo.InvariantCulture)}");
        }

        private void DrawVectorShapeOnPreview(Graphics graphics, VectorShapeObject vectorShape, bool multiSelectionActive)
        {
            if (graphics == null || vectorShape == null || vectorShape.PageNumber != currentPage || vectorShape.Points == null || vectorShape.Points.Count < 2)
            {
                return;
            }

            VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
            VectorShapeStrokeKind strokeKind = ParseVectorStrokeKind(vectorShape.StrokeStyle);
            PointF[] points = BuildVectorShapeRenderPoints(shapeType, vectorShape.Points)
                .Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor))
                .ToArray();
            if (points.Length < 2)
            {
                return;
            }

            using (var pen = new Pen(System.Drawing.Color.FromArgb(vectorShape.StrokeColorArgb), NormalizeVectorStrokeWidth(vectorShape.StrokeWidth) * scaleFactor))
            {
                bool isSelectedVector = IsVectorShapeSelected(vectorShape);
                bool hasStrokeColor = HasVisibleVectorColor(vectorShape.StrokeColorArgb);
                bool drawStroke = hasStrokeColor || isSelectedVector;
                if (isSelectedVector)
                {
                    pen.Color = System.Drawing.Color.Red;
                    pen.Width = Math.Max(SelectedObjectBorderWidth, pen.Width + 1f);
                }
                pen.DashStyle = ToDrawingDashStyle(strokeKind);
                pen.LineJoin = LineJoin.Round;
                pen.StartCap = LineCap.Round;
                pen.EndCap = LineCap.Round;

                bool isClosed = IsShapeClosed(shapeType);
                bool supportsFill = ShapeTypeSupportsFill(shapeType);
                if (isClosed && points.Length >= 3)
                {
                    bool hasFillColor = HasVisibleVectorColor(vectorShape.FillColorArgb);
                    if (supportsFill && hasFillColor)
                    {
                        int alpha = (int)(NormalizeVectorFillOpacity(vectorShape.FillOpacity) * 255f);
                        alpha = Math.Max(0, Math.Min(255, alpha));
                        if (alpha > 0)
                        {
                            System.Drawing.Color fillBase = System.Drawing.Color.FromArgb(vectorShape.FillColorArgb);
                            System.Drawing.Color fillColor = System.Drawing.Color.FromArgb(alpha, fillBase.R, fillBase.G, fillBase.B);
                            VectorFillPatternKind fillPattern = ParseVectorFillPattern(vectorShape.FillPattern);
                            if (fillPattern == VectorFillPatternKind.Solid)
                            {
                                using (var fillBrush = new SolidBrush(fillColor))
                                {
                                    graphics.FillPolygon(fillBrush, points);
                                }
                            }
                            else
                            {
                                using (var fillBrush = new SolidBrush(fillColor))
                                {
                                    graphics.FillPolygon(fillBrush, points);
                                }
                                if (HasVisibleVectorColor(vectorShape.FillPatternColorArgb))
                                {
                                    System.Drawing.Color patternBase = System.Drawing.Color.FromArgb(vectorShape.FillPatternColorArgb);
                                    System.Drawing.Color patternColor = System.Drawing.Color.FromArgb(alpha, patternBase.R, patternBase.G, patternBase.B);
                                    using (var hatchBrush = new HatchBrush(
                                        ToDrawingHatchStyle(fillPattern),
                                        patternColor,
                                        System.Drawing.Color.FromArgb(0, fillBase.R, fillBase.G, fillBase.B)))
                                    {
                                        graphics.FillPolygon(hatchBrush, points);
                                    }
                                }
                            }
                        }
                    }
                    if (drawStroke)
                    {
                        graphics.DrawPolygon(pen, points);
                    }
                }
                else
                {
                    if (drawStroke)
                    {
                        graphics.DrawLines(pen, points);
                    }
                }
            }

            if (multiSelectionActive && IsVectorShapeSelected(vectorShape))
            {
                float minX = points.Min(p => p.X);
                float maxX = points.Max(p => p.X);
                float minY = points.Min(p => p.Y);
                float maxY = points.Max(p => p.Y);
                RectangleF vectorBounds = new RectangleF(
                    minX,
                    minY,
                    Math.Max(1f, maxX - minX),
                    Math.Max(1f, maxY - minY));
                DrawGroupSelectionOutline(graphics, vectorBounds);
            }
        }

        private void DrawVectorShapeDraftOnPreview(Graphics graphics)
        {
            if (graphics == null || !isVectorShapeCreationMode || vectorShapeDraftPoints.Count == 0)
            {
                return;
            }

            var draftSourcePoints = vectorShapeDraftPoints.ToList();
            if (vectorShapeDraftHoverActive)
            {
                draftSourcePoints.Add(vectorShapeDraftHoverPoint);
            }

            var draftPoints = BuildVectorShapeRenderPoints(activeVectorShapeType, draftSourcePoints)
                .Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor))
                .ToList();
            if (draftPoints.Count < 2)
            {
                return;
            }

            using (var pen = new Pen(System.Drawing.Color.DarkOrange, Math.Max(1f, activeVectorShapeDefaults.StrokeWidth * scaleFactor)))
            {
                pen.DashStyle = DashStyle.Dash;
                pen.LineJoin = LineJoin.Round;
                pen.StartCap = LineCap.Round;
                pen.EndCap = LineCap.Round;

                if (IsShapeClosed(activeVectorShapeType) && draftPoints.Count >= 3)
                {
                    graphics.DrawPolygon(pen, draftPoints.ToArray());
                }
                else
                {
                    graphics.DrawLines(pen, draftPoints.ToArray());
                }
            }

            foreach (PointF point in vectorShapeDraftPoints.Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor)))
            {
                float size = 6f;
                graphics.FillEllipse(Brushes.DarkOrange, point.X - (size / 2f), point.Y - (size / 2f), size, size);
            }
        }

        private void DrawRasterObjectOnPreview(Graphics graphics, RasterObject rasterObject, bool multiSelectionActive)
        {
            if (graphics == null || rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return;
            }

            if (!TryCreateRasterPreviewImage(rasterObject, out DrawingImage previewImage))
            {
                return;
            }

            using (previewImage)
            {
                bool isSelectedRaster = IsRasterObjectSelected(rasterObject);
                bool showRasterTools = selectedRasterObject != null &&
                                       selectedRasterObject.Id == rasterObject.Id &&
                                       GetGroupSelectionCount() == 0;
                RectangleF scaledBounds = new RectangleF(
                    rasterObject.Bounds.X * scaleFactor,
                    rasterObject.Bounds.Y * scaleFactor,
                    rasterObject.Bounds.Width * scaleFactor,
                    rasterObject.Bounds.Height * scaleFactor);

                var state = graphics.Save();
                try
                {
                    graphics.TranslateTransform(
                        scaledBounds.X + (scaledBounds.Width / 2f),
                        scaledBounds.Y + (scaledBounds.Height / 2f));
                    graphics.RotateTransform(rasterObject.Rotation);
                    graphics.TranslateTransform(-(scaledBounds.Width / 2f), -(scaledBounds.Height / 2f));
                    float opacity = NormalizeOpacity(rasterObject.Opacity);
                    if (opacity >= 0.999f)
                    {
                        graphics.DrawImage(previewImage, new RectangleF(0f, 0f, scaledBounds.Width, scaledBounds.Height));
                    }
                    else
                    {
                        using (var imageAttributes = new ImageAttributes())
                        {
                            var colorMatrix = new ColorMatrix
                            {
                                Matrix33 = opacity
                            };
                            imageAttributes.SetColorMatrix(colorMatrix, ColorMatrixFlag.Default, ColorAdjustType.Bitmap);
                            var drawRect = new Rectangle(
                                0,
                                0,
                                Math.Max(1, (int)Math.Round(scaledBounds.Width)),
                                Math.Max(1, (int)Math.Round(scaledBounds.Height)));
                            graphics.DrawImage(
                                previewImage,
                                drawRect,
                                0,
                                0,
                                previewImage.Width,
                                previewImage.Height,
                                GraphicsUnit.Pixel,
                                imageAttributes);
                        }
                    }
                    System.Drawing.Color borderColor = (isSelectedRaster && !multiSelectionActive)
                        ? System.Drawing.Color.Red
                        : System.Drawing.Color.SteelBlue;
                    float borderWidth = (isSelectedRaster && !multiSelectionActive) ? SelectedObjectBorderWidth : 1f;
                    using (var borderPen = new Pen(borderColor, borderWidth))
                    {
                        graphics.DrawRectangle(borderPen, 0f, 0f, scaledBounds.Width, scaledBounds.Height);
                    }
                }
                finally
                {
                    graphics.Restore(state);
                }

                RectangleF frameBounds = GetRasterObjectScreenFrameBounds(rasterObject);
                if (frameBounds.Width > 0f && frameBounds.Height > 0f)
                {
                    if (showRasterTools)
                    {
                        using (var framePen = new Pen(System.Drawing.Color.Green, 1f))
                        {
                            graphics.DrawRectangle(framePen, frameBounds.X, frameBounds.Y, frameBounds.Width, frameBounds.Height);
                        }
                    }

                    if (multiSelectionActive && isSelectedRaster)
                    {
                        DrawGroupSelectionOutline(graphics, frameBounds);
                    }
                }

                if (showRasterTools && TryGetRasterRotationHandleRect(rasterObject, out RectangleF handleRect, out PointF connectorPoint))
                {
                    PointF handleCenter = new PointF(
                        handleRect.X + (handleRect.Width / 2f),
                        handleRect.Y + (handleRect.Height / 2f));
                    using (var connectorPen = new Pen(System.Drawing.Color.OrangeRed, 1.5f))
                    {
                        graphics.DrawLine(connectorPen, connectorPoint, handleCenter);
                    }
                    using (var handleBrush = new SolidBrush(System.Drawing.Color.White))
                    using (var handlePen = new Pen(System.Drawing.Color.OrangeRed, 2f))
                    {
                        graphics.FillEllipse(handleBrush, handleRect);
                        graphics.DrawEllipse(handlePen, handleRect);
                    }
                }

                if (showRasterTools && TryGetRasterResizeHandleRects(rasterObject, out Dictionary<RasterResizeHandleType, RectangleF> resizeHandles))
                {
                    using (var handleBrush = new SolidBrush(System.Drawing.Color.White))
                    using (var handlePen = new Pen(System.Drawing.Color.OrangeRed, 1.5f))
                    {
                        foreach (var kvp in resizeHandles)
                        {
                            if (kvp.Key == RasterResizeHandleType.None)
                            {
                                continue;
                            }

                            graphics.FillRectangle(handleBrush, kvp.Value);
                            graphics.DrawRectangle(handlePen, kvp.Value.X, kvp.Value.Y, kvp.Value.Width, kvp.Value.Height);
                        }
                    }
                }

                if (showRasterTools && TryGetRasterIconRects(rasterObject, out Dictionary<RasterIconType, Rectangle> iconRects))
                {
                    DrawIconButton(graphics, iconRects[RasterIconType.Edit], "\uE70F");
                    DrawIconButton(
                        graphics,
                        iconRects[RasterIconType.Lock],
                        rasterObject.IsLocked ? "\uE72E" : "\uE785");
                    DrawIconButton(graphics, iconRects[RasterIconType.Duplicate], "\uE8C8");
                    DrawIconButton(graphics, iconRects[RasterIconType.Order], "\u2630");
                    DrawIconButton(graphics, iconRects[RasterIconType.ResetSize], "\uE777");
                    DrawIconButton(graphics, iconRects[RasterIconType.Delete], "\uE74D");
                }
            }
        }

        private void DrawArrowObjectOnPreview(Graphics graphics, ArrowObject arrowObject, bool multiSelectionActive)
        {
            if (graphics == null || arrowObject == null || arrowObject.PageNumber != currentPage)
            {
                return;
            }

            arrowObject.Thickness = NormalizeArrowThickness(arrowObject.Thickness);
            arrowObject.HeadLength = NormalizeArrowHeadLength(arrowObject.HeadLength);
            arrowObject.HeadWidth = NormalizeArrowHeadWidth(arrowObject.HeadWidth);
            if (!IsArrowColorValid(arrowObject))
            {
                arrowObject.LineColorArgb = DefaultArrowColor.ToArgb();
            }

            bool isSelectedArrow = IsArrowObjectSelected(arrowObject);
            bool showArrowTools = selectedArrowObject != null &&
                                  selectedArrowObject.Id == arrowObject.Id &&
                                  GetGroupSelectionCount() == 0;
            System.Drawing.Color baseColor = (isSelectedArrow && !multiSelectionActive)
                ? System.Drawing.Color.Red
                : GetArrowColor(arrowObject);
            PointF startScreen = GetArrowScreenPoint(arrowObject.Start);
            PointF endScreen = GetArrowScreenPoint(arrowObject.End);
            float thicknessPx = Math.Max(1f, arrowObject.Thickness * scaleFactor);
            float headLengthPx = Math.Max(4f, arrowObject.HeadLength * scaleFactor);
            float headWidthPx = Math.Max(4f, arrowObject.HeadWidth * scaleFactor);

            var state = graphics.Save();
            try
            {
                graphics.SmoothingMode = System.Drawing.Drawing2D.SmoothingMode.AntiAlias;
                if (TryBuildArrowHead(startScreen, endScreen, headLengthPx, headWidthPx, out PointF leftPoint, out PointF rightPoint, out PointF lineEndPoint))
                {
                    using (var pen = new Pen(baseColor, thicknessPx))
                    {
                        pen.StartCap = System.Drawing.Drawing2D.LineCap.Round;
                        pen.EndCap = System.Drawing.Drawing2D.LineCap.Round;
                        pen.LineJoin = System.Drawing.Drawing2D.LineJoin.Round;
                        graphics.DrawLine(pen, startScreen, lineEndPoint);
                    }

                    using (var brush = new SolidBrush(baseColor))
                    {
                        graphics.FillPolygon(brush, new[] { endScreen, leftPoint, rightPoint });
                    }
                }
                else
                {
                    using (var pen = new Pen(baseColor, thicknessPx))
                    {
                        pen.StartCap = System.Drawing.Drawing2D.LineCap.Round;
                        pen.EndCap = System.Drawing.Drawing2D.LineCap.Round;
                        pen.LineJoin = System.Drawing.Drawing2D.LineJoin.Round;
                        graphics.DrawLine(pen, startScreen, endScreen);
                    }
                }

                if (multiSelectionActive && isSelectedArrow)
                {
                    float minX = Math.Min(startScreen.X, endScreen.X);
                    float maxX = Math.Max(startScreen.X, endScreen.X);
                    float minY = Math.Min(startScreen.Y, endScreen.Y);
                    float maxY = Math.Max(startScreen.Y, endScreen.Y);
                    RectangleF arrowBounds = new RectangleF(minX, minY, Math.Max(1f, maxX - minX), Math.Max(1f, maxY - minY));
                    DrawGroupSelectionOutline(graphics, arrowBounds);
                }

                if (showArrowTools)
                {
                    RectangleF startHandle = BuildHandleRect(startScreen, RasterResizeHandleSize);
                    RectangleF endHandle = BuildHandleRect(endScreen, RasterResizeHandleSize);
                    using (var handleBrush = new SolidBrush(System.Drawing.Color.White))
                    using (var handlePen = new Pen(System.Drawing.Color.OrangeRed, 1.5f))
                    {
                        graphics.FillRectangle(handleBrush, startHandle);
                        graphics.DrawRectangle(handlePen, startHandle.X, startHandle.Y, startHandle.Width, startHandle.Height);
                        graphics.FillRectangle(handleBrush, endHandle);
                        graphics.DrawRectangle(handlePen, endHandle.X, endHandle.Y, endHandle.Width, endHandle.Height);
                    }

                    if (TryGetArrowIconRects(arrowObject, out Dictionary<ArrowIconType, Rectangle> arrowIconRects))
                    {
                        DrawIconButton(graphics, arrowIconRects[ArrowIconType.Edit], "\uE70F");
                        DrawIconButton(
                            graphics,
                            arrowIconRects[ArrowIconType.Lock],
                            arrowObject.IsLocked ? "\uE72E" : "\uE785");
                        DrawIconButton(graphics, arrowIconRects[ArrowIconType.Duplicate], "\uE8C8");
                        DrawIconButton(graphics, arrowIconRects[ArrowIconType.Order], "\u2630");
                        DrawIconButton(graphics, arrowIconRects[ArrowIconType.Delete], "\uE74D");
                    }
                }
            }
            finally
            {
                graphics.Restore(state);
            }
        }

        private void DrawTextAnnotationOnPreview(Graphics graphics, TextAnnotation annotation, bool multiSelectionActive)
        {
            if (graphics == null || annotation == null || annotation.PageNumber != currentPage)
            {
                return;
            }

            System.Drawing.Rectangle rect = new System.Drawing.Rectangle(
                (int)(annotation.AnnotationBounds.X * scaleFactor),
                (int)(annotation.AnnotationBounds.Y * scaleFactor),
                (int)(annotation.AnnotationBounds.Width * scaleFactor * 72f / graphics.DpiX),
                (int)(annotation.AnnotationBounds.Height * scaleFactor * 72f / graphics.DpiY)
            );

            bool isSelectedAnnotation = IsTextAnnotationSelected(annotation);
            PointF[] textFrameCorners = null;
            bool hasTextFrame = TryGetAnnotationTextFrameGeometry(
                annotation,
                graphics.DpiX,
                graphics.DpiY,
                out textFrameCorners,
                out _,
                out _,
                out _);
            System.Drawing.Color annotationBackgroundColor = GetAnnotationBackgroundColor(annotation);
            bool isRich = IsRichTextMode(annotation);

            if (!isRich && hasTextFrame && annotationBackgroundColor.A > 0)
            {
                using (SolidBrush backgroundBrush = new SolidBrush(annotationBackgroundColor))
                {
                    graphics.FillPolygon(backgroundBrush, textFrameCorners);
                }
            }

            void DrawTextFrameOverlay()
            {
                if (!hasTextFrame)
                {
                    return;
                }

                System.Drawing.Color frameColor = (isSelectedAnnotation && !multiSelectionActive)
                    ? System.Drawing.Color.Red
                    : System.Drawing.Color.SteelBlue;
                float frameWidth = (isSelectedAnnotation && !multiSelectionActive)
                    ? SelectedObjectBorderWidth
                    : 1f;
                using (Pen textFramePen = new Pen(frameColor, frameWidth))
                {
                    textFramePen.Alignment = System.Drawing.Drawing2D.PenAlignment.Inset;
                    graphics.DrawPolygon(textFramePen, textFrameCorners);
                }
            }

            StringAlignment align;
            switch (annotation.AnnotationAlignment)
            {
                case System.Windows.Forms.HorizontalAlignment.Left:
                    align = StringAlignment.Near;
                    break;
                case System.Windows.Forms.HorizontalAlignment.Center:
                    align = StringAlignment.Center;
                    break;
                case System.Windows.Forms.HorizontalAlignment.Right:
                    align = StringAlignment.Far;
                    break;
                default:
                    align = StringAlignment.Near;
                    break;
            }

            StringFormat stringFormat = StringFormat.GenericTypographic;
            stringFormat.Alignment = align;
            stringFormat.LineAlignment = StringAlignment.Near;
            stringFormat.FormatFlags = StringFormatFlags.NoWrap;
            stringFormat.Trimming = StringTrimming.None;

            float dpiCorrection = 72f / graphics.DpiY;
            int annotationRotation = NormalizeRotation(annotation.AnnotationRotation);
            float layoutWidth;
            float layoutHeight;
            if (isRich)
            {
                SizeF richBaseSize = GetRichAnnotationSize(
                    annotation.AnnotationText,
                    annotation.AnnotationRichText,
                    annotation.AnnotationFont,
                    0);
                layoutWidth = richBaseSize.Width * scaleFactor * 72f / graphics.DpiX;
                layoutHeight = richBaseSize.Height * scaleFactor * 72f / graphics.DpiY;
            }
            else
            {
                SizeF baseSize = GetAnnotationSize(annotation.AnnotationText, annotation.AnnotationFont, 0);
                layoutWidth = baseSize.Width * scaleFactor * 72f / graphics.DpiX;
                layoutHeight = baseSize.Height * scaleFactor * 72f / graphics.DpiY;
            }

            if (isRich)
            {
                int bitmapWidth = Math.Max(1, (int)Math.Ceiling(layoutWidth));
                int bitmapHeight = Math.Max(1, (int)Math.Ceiling(layoutHeight));
                bitmapWidth = Math.Max(1, (int)Math.Ceiling(layoutWidth * (graphics.DpiX / 72f)));
                bitmapHeight = Math.Max(1, (int)Math.Ceiling(layoutHeight * (graphics.DpiY / 72f)));
                float richAlignmentOffset = GetRichAlignmentOffset(graphics.DpiX, annotation.AnnotationAlignment);
                using (Bitmap richBitmap = RenderRichTextToBitmap(
                    annotation,
                    bitmapWidth,
                    bitmapHeight,
                    annotationBackgroundColor,
                    Math.Max(0.1f, scaleFactor)))
                {
                    float rotationRadians = (float)(annotationRotation * Math.PI / 180.0);
                    float rotCos = (float)Math.Cos(rotationRadians);
                    float rotSin = (float)Math.Sin(rotationRadians);
                    PointF rotationOffset = GetRotationOffsetForBounds(annotationRotation, layoutWidth, layoutHeight);
                    float offsetX = rotationOffset.X;
                    float offsetY = rotationOffset.Y;

                    var state = graphics.Save();
                    graphics.Transform = new System.Drawing.Drawing2D.Matrix(
                        rotCos, rotSin, -rotSin, rotCos,
                        rect.X + offsetX, rect.Y + offsetY);
                    graphics.DrawImage(richBitmap, new RectangleF(-richAlignmentOffset, 0f, layoutWidth, layoutHeight));
                    graphics.Restore(state);
                }

                DrawTextFrameOverlay();

                if (multiSelectionActive && isSelectedAnnotation)
                {
                    DrawGroupSelectionOutline(graphics, rect);
                }

                return;
            }

            using (SolidBrush brush = new SolidBrush(annotation.AnnotationColor))
            {
                float scaledFontSize = annotation.AnnotationFont.Size * scaleFactor * dpiCorrection;
                using (Font scaledFont = new Font(annotation.AnnotationFont.FontFamily, scaledFontSize, annotation.AnnotationFont.Style))
                {
                    float rotationRadians = (float)(annotationRotation * Math.PI / 180.0);
                    float rotCos = (float)Math.Cos(rotationRadians);
                    float rotSin = (float)Math.Sin(rotationRadians);
                    PointF rotationOffset = GetRotationOffsetForBounds(annotationRotation, layoutWidth, layoutHeight);
                    float offsetX = rotationOffset.X;
                    float offsetY = rotationOffset.Y;

                    RectangleF layoutRect = new RectangleF(0, 0, layoutWidth, layoutHeight);
                    var state = graphics.Save();
                    graphics.Transform = new System.Drawing.Drawing2D.Matrix(
                        rotCos, rotSin, -rotSin, rotCos,
                        rect.X + offsetX, rect.Y + offsetY);
                    graphics.DrawString(
                        annotation.AnnotationText,
                        scaledFont,
                        brush,
                        layoutRect,
                        stringFormat
                    );
                    graphics.Restore(state);
                }
            }

            DrawTextFrameOverlay();

            if (multiSelectionActive && isSelectedAnnotation)
            {
                DrawGroupSelectionOutline(graphics, rect);
            }
        }

        private void DrawCommentAnnotationsOnPreview(Graphics graphics)
        {
            if (graphics == null || commentAnnotations == null || commentAnnotations.Count == 0 || currentPage <= 0)
            {
                return;
            }

            List<CommentAnnotation> comments = commentAnnotations
                .Where(c => c != null && c.PageNumber == currentPage)
                .OrderBy(c => c.Bounds.Top)
                .ThenBy(c => c.Bounds.Left)
                .ToList();
            if (comments.Count == 0)
            {
                return;
            }

            float connectorThickness = Math.Max(2.6f, scaleFactor * 1.6f);
            float borderThickness = Math.Max(1.2f, scaleFactor * 0.7f);
            float fontSize = Math.Max(6.5f, Math.Min(8.5f, this.Font.SizeInPoints * 0.72f));
            using (Font noteFont = new Font(this.Font.FontFamily, fontSize, FontStyle.Regular))
            {
                var noteRectsDoc = BuildCommentNoteRectanglesDoc(currentPage, graphics);
                commentNoteRectsDoc.Clear();
                foreach (var pair in noteRectsDoc)
                {
                    commentNoteRectsDoc[pair.Key] = pair.Value;
                }

                for (int index = 0; index < comments.Count; index++)
                {
                    CommentAnnotation comment = comments[index];
                    RectangleF highlightRect = new RectangleF(
                        comment.Bounds.X * scaleFactor,
                        comment.Bounds.Y * scaleFactor,
                        comment.Bounds.Width * scaleFactor,
                        comment.Bounds.Height * scaleFactor);

                    string text = string.IsNullOrWhiteSpace(comment.CommentText)
                        ? GetDefaultCommentText()
                        : comment.CommentText.Replace("\r\n", "\n").Replace("\r", "\n").Trim();
                    string noteText = $"{index + 1}. {text}";
                    if (!noteRectsDoc.TryGetValue(comment.Id, out RectangleF noteRectDoc))
                    {
                        continue;
                    }
                    RectangleF noteRect = new RectangleF(
                        noteRectDoc.X * scaleFactor,
                        noteRectDoc.Y * scaleFactor,
                        noteRectDoc.Width * scaleFactor,
                        noteRectDoc.Height * scaleFactor);

                    System.Drawing.Color highlightColor = GetCommentHighlightColor(comment);
                    System.Drawing.Color textColor = GetCommentTextColor(comment);
                    using (SolidBrush noteBack = new SolidBrush(System.Drawing.Color.FromArgb(215, highlightColor)))
                    using (Pen noteBorder = new Pen(highlightColor, borderThickness))
                    using (Pen connectorPen = new Pen(highlightColor, connectorThickness))
                    using (SolidBrush noteTextBrush = new SolidBrush(textColor))
                    {
                        connectorPen.DashStyle = DashStyle.Solid;
                        PointF from = new PointF(
                            highlightRect.Right,
                            highlightRect.Top + (highlightRect.Height / 2f));
                        PointF to = new PointF(noteRect.Left, noteRect.Top + (noteRect.Height / 2f));
                        graphics.DrawLine(connectorPen, from, to);

                        graphics.FillRectangle(noteBack, noteRect);
                        graphics.DrawRectangle(noteBorder, noteRect.X, noteRect.Y, noteRect.Width, noteRect.Height);
                        float handleSize = Math.Max(8f, CommentNoteResizeHandleSizePx);
                        RectangleF handleRect = new RectangleF(
                            noteRect.Right - handleSize,
                            noteRect.Bottom - handleSize,
                            handleSize,
                            handleSize);
                        graphics.FillRectangle(noteBorder.Brush, handleRect);
                        float textPadding = Math.Max(2f, 2f * Math.Min(1.4f, scaleFactor));
                        RectangleF textRect = new RectangleF(
                            noteRect.X + textPadding,
                            noteRect.Y + textPadding,
                            Math.Max(1f, noteRect.Width - (textPadding * 2f)),
                            Math.Max(1f, noteRect.Height - (textPadding * 2f)));
                        graphics.DrawString(noteText, noteFont, noteTextBrush, textRect);
                    }
                }
            }
        }

        private Bitmap RenderRichTextToBitmap(TextAnnotation annotation, int widthPx, int heightPx, System.Drawing.Color backgroundColor, float fontScale = 1f)
        {
            int safeWidth = Math.Max(1, widthPx);
            int safeHeight = Math.Max(1, heightPx);
            if (backgroundColor.A > 0)
            {
                return RenderRichTextToBitmapOpaque(annotation, safeWidth, safeHeight, backgroundColor, fontScale);
            }

            using (Bitmap black = RenderRichTextToBitmapOpaque(annotation, safeWidth, safeHeight, System.Drawing.Color.Black, fontScale))
            using (Bitmap white = RenderRichTextToBitmapOpaque(annotation, safeWidth, safeHeight, System.Drawing.Color.White, fontScale))
            {
                var bitmap = new Bitmap(safeWidth, safeHeight, PixelFormat.Format32bppArgb);
                for (int y = 0; y < safeHeight; y++)
                {
                    for (int x = 0; x < safeWidth; x++)
                    {
                        System.Drawing.Color cb = black.GetPixel(x, y);
                        System.Drawing.Color cw = white.GetPixel(x, y);

                        int alphaR = 255 - (cw.R - cb.R);
                        int alphaG = 255 - (cw.G - cb.G);
                        int alphaB = 255 - (cw.B - cb.B);
                        int alpha = Math.Max(0, Math.Min(255, (alphaR + alphaG + alphaB) / 3));
                        if (alpha <= 0)
                        {
                            bitmap.SetPixel(x, y, System.Drawing.Color.Transparent);
                            continue;
                        }

                        int r = Math.Max(0, Math.Min(255, (cb.R * 255) / alpha));
                        int g = Math.Max(0, Math.Min(255, (cb.G * 255) / alpha));
                        int b = Math.Max(0, Math.Min(255, (cb.B * 255) / alpha));
                        bitmap.SetPixel(x, y, System.Drawing.Color.FromArgb(alpha, r, g, b));
                    }
                }

                return bitmap;
            }
        }

        private Bitmap RenderRichTextToBitmapOpaque(TextAnnotation annotation, int safeWidth, int safeHeight, System.Drawing.Color backgroundColor, float fontScale)
        {
            int renderInsetPx = 0;
            if (annotation != null &&
                (annotation.AnnotationAlignment == System.Windows.Forms.HorizontalAlignment.Center ||
                 annotation.AnnotationAlignment == System.Windows.Forms.HorizontalAlignment.Right))
            {
                renderInsetPx = 6;
            }

            int renderWidth = safeWidth + renderInsetPx;
            var renderBitmap = new Bitmap(renderWidth, safeHeight, PixelFormat.Format32bppArgb);
            using (var graphics = Graphics.FromImage(renderBitmap))
            {
                graphics.Clear(backgroundColor);
            }

            using (var richTextBox = new RichTextBox())
            {
                richTextBox.BorderStyle = BorderStyle.None;
                richTextBox.ScrollBars = RichTextBoxScrollBars.None;
                richTextBox.Multiline = true;
                richTextBox.WordWrap = false;
                richTextBox.DetectUrls = false;
                richTextBox.ReadOnly = true;
                richTextBox.Font = annotation?.AnnotationFont ?? this.Font;
                richTextBox.ForeColor = annotation?.AnnotationColor ?? System.Drawing.Color.Black;
                richTextBox.BackColor = backgroundColor;
                richTextBox.Size = new Size(renderWidth, safeHeight);
                richTextBox.Location = Point.Empty;

                bool richLoaded = false;
                if (annotation != null && !string.IsNullOrWhiteSpace(annotation.AnnotationRichText))
                {
                    try
                    {
                        richTextBox.Rtf = annotation.AnnotationRichText;
                        richLoaded = true;
                    }
                    catch
                    {
                        richLoaded = false;
                    }
                }

                if (!richLoaded)
                {
                    richTextBox.Text = annotation?.AnnotationText ?? string.Empty;
                }
                ApplyRichParagraphAlignment(
                    richTextBox,
                    annotation?.AnnotationAlignment ?? System.Windows.Forms.HorizontalAlignment.Left);
                ApplyGlobalRichFont(richTextBox, annotation?.AnnotationFont ?? this.Font);

                float safeZoom = Math.Max(0.1f, Math.Min(8f, fontScale));
                richTextBox.ZoomFactor = safeZoom;

                richTextBox.CreateControl();
                richTextBox.DrawToBitmap(renderBitmap, new Rectangle(0, 0, renderWidth, safeHeight));
            }

            var bitmap = new Bitmap(safeWidth, safeHeight, PixelFormat.Format32bppArgb);
            using (var graphics = Graphics.FromImage(bitmap))
            {
                graphics.Clear(backgroundColor);
                graphics.DrawImage(
                    renderBitmap,
                    new Rectangle(0, 0, safeWidth, safeHeight),
                    new Rectangle(renderInsetPx, 0, safeWidth, safeHeight),
                    GraphicsUnit.Pixel);
            }
            renderBitmap.Dispose();
            return bitmap;
        }

        private void OnPaint(object sender, PaintEventArgs e)
        {
            // Draw current selection
            if (isDrawing && currentSelection.Width > 0 && currentSelection.Height > 0)
            {
                System.Drawing.Color selectionPreviewColor = isCommentCreationMode
                    ? System.Drawing.Color.FromArgb(140, 255, 235, 59)
                    : System.Drawing.Color.FromArgb(128, 255, 0, 0);
                using (SolidBrush brush = new SolidBrush(selectionPreviewColor))
                {
                    e.Graphics.FillRectangle(brush, currentSelection);
                }
            }

            if (commentPreviewOverlayReady)
            {
                DrawCommentAnnotationsOnPreview(e.Graphics);
            }

            Dictionary<string, int> previewBasisNumberMap = BuildLegalBasisFootnoteNumberMap();

            // Drawing saved redaction blocks for current page
            foreach (var block in redactionBlocks.Where(b => b.PageNumber == currentPage))
            {
                using (SolidBrush brush = new SolidBrush(System.Drawing.Color.FromArgb(128, 255, 0, 0)))
                {
                    System.Drawing.RectangleF rect = new System.Drawing.RectangleF((block.Bounds.X * scaleFactor), (block.Bounds.Y * scaleFactor), (block.Bounds.Width * scaleFactor), (block.Bounds.Height * scaleFactor));
                    e.Graphics.FillRectangle(brush, rect);
                    DrawCornerDebugMarkersOnPreview(e.Graphics, rect);

                    if (TryBuildFootnoteMarkerText(block, previewBasisNumberMap, out string badgeText))
                    {
                        string previewBadgeText = badgeText
                            .Replace("[", string.Empty)
                            .Replace("]", string.Empty)
                            .Replace(".", ",")
                            .Replace(",", ", ");
                        float badgeScale = Math.Max(1f, scaleFactor);
                        float badgeFontSize = Math.Max(9f, (this.Font.SizeInPoints * badgeScale) - 0.5f);
                        using (Font badgeFont = CreatePreviewBadgeFont(badgeFontSize))
                        {
                            TextRenderingHint previousTextRenderingHint = e.Graphics.TextRenderingHint;
                            try
                            {
                                e.Graphics.TextRenderingHint = TextRenderingHint.AntiAliasGridFit;
                                SizeF textSize = e.Graphics.MeasureString(previewBadgeText, badgeFont);
                                float badgePaddingX = Math.Max(4f, 4f * badgeScale);
                                float badgePaddingY = Math.Max(1f, 1f * badgeScale);
                                float badgeWidth = textSize.Width + (badgePaddingX * 2f);
                                float badgeHeight = textSize.Height + (badgePaddingY * 2f);
                                float margin = Math.Max(2f, 2f * badgeScale);
                                bool useRotationAwarePlacement = addObjectsByPageRotationEnabled;
                                int rotationOffset = useRotationAwarePlacement
                                    ? NormalizeRotation(GetRotationOffset(block.PageNumber))
                                    : 0;
                                float halfDiff = (badgeWidth - badgeHeight) / 2f;

                                float badgeX;
                                float badgeY;
                                if (!useRotationAwarePlacement)
                                {
                                    // Flat mode: always place marker on the right side (same visual rule as 0 deg).
                                    badgeX = rect.Right + margin;
                                    badgeY = rect.Top + (rect.Height / 2f) - badgeHeight;
                                }
                                else
                                {
                                    switch (rotationOffset)
                                    {
                                        case 90:
                                            badgeX = rect.Right - badgeWidth;
                                            badgeY = rect.Bottom + margin;
                                            break;
                                        case 180:
                                            badgeX = rect.Left - badgeWidth - margin;
                                            badgeY = rect.Bottom - badgeHeight;
                                            break;
                                        case 270:
                                            badgeX = rect.Left;
                                            badgeY = rect.Top - badgeHeight - margin;
                                            break;
                                        default:
                                            badgeX = rect.Right + margin;
                                            badgeY = rect.Top;
                                            break;
                                    }

                                    if (rotationOffset == 90)
                                    {
                                        badgeX += halfDiff;
                                        badgeY += halfDiff;
                                    }
                                    else if (rotationOffset == 270)
                                    {
                                        badgeX -= halfDiff;
                                        badgeY -= halfDiff;
                                    }

                                    float badgeVerticalShift = badgeHeight / 2f;
                                    switch (rotationOffset)
                                    {
                                        case 90:
                                            badgeX += badgeVerticalShift;
                                            break;
                                        case 180:
                                            badgeY += badgeVerticalShift;
                                            break;
                                        case 270:
                                            badgeX -= badgeVerticalShift;
                                            break;
                                        default:
                                            badgeY -= badgeVerticalShift;
                                            break;
                                    }

                                    float markerThicknessPx = markerWidth * scaleFactor;
                                    float minSelectionDim = Math.Min(rect.Width, rect.Height);
                                    float maxSelectionDim = Math.Max(rect.Width, rect.Height);
                                    bool isThinElongatedSelection = markerThicknessPx > 0f &&
                                                                    minSelectionDim <= markerThicknessPx * 1.4f &&
                                                                    maxSelectionDim >= minSelectionDim * 3f;
                                    if (isThinElongatedSelection)
                                    {
                                        bool markerAxisIsVertical = rect.Height > rect.Width;
                                        float markerAxisCenterY = rect.Top + (rect.Height / 2f);
                                        float markerAxisCenterX = rect.Left + (rect.Width / 2f);

                                        if (!markerAxisIsVertical)
                                        {
                                            if (rotationOffset == 0)
                                            {
                                                // Bottom edge of badge sits on marker symmetry axis.
                                                badgeY = markerAxisCenterY - badgeHeight;
                                            }
                                            else if (rotationOffset == 180)
                                            {
                                                // For 180 deg badge rotation, bottom edge maps to top edge in view space.
                                                badgeY = markerAxisCenterY;
                                            }
                                        }
                                        else
                                        {
                                            if (rotationOffset == 90)
                                            {
                                                // For 90 deg badge rotation, bottom edge maps to left edge in view space.
                                                badgeX = markerAxisCenterX;
                                            }
                                            else if (rotationOffset == 270)
                                            {
                                                // For 270 deg badge rotation, bottom edge maps to right edge in view space.
                                                badgeX = markerAxisCenterX - badgeWidth;
                                            }
                                        }
                                    }
                                }

                                if (badgeX + badgeWidth > pdfViewer.ClientSize.Width)
                                {
                                    badgeX = Math.Max(0f, rect.Right - badgeWidth - 2f);
                                }
                                if (badgeX < 0f)
                                {
                                    badgeX = 0f;
                                }
                                if (badgeY < 0f)
                                {
                                    badgeY = 0f;
                                }
                                if (badgeY + badgeHeight > pdfViewer.ClientSize.Height)
                                {
                                    badgeY = Math.Max(0f, pdfViewer.ClientSize.Height - badgeHeight);
                                }

                                RectangleF badgeRect = new RectangleF(badgeX, badgeY, badgeWidth, badgeHeight);
                                LogFootnoteBadgeLayoutIfNeeded(badgeText, block, rect, badgeRect, rotationOffset, halfDiff);
                                using (SolidBrush badgeBackground = new SolidBrush(System.Drawing.Color.FromArgb(64, 255, 0, 0)))
                                using (Pen badgeBorder = new Pen(System.Drawing.Color.FromArgb(220, 255, 0, 0), Math.Max(1f, badgeScale * 0.9f)))
                                using (SolidBrush badgeTextBrush = new SolidBrush(System.Drawing.Color.FromArgb(255, 255, 0, 0)))
                                {
                                    float borderInset = 3f;
                                    RectangleF borderRect = new RectangleF(
                                        badgeRect.X + borderInset,
                                        badgeRect.Y + borderInset,
                                        Math.Max(1f, badgeRect.Width - (borderInset * 2f)),
                                        Math.Max(1f, badgeRect.Height - (borderInset * 2f)));

                                    if (rotationOffset == 0)
                                    {
                                        e.Graphics.FillRectangle(badgeBackground, borderRect);
                                        e.Graphics.DrawRectangle(badgeBorder, borderRect.X, borderRect.Y, borderRect.Width, borderRect.Height);
                                        e.Graphics.DrawString(
                                            previewBadgeText,
                                            badgeFont,
                                            badgeTextBrush,
                                            badgeRect.X + badgePaddingX,
                                            badgeRect.Y + badgePaddingY);
                                    }
                                    else
                                    {
                                        var state = e.Graphics.Save();
                                        float centerX = badgeRect.X + (badgeRect.Width / 2f);
                                        float centerY = badgeRect.Y + (badgeRect.Height / 2f);
                                        e.Graphics.TranslateTransform(centerX, centerY);
                                        e.Graphics.RotateTransform(rotationOffset);
                                        e.Graphics.TranslateTransform(-centerX, -centerY);

                                        e.Graphics.FillRectangle(badgeBackground, borderRect);
                                        e.Graphics.DrawRectangle(badgeBorder, borderRect.X, borderRect.Y, borderRect.Width, borderRect.Height);
                                        e.Graphics.DrawString(
                                            previewBadgeText,
                                            badgeFont,
                                            badgeTextBrush,
                                            badgeRect.X + badgePaddingX,
                                            badgeRect.Y + badgePaddingY);

                                        e.Graphics.Restore(state);
                                    }
                                }
                            }
                            finally
                            {
                                e.Graphics.TextRenderingHint = previousTextRenderingHint;
                            }
                        }
                    }
                }
            }


            TextLocation selectedSearchLocation = null;
            if (currentLocationIndex >= 0 && currentLocationIndex < searchLocations.Count)
            {
                selectedSearchLocation = searchLocations[currentLocationIndex];
            }
            bool multiSelectionActive = GetTotalSelectedObjectsCount() > 1;

            // Drawing saved search results
            foreach (var location in searchLocations)
            {
                if (location.PageNumber == currentPage)
                {
                    float x = location.Rect.GetX();
                    float y = location.Rect.GetY();
                    float w = location.Rect.GetWidth();
                    float h = location.Rect.GetHeight();
                    int rotation = GetEffectiveRotationDegrees(location.PageNumber);

                    RectangleF rectF = new RectangleF(x, y, w, h);
                    var pdfCoordinates = ConvertPdfToViewCoordinates(rectF, currentPage, rotation);

                    // Default highlight â€“ e.g. yellow
                    System.Drawing.Color highlightColor = System.Drawing.Color.FromArgb(128, 255, 215, 0);

                    // Scale rectangle
                    float sc_x = pdfCoordinates.X * scaleFactor;
                    float sc_y = pdfCoordinates.Y * scaleFactor;
                    float sc_w = pdfCoordinates.Width * scaleFactor;
                    float sc_h = pdfCoordinates.Height * scaleFactor;
                    float highlightPad = Math.Max(2f, Math.Min(sc_w, sc_h) * 0.35f);
                    RectangleF primaryHighlightRect = new RectangleF(
                        sc_x - highlightPad,
                        sc_y - highlightPad,
                        sc_w + (highlightPad * 2f),
                        sc_h + (highlightPad * 2f));

                    using (Pen pen = new Pen(highlightColor, 3))
                    {
                        e.Graphics.DrawRectangle(pen, primaryHighlightRect.X, primaryHighlightRect.Y, primaryHighlightRect.Width, primaryHighlightRect.Height);
                    }

                    bool isSelectedSearchLocation = ReferenceEquals(location, selectedSearchLocation);
                    if (isSelectedSearchLocation)
                    {
                        // If this is currently selected location, change color to gray
                        highlightColor = System.Drawing.Color.FromArgb(255, 128, 128, 128);
                        float selectedPad = highlightPad * 2f;
                        RectangleF selectedHighlightRect = new RectangleF(
                            sc_x - selectedPad,
                            sc_y - selectedPad,
                            sc_w + (selectedPad * 2f),
                            sc_h + (selectedPad * 2f));

                        using (Pen pen = new Pen(highlightColor, 3))
                        {
                            e.Graphics.DrawRectangle(pen, selectedHighlightRect.X, selectedHighlightRect.Y, selectedHighlightRect.Width, selectedHighlightRect.Height);
                        }

                        if (DebugLogEnabled && (rotation == 90 || rotation == 270))
                        {
                            RectangleF scaledRect = new RectangleF(sc_x, sc_y, sc_w, sc_h);
                            LogDebug(
                                $"SearchHighlight page={location.PageNumber} idx={currentLocationIndex} pageRot={rotation} lineRot={NormalizeRotation(location.PageRotation)} " +
                                $"pdfRect={FormatRectFInvariant(rectF)} viewRect={FormatRectFInvariant(pdfCoordinates)} scaledRect={FormatRectFInvariant(scaledRect)} " +
                                $"drawPrimary={FormatRectFInvariant(primaryHighlightRect)} drawSelected={FormatRectFInvariant(selectedHighlightRect)}");
                        }
                    }
                }
            }

            foreach (object drawableObject in GetOrderedObjectsForCurrentPage())
            {
                if (drawableObject is RasterObject rasterObject)
                {
                    DrawRasterObjectOnPreview(e.Graphics, rasterObject, multiSelectionActive);
                }
                else if (drawableObject is ArrowObject arrowObject)
                {
                    DrawArrowObjectOnPreview(e.Graphics, arrowObject, multiSelectionActive);
                }
                else if (drawableObject is VectorShapeObject vectorShapeObject)
                {
                    DrawVectorShapeOnPreview(e.Graphics, vectorShapeObject, multiSelectionActive);
                }
                else if (drawableObject is TextAnnotation annotation)
                {
                    DrawTextAnnotationOnPreview(e.Graphics, annotation, multiSelectionActive);
                }
            }
            DrawVectorShapeDraftOnPreview(e.Graphics);

            if (!multiSelectionActive)
            {
                DrawSelectedTextOverlayOnTop(e.Graphics);
                DrawSelectedRasterOverlayOnTop(e.Graphics);
                DrawSelectedArrowOverlayOnTop(e.Graphics);
                DrawSelectedVectorOverlayOnTop(e.Graphics);
            }

            if (IsCurrentPageMarkedForDeletion())
            {
                using (var overlayBrush = new SolidBrush(System.Drawing.Color.FromArgb(120, 180, 180, 180)))
                {
                    e.Graphics.FillRectangle(overlayBrush, pdfViewer.ClientRectangle);
                }

                string lockMessage = LocalizedText("Msg_PageMarkedForDeletion_EditLocked");
                using (var messageFont = new Font("Segoe UI", 18f, FontStyle.Bold, GraphicsUnit.Point))
                using (var messagePath = new System.Drawing.Drawing2D.GraphicsPath())
                {
                    var sf = new StringFormat
                    {
                        Alignment = StringAlignment.Center,
                        LineAlignment = StringAlignment.Center
                    };
                    float emSize = e.Graphics.DpiY * messageFont.Size / 72f;
                    messagePath.AddString(
                        lockMessage,
                        messageFont.FontFamily,
                        (int)messageFont.Style,
                        emSize,
                        pdfViewer.ClientRectangle,
                        sf);

                    var state = e.Graphics.Save();
                    e.Graphics.SmoothingMode = System.Drawing.Drawing2D.SmoothingMode.AntiAlias;
                    e.Graphics.TextRenderingHint = System.Drawing.Text.TextRenderingHint.AntiAliasGridFit;
                    using (var haloPen = new Pen(System.Drawing.Color.FromArgb(240, 255, 255, 255), 6f))
                    using (var textBrush = new SolidBrush(System.Drawing.Color.FromArgb(235, 40, 40, 40)))
                    {
                        haloPen.LineJoin = System.Drawing.Drawing2D.LineJoin.Round;
                        e.Graphics.DrawPath(haloPen, messagePath);
                        e.Graphics.FillPath(textBrush, messagePath);
                    }
                    e.Graphics.Restore(state);
                }
            }


        }

        private void ClearSelectionButton_Click(object sender, EventArgs e)
        {
            DialogResult result = MessageBox.Show(this,
                Resources.Msg_Confirm_ClearAllSelections,
                Resources.Title_Confirmation,
                MessageBoxButtons.YesNo,
                MessageBoxIcon.Exclamation, MessageBoxDefaultButton.Button2
            );

            if (result == DialogResult.No)
            {
                return;
            }

            ClearRedactionBlocks();
        }

        private void ClearPageButton_Click(object sender, EventArgs e)
        {
            ClearCurrentPageRedactionBlock();
        }

        private void ApplyRightPanelTabSelectionFromSettings()
        {
            try
            {
                if (pagesTabControl == null || pagesListTabPage == null || thumbnailsTabPage == null)
                {
                    return;
                }

                bool useThumbnails = Properties.Settings.Default.UseThumbnailsTabInRightPanel;
                pagesTabControl.SelectedTab = useThumbnails ? thumbnailsTabPage : pagesListTabPage;
                if (useThumbnails)
                {
                    thumbnailViewportTimer?.Start();
                }
                else
                {
                    thumbnailViewportTimer?.Stop();
                }
            }
            catch (Exception ex)
            {
                LogDebug("Apply right-panel tab selection failed: " + ex.Message);
            }
        }

        private void SaveRightPanelTabSelectionUserSetting(bool useThumbnails)
        {
            try
            {
                Properties.Settings.Default.UseThumbnailsTabInRightPanel = useThumbnails;
                Properties.Settings.Default.Save();
            }
            catch (Exception ex)
            {
                LogDebug("Save right-panel tab selection failed: " + ex.Message);
            }
        }

        private void ApplyRightPanelDividerFromSettings()
        {
            try
            {
                if (formSplitContainer == null)
                {
                    return;
                }

                int desiredRightPanelWidth = Properties.Settings.Default.RightPanelWidth;
                if (desiredRightPanelWidth <= 0)
                {
                    return;
                }

                int totalWidth = formSplitContainer.ClientSize.Width;
                int splitterWidth = formSplitContainer.SplitterWidth;
                if (totalWidth <= splitterWidth)
                {
                    return;
                }

                int minRightWidth = Math.Max(1, formSplitContainer.Panel2MinSize);
                int maxRightWidth = Math.Max(minRightWidth, totalWidth - splitterWidth - formSplitContainer.Panel1MinSize);
                int rightWidth = Math.Max(minRightWidth, Math.Min(desiredRightPanelWidth, maxRightWidth));

                int desiredSplitterDistance = totalWidth - splitterWidth - rightWidth;
                int minSplitterDistance = Math.Max(0, formSplitContainer.Panel1MinSize);
                int maxSplitterDistance = Math.Max(minSplitterDistance, totalWidth - splitterWidth - minRightWidth);
                desiredSplitterDistance = Math.Max(minSplitterDistance, Math.Min(desiredSplitterDistance, maxSplitterDistance));

                if (formSplitContainer.SplitterDistance != desiredSplitterDistance)
                {
                    formSplitContainer.SplitterDistance = desiredSplitterDistance;
                }
            }
            catch (Exception ex)
            {
                LogDebug("Apply right-panel divider failed: " + ex.Message);
            }
        }

        private void SaveRightPanelDividerUserSetting()
        {
            try
            {
                if (formSplitContainer == null)
                {
                    return;
                }

                int currentRightPanelWidth = formSplitContainer.Panel2.Width;
                if (currentRightPanelWidth <= 0)
                {
                    return;
                }

                if (Properties.Settings.Default.RightPanelWidth == currentRightPanelWidth)
                {
                    return;
                }

                Properties.Settings.Default.RightPanelWidth = currentRightPanelWidth;
                Properties.Settings.Default.Save();
            }
            catch (Exception ex)
            {
                LogDebug("Save right-panel divider failed: " + ex.Message);
            }
        }

        private void FormSplitContainer_SplitterMoved(object sender, SplitterEventArgs e)
        {
            SaveRightPanelDividerUserSetting();
        }

        private bool IsThumbnailsTabSelected()
        {
            return pagesTabControl != null && thumbnailsTabPage != null && pagesTabControl.SelectedTab == thumbnailsTabPage;
        }

        private void PagesTabControl_SelectedIndexChanged(object sender, EventArgs e)
        {
            if (pagesTabControl == null || pagesTabControl.SelectedTab == null)
            {
                return;
            }

            SaveRightPanelTabSelectionUserSetting(IsThumbnailsTabSelected());

            if (IsThumbnailsTabSelected())
            {
                thumbnailViewportTimer?.Start();
                EnsureThumbnailGeneration();
                SelectThumbnailItemForCurrentPage(ensureVisible: true);
            }
            else
            {
                thumbnailViewportTimer?.Stop();
                CancelThumbnailGeneration();
                SyncPagesListSelectionToCurrentPage(ensureVisible: true);
            }
        }

        private void InitializeThumbnailPanelItems()
        {
            if (thumbnailsListView == null || thumbnailsImageList == null)
            {
                return;
            }

            CancelThumbnailGeneration();
            thumbnailGenerationSourcePdfPath = inputPdfPath ?? string.Empty;
            thumbnailContentSizeByPage.Clear();
            PrepareThumbnailCacheForCurrentDocument();
            lock (thumbnailGenerationSync)
            {
                thumbnailGenerationQueue.Clear();
                thumbnailQueuedPages.Clear();
                thumbnailRenderedPages.Clear();
            }

            thumbnailsListView.BeginUpdate();
            try
            {
                thumbnailsListView.Items.Clear();
                thumbnailsImageList.Images.Clear();
                Bitmap placeholder = CreateThumbnailPlaceholderImage(thumbnailsImageList.ImageSize);
                thumbnailsImageList.Images.Add("placeholder", placeholder);
                for (int i = 1; i <= numPages; i++)
                {
                    thumbnailContentSizeByPage[i] = thumbnailsImageList.ImageSize;
                }
            }
            finally
            {
                thumbnailsListView.EndUpdate();
            }

            var filteredPages = GetStatusesForFilter((string)filterComboBox.SelectedItem)
                .Select(s => s.PageNumber)
                .ToList();
            RebuildThumbnailsForFilter(filteredPages);
        }

        private void ResetThumbnailPanel()
        {
            thumbnailViewportTimer?.Stop();
            CancelThumbnailGeneration();
            thumbnailGenerationSourcePdfPath = string.Empty;
            thumbnailCacheDocumentDirectory = string.Empty;

            if (thumbnailsListView != null)
            {
                thumbnailsListView.Items.Clear();
            }

            if (thumbnailsImageList != null)
            {
                thumbnailsImageList.Images.Clear();
            }

            thumbnailContentSizeByPage.Clear();
            lock (thumbnailGenerationSync)
            {
                thumbnailGenerationQueue.Clear();
                thumbnailQueuedPages.Clear();
                thumbnailRenderedPages.Clear();
            }
        }

        private void PrepareThumbnailCacheForCurrentDocument()
        {
            try
            {
                thumbnailCacheDocumentDirectory = string.Empty;
                if (string.IsNullOrWhiteSpace(inputPdfPath) || !File.Exists(inputPdfPath))
                {
                    return;
                }

                string fullPath = Path.GetFullPath(inputPdfPath);
                var fileInfo = new FileInfo(fullPath);
                string keySource = string.Join("|",
                    "thumbcache-v1",
                    fullPath.ToLowerInvariant(),
                    fileInfo.Length.ToString(CultureInfo.InvariantCulture),
                    fileInfo.LastWriteTimeUtc.Ticks.ToString(CultureInfo.InvariantCulture),
                    thumbnailsImageList.ImageSize.Width.ToString(CultureInfo.InvariantCulture),
                    thumbnailsImageList.ImageSize.Height.ToString(CultureInfo.InvariantCulture));
                string key = ComputeSha256Hex(keySource);
                string root = Path.Combine(
                    Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
                    "MISART",
                    "AnonPDFPro",
                    "thumbcache");
                string documentDir = Path.Combine(root, key);
                Directory.CreateDirectory(documentDir);
                thumbnailCacheDocumentDirectory = documentDir;
            }
            catch (Exception ex)
            {
                thumbnailCacheDocumentDirectory = string.Empty;
                LogDebug("Prepare thumbnail cache failed: " + ex.Message);
            }
        }

        private static string ComputeSha256Hex(string input)
        {
            using (var sha = SHA256.Create())
            {
                byte[] bytes = System.Text.Encoding.UTF8.GetBytes(input ?? string.Empty);
                byte[] hash = sha.ComputeHash(bytes);
                var sb = new System.Text.StringBuilder(hash.Length * 2);
                for (int i = 0; i < hash.Length; i++)
                {
                    sb.Append(hash[i].ToString("x2", CultureInfo.InvariantCulture));
                }

                return sb.ToString();
            }
        }

        private string GetThumbnailCacheFilePath(int pageNumber, int renderedWidth, int renderedHeight)
        {
            if (string.IsNullOrWhiteSpace(thumbnailCacheDocumentDirectory))
            {
                return string.Empty;
            }

            string fileName = string.Format(
                CultureInfo.InvariantCulture,
                "p{0:D5}_{1}x{2}.png",
                pageNumber,
                renderedWidth,
                renderedHeight);
            return Path.Combine(thumbnailCacheDocumentDirectory, fileName);
        }

        private static bool TryLoadThumbnailBitmapFromCache(string cachePath, out Bitmap bitmap)
        {
            bitmap = null;
            if (string.IsNullOrWhiteSpace(cachePath) || !File.Exists(cachePath))
            {
                return false;
            }

            try
            {
                using (var stream = new FileStream(cachePath, FileMode.Open, FileAccess.Read, FileShare.Read))
                using (var image = DrawingImage.FromStream(stream))
                {
                    bitmap = new Bitmap(image);
                }

                return true;
            }
            catch
            {
                try
                {
                    File.Delete(cachePath);
                }
                catch
                {
                    // ignore
                }

                return false;
            }
        }

        private static void TrySaveThumbnailBitmapToCache(string cachePath, Bitmap bitmap)
        {
            if (string.IsNullOrWhiteSpace(cachePath) || bitmap == null)
            {
                return;
            }

            try
            {
                string directory = Path.GetDirectoryName(cachePath);
                if (!string.IsNullOrWhiteSpace(directory))
                {
                    Directory.CreateDirectory(directory);
                }

                bitmap.Save(cachePath, ImageFormat.Png);
            }
            catch
            {
                // ignore cache write errors
            }
        }

        private void ApplyThumbnailIconSpacing()
        {
            try
            {
                if (thumbnailsListView == null || thumbnailsImageList == null || !thumbnailsListView.IsHandleCreated)
                {
                    return;
                }

                int iconWidth = Math.Max(1, thumbnailsImageList.ImageSize.Width);
                int iconHeight = Math.Max(1, thumbnailsImageList.ImageSize.Height);
                int horizontalSpacing = Math.Max(iconWidth + 8, iconWidth);
                int verticalSpacing = Math.Max(iconHeight + Math.Max(thumbnailsListView.Font.Height + 18, 34), iconHeight + 24);
                int lParam = (verticalSpacing << 16) | (horizontalSpacing & 0xFFFF);
                SendMessage(thumbnailsListView.Handle, LVM_SETICONSPACING, IntPtr.Zero, (IntPtr)lParam);
            }
            catch (Exception ex)
            {
                LogDebug("Apply thumbnail spacing failed: " + ex.Message);
            }
        }

        private void EnsureThumbnailGeneration()
        {
            if (!IsThumbnailsTabSelected() ||
                pdf == null ||
                numPages <= 0 ||
                string.IsNullOrWhiteSpace(inputPdfPath) ||
                !File.Exists(inputPdfPath))
            {
                return;
            }

            if (thumbnailsListView.Items.Count == 0)
            {
                RebuildThumbnailsForFilter(
                    GetStatusesForFilter((string)filterComboBox.SelectedItem)
                        .Select(s => s.PageNumber)
                        .ToList());
            }

            QueueVisibleThumbnailsForGeneration();
            StartThumbnailGenerationWorkerIfNeeded();
        }

        private void QueueVisibleThumbnailsForGeneration()
        {
            var candidatePages = GetThumbnailPagesAroundViewport();
            if (candidatePages.Count == 0)
            {
                return;
            }

            foreach (int page in candidatePages
                .OrderBy(p => Math.Abs(p - currentPage))
                .ThenBy(p => p))
            {
                QueueThumbnailPageForGeneration(page);
            }
        }

        private List<int> GetThumbnailPagesAroundViewport()
        {
            var result = new List<int>();
            if (thumbnailsListView == null || thumbnailsListView.Items.Count == 0)
            {
                return result;
            }

            DrawingRectangle client = thumbnailsListView.ClientRectangle;
            int firstVisible = int.MaxValue;
            int lastVisible = int.MinValue;

            for (int i = 0; i < thumbnailsListView.Items.Count; i++)
            {
                DrawingRectangle itemBounds = thumbnailsListView.GetItemRect(i, ItemBoundsPortion.Entire);
                if (itemBounds.IntersectsWith(client))
                {
                    firstVisible = Math.Min(firstVisible, i);
                    lastVisible = Math.Max(lastVisible, i);
                }
            }

            if (firstVisible == int.MaxValue || lastVisible == int.MinValue)
            {
                var fallbackItem = FindThumbnailListItemByPageNumber(currentPage);
                int fallback = fallbackItem != null
                    ? fallbackItem.Index
                    : Math.Max(0, Math.Min(thumbnailsListView.Items.Count - 1, 0));
                firstVisible = fallback;
                lastVisible = fallback;
            }

            int estimatedColumns = Math.Max(
                1,
                thumbnailsListView.ClientSize.Width / Math.Max(1, thumbnailsImageList.ImageSize.Width + 8));
            int buffer = Math.Max(4, estimatedColumns * 2);

            int startIndex = Math.Max(0, firstVisible - buffer);
            int endIndex = Math.Min(thumbnailsListView.Items.Count - 1, lastVisible + buffer);
            for (int i = startIndex; i <= endIndex; i++)
            {
                if (thumbnailsListView.Items[i].Tag is int page && page >= 1 && page <= numPages)
                {
                    result.Add(page);
                }
            }

            if (FindThumbnailListItemByPageNumber(currentPage) != null && !result.Contains(currentPage))
            {
                result.Add(currentPage);
            }

            return result;
        }

        private void QueueThumbnailPageForGeneration(int pageNumber)
        {
            if (pageNumber < 1 || pageNumber > numPages)
            {
                return;
            }

            lock (thumbnailGenerationSync)
            {
                string key = $"thumb_{pageNumber}";
                if (thumbnailRenderedPages.Contains(pageNumber) && !thumbnailsImageList.Images.ContainsKey(key))
                {
                    thumbnailRenderedPages.Remove(pageNumber);
                }

                if (thumbnailRenderedPages.Contains(pageNumber) || thumbnailQueuedPages.Contains(pageNumber))
                {
                    return;
                }

                thumbnailGenerationQueue.Enqueue(pageNumber);
                thumbnailQueuedPages.Add(pageNumber);
            }
        }

        private void CancelThumbnailGeneration()
        {
            lock (thumbnailGenerationSync)
            {
                thumbnailGenerationQueue.Clear();
                thumbnailQueuedPages.Clear();
            }

            var cts = thumbnailGenerationCts;
            thumbnailGenerationCts = null;

            try
            {
                cts?.Cancel();
            }
            catch
            {
                // ignore
            }
        }

        private void StartThumbnailGenerationWorkerIfNeeded()
        {
            if (thumbnailGenerationWorkerRunning)
            {
                return;
            }

            bool hasWork;
            lock (thumbnailGenerationSync)
            {
                hasWork = thumbnailGenerationQueue.Count > 0;
                if (hasWork)
                {
                    thumbnailGenerationWorkerRunning = true;
                }
            }

            if (!hasWork)
            {
                return;
            }

            var cts = new System.Threading.CancellationTokenSource();
            thumbnailGenerationCts = cts;
            string sourcePdfPath = inputPdfPath;
            string password = userPassword;
            thumbnailGenerationSourcePdfPath = sourcePdfPath ?? string.Empty;

            _ = Task.Run(() => ThumbnailGenerationWorkerAsync(sourcePdfPath, password, cts));
        }

        private async Task ThumbnailGenerationWorkerAsync(string sourcePdfPath, string password, System.Threading.CancellationTokenSource cts)
        {
            System.Threading.CancellationToken token = cts.Token;
            Size thumbnailSize = thumbnailsImageList.ImageSize;

            try
            {
                using (var thumbPdf = string.IsNullOrWhiteSpace(password)
                    ? new PDFiumSharp.PdfDocument(sourcePdfPath)
                    : new PDFiumSharp.PdfDocument(sourcePdfPath, password))
                {
                    while (true)
                    {
                        token.ThrowIfCancellationRequested();

                        int pageNumber;
                        lock (thumbnailGenerationSync)
                        {
                            if (thumbnailGenerationQueue.Count == 0)
                            {
                                break;
                            }

                            pageNumber = thumbnailGenerationQueue.Dequeue();
                            thumbnailQueuedPages.Remove(pageNumber);
                        }

                        if (pageNumber < 1 || pageNumber > thumbPdf.Pages.Count)
                        {
                            continue;
                        }

                        Bitmap thumbBitmap;
                        int renderedWidth = 1;
                        int renderedHeight = 1;
                        using (var page = thumbPdf.Pages[pageNumber - 1])
                        {
                            float pageWidth = Math.Max(1f, (float)page.Width);
                            float pageHeight = Math.Max(1f, (float)page.Height);
                            float scale = Math.Min(
                                thumbnailSize.Width / pageWidth,
                                thumbnailSize.Height / pageHeight);
                            int renderWidth = Math.Max(1, (int)Math.Round(pageWidth * scale));
                            int renderHeight = Math.Max(1, (int)Math.Round(pageHeight * scale));
                            renderedWidth = renderWidth;
                            renderedHeight = renderHeight;
                            string cachePath = GetThumbnailCacheFilePath(pageNumber, renderWidth, renderHeight);
                            if (!TryLoadThumbnailBitmapFromCache(cachePath, out thumbBitmap))
                            {
                                thumbBitmap = new Bitmap(thumbnailSize.Width, thumbnailSize.Height, PixelFormat.Format32bppArgb);
                                using (Graphics g = Graphics.FromImage(thumbBitmap))
                                {
                                    g.Clear(System.Drawing.Color.Transparent);
                                    int left = (thumbnailSize.Width - renderWidth) / 2;
                                    int top = (thumbnailSize.Height - renderHeight) / 2;
                                    using (var pdfBitmap = new PDFiumBitmap(renderWidth, renderHeight, false))
                                    {
                                        pdfBitmap.FillRectangle(0, 0, renderWidth, renderHeight, 0xFFFFFFFF);
                                        page.Render(renderTarget: pdfBitmap, flags: RenderingFlags.Annotations);
                                        using (var bmpStream = pdfBitmap.AsBmpStream())
                                        using (var rendered = DrawingImage.FromStream(bmpStream))
                                        {
                                            g.DrawImage(rendered, left, top, renderWidth, renderHeight);
                                        }
                                    }
                                }

                                TrySaveThumbnailBitmapToCache(cachePath, thumbBitmap);
                            }
                        }

                        if (!IsHandleCreated || IsDisposed || token.IsCancellationRequested)
                        {
                            thumbBitmap.Dispose();
                            break;
                        }

                        Invoke(new Action(() =>
                        {
                            if (thumbBitmap == null)
                            {
                                return;
                            }

                            if (!ArePathsEqual(sourcePdfPath, inputPdfPath) ||
                                pageNumber < 1 ||
                                pageNumber > numPages)
                            {
                                thumbBitmap.Dispose();
                                return;
                            }

                            var targetItem = FindThumbnailListItemByPageNumber(pageNumber);
                            string key = $"thumb_{pageNumber}";
                            if (thumbnailsImageList.Images.ContainsKey(key))
                            {
                                thumbnailsImageList.Images.RemoveByKey(key);
                            }

                            thumbnailsImageList.Images.Add(key, thumbBitmap);
                            if (targetItem != null)
                            {
                                targetItem.ImageKey = key;
                            }
                            thumbnailContentSizeByPage[pageNumber] = new Size(renderedWidth, renderedHeight);
                            lock (thumbnailGenerationSync)
                            {
                                thumbnailRenderedPages.Add(pageNumber);
                            }
                        }));

                        await Task.Yield();
                    }
                }
            }
            catch (OperationCanceledException)
            {
                // ignored
            }
            catch (Exception ex)
            {
                LogDebug("Thumbnail generation failed: " + ex.Message);
            }
            finally
            {
                if (ReferenceEquals(thumbnailGenerationCts, cts))
                {
                    thumbnailGenerationCts = null;
                }
                lock (thumbnailGenerationSync)
                {
                    thumbnailGenerationWorkerRunning = false;
                }
                cts.Dispose();

                if (IsHandleCreated && !IsDisposed)
                {
                    BeginInvoke(new Action(() =>
                    {
                        if (IsThumbnailsTabSelected())
                        {
                            QueueVisibleThumbnailsForGeneration();
                            StartThumbnailGenerationWorkerIfNeeded();
                        }
                    }));
                }
            }
        }

        private static Bitmap CreateThumbnailPlaceholderImage(Size size)
        {
            Bitmap bitmap = new Bitmap(Math.Max(1, size.Width), Math.Max(1, size.Height), PixelFormat.Format32bppArgb);
            using (Graphics g = Graphics.FromImage(bitmap))
            {
                g.Clear(System.Drawing.Color.Transparent);
            }

            return bitmap;
        }

        private void SelectThumbnailItemForCurrentPage(bool ensureVisible)
        {
            if (thumbnailsListView == null || currentPage < 1)
            {
                return;
            }

            if (syncThumbnailSelectionFromPage)
            {
                return;
            }

            syncThumbnailSelectionFromPage = true;
            try
            {
                var item = FindThumbnailListItemByPageNumber(currentPage);
                if (item == null)
                {
                    thumbnailsListView.SelectedItems.Clear();
                    return;
                }

                if (thumbnailsListView.SelectedItems.Count != 1 || thumbnailsListView.SelectedItems[0] != item)
                {
                    thumbnailsListView.SelectedItems.Clear();
                    item.Selected = true;
                }

                if (ensureVisible)
                {
                    item.EnsureVisible();
                }
            }
            finally
            {
                syncThumbnailSelectionFromPage = false;
            }
        }

        private ListViewItem FindThumbnailListItemByPageNumber(int pageNumber)
        {
            if (thumbnailsListView == null)
            {
                return null;
            }

            return thumbnailsListView.Items
                .Cast<ListViewItem>()
                .FirstOrDefault(item => item.Tag is int page && page == pageNumber);
        }

        private void ThumbnailsListView_SelectedIndexChanged(object sender, EventArgs e)
        {
            if (syncThumbnailSelectionFromPage || syncPageSelectionFromThumbnail)
            {
                return;
            }

            if (thumbnailsListView.SelectedItems.Count == 0)
            {
                return;
            }

            if (!(thumbnailsListView.SelectedItems[0].Tag is int selectedPage) || selectedPage < 1 || selectedPage > numPages)
            {
                return;
            }

            ListViewItem target = FindListViewItemByPageNumber(selectedPage);
            if (target != null)
            {
                syncPageSelectionFromThumbnail = true;
                try
                {
                    ForcePageListSelection(target);
                    target.EnsureVisible();
                }
                finally
                {
                    syncPageSelectionFromThumbnail = false;
                }
                return;
            }

            currentPage = selectedPage;
            ReloadRefreshCurrentPage();
            UpdateNavigationButtons(currentPage);
            UpdateSelectionNavigationButtons();
            UpdateSearchNavigationButtons();
            SyncPagesListSelectionToCurrentPage(ensureVisible: false);
        }

        private void SyncPagesListSelectionToCurrentPage(bool ensureVisible)
        {
            if (pagesListView == null || pagesListView.Items.Count == 0 || currentPage < 1)
            {
                return;
            }

            ListViewItem target = null;
            if ((string)filterComboBox.SelectedItem == allComboItem &&
                currentPage <= pagesListView.Items.Count)
            {
                target = pagesListView.Items[currentPage - 1];
            }
            else
            {
                target = FindListViewItemByPageNumber(currentPage);
            }

            if (target == null)
            {
                return;
            }

            ForcePageListSelection(target);
            if (ensureVisible)
            {
                target.EnsureVisible();
            }
        }

        private void ThumbnailViewportTimer_Tick(object sender, EventArgs e)
        {
            if (!IsThumbnailsTabSelected())
            {
                return;
            }

            EnsureThumbnailGeneration();
        }

        private void ThumbnailsListView_DrawItem(object sender, DrawListViewItemEventArgs e)
        {
            if (e?.Item == null)
            {
                return;
            }

            bool isSelected = e.Item.Selected;
            var theme = CurrentTheme;
            System.Drawing.Color itemBackColor = isSelected ? theme.SelectionBackColor : thumbnailsListView.BackColor;
            System.Drawing.Color itemTextColor = isSelected ? theme.TextPrimaryColor : thumbnailsListView.ForeColor;
            using (var backBrush = new SolidBrush(itemBackColor))
            {
                e.Graphics.FillRectangle(backBrush, e.Bounds);
            }

            Image image = null;
            if (e.Item.ImageIndex >= 0 && e.Item.ImageIndex < thumbnailsImageList.Images.Count)
            {
                image = thumbnailsImageList.Images[e.Item.ImageIndex];
            }
            else if (!string.IsNullOrEmpty(e.Item.ImageKey) && thumbnailsImageList.Images.ContainsKey(e.Item.ImageKey))
            {
                image = thumbnailsImageList.Images[e.Item.ImageKey];
            }

            int maxThumbWidth = Math.Max(1, e.Bounds.Width - 2);
            int maxThumbHeight = Math.Max(1, e.Bounds.Height - 32);
            int thumbWidth = Math.Min(image?.Width ?? thumbnailsImageList.ImageSize.Width, maxThumbWidth);
            int thumbHeight = Math.Min(image?.Height ?? thumbnailsImageList.ImageSize.Height, maxThumbHeight);
            int thumbX = e.Bounds.Left + Math.Max(0, (e.Bounds.Width - thumbWidth) / 2);
            int thumbY = e.Bounds.Top + 10;
            var thumbRect = new DrawingRectangle(thumbX, thumbY, thumbWidth, thumbHeight);

            if (image != null)
            {
                e.Graphics.DrawImage(image, thumbRect);
            }

            int pageNumber = e.Item.Tag is int taggedPage ? taggedPage : -1;
            Size contentSize = thumbnailContentSizeByPage.TryGetValue(pageNumber, out var cachedSize)
                ? cachedSize
                : thumbnailsImageList.ImageSize;
            int contentWidth = Math.Max(1, Math.Min(contentSize.Width, thumbRect.Width));
            int contentHeight = Math.Max(1, Math.Min(contentSize.Height, thumbRect.Height));
            int contentX = thumbRect.Left + (thumbRect.Width - contentWidth) / 2;
            int contentY = thumbRect.Top + (thumbRect.Height - contentHeight) / 2;
            var contentRect = new DrawingRectangle(contentX, contentY, contentWidth, contentHeight);

            using (var borderPen = new Pen(isSelected ? theme.DangerBackColor : theme.BorderColor, isSelected ? 2f : 1.25f))
            {
                e.Graphics.DrawRectangle(borderPen, contentRect.X, contentRect.Y, Math.Max(1, contentRect.Width - 1), Math.Max(1, contentRect.Height - 1));
            }

            int fontHeight = (e.Item.Font ?? thumbnailsListView.Font).Height;
            int textHeight = Math.Max(fontHeight + 4, 20);
            int textY = Math.Min(thumbRect.Bottom + 8, e.Bounds.Bottom - textHeight - 2);
            var textRect = new DrawingRectangle(
                e.Bounds.Left + 2,
                textY,
                Math.Max(1, e.Bounds.Width - 4),
                textHeight);

            TextRenderer.DrawText(
                e.Graphics,
                e.Item.Text ?? string.Empty,
                e.Item.Font ?? thumbnailsListView.Font,
                textRect,
                itemTextColor,
                TextFormatFlags.HorizontalCenter | TextFormatFlags.VerticalCenter | TextFormatFlags.SingleLine | TextFormatFlags.EndEllipsis);

            if (isSelected)
            {
                using (var selectionBorderPen = new Pen(System.Drawing.Color.Black, 1f))
                {
                    e.Graphics.DrawRectangle(
                        selectionBorderPen,
                        e.Bounds.X,
                        e.Bounds.Y,
                        Math.Max(1, e.Bounds.Width - 1),
                        Math.Max(1, e.Bounds.Height - 1));
                }
            }

            if ((e.State & ListViewItemStates.Focused) == ListViewItemStates.Focused)
            {
                ControlPaint.DrawFocusRectangle(e.Graphics, e.Bounds, itemTextColor, itemBackColor);
            }
        }

        private void ReloadRefreshCurrentPage()
        {
            pageNumberTextBox.Text = currentPage.ToString();
            pageNumberTextBox.Refresh();

            CalculateMinScaleFactor(currentPage);
            CalculateMaxScaleFactor();

            if ((scaleFactor < minScaleFactor) || minScaleButton)
            {
                scaleFactor = minScaleFactor;
            }
            else if ((scaleFactor > maxScaleFactor) || maxScaleButton)
            {
                scaleFactor = maxScaleFactor;
            }
            pagingTimer.Stop();
            pagingTimer.Start();
            SelectThumbnailItemForCurrentPage(ensureVisible: IsThumbnailsTabSelected());
        }


        private void PagesListView_SelectedIndexChanged(object sender, EventArgs e)
        {
            // If at least one element is selected
            if (pagesListView.SelectedItems.Count > 0)
            {
                // Take the first selected item
                ListViewItem selectedItem = pagesListView.SelectedItems[0];
                if (DebugLogEnabled)
                {
                    LogDebug($"PagesList selected count={pagesListView.SelectedItems.Count} item={DescribePageListItem(selectedItem)}");
                }


                // Item text, e.g. "Page 1"
                //string text = selectedItem.Text;


                // If we use Tag to store number:
                currentPage = ((PageItemStatus)selectedItem.Tag).PageNumber;

                ReloadRefreshCurrentPage();

                

                PageItemStatus status = allPageStatuses[currentPage - 1];
                // Check whether current page has selections
                bool hasSelectionsForThisPage = redactionBlocks.Any(rb => rb.PageNumber == currentPage);
                bool hasSearchResultsForThisPage = searchLocations.Any(sr => sr.PageNumber == currentPage);
                bool markedForDeletionForThisPage = pagesToRemove.Contains(currentPage);
                bool hasObjectsForThisPage = HasAnyObjectsOnPage(currentPage);

                status.HasSelections = hasSelectionsForThisPage;
                status.HasSearchResults = hasSearchResultsForThisPage;
                status.MarkedForDeletion = markedForDeletionForThisPage;
                status.HasObjects = hasObjectsForThisPage;
                status.HasRotation = pageRotationOffsets.ContainsKey(currentPage);

                //UpdateItemTag(selectedItem, pageNumber, hasSelectionsForThisPage, hasSearchResultsForThisPage, markedForDeletionForThisPage, hasObjectsForThisPage);

                //if ((string)filterComboBox.SelectedItem == allComboItem)
                //{
                    // only refresh this row
                    //ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                UpdateItemTag(selectedItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                //}
                //else
                //{
                    // rebuild list according to filter
                //    ApplyFilter((string)filterComboBox.SelectedItem);
                //}

                if (hasSearchResultsForThisPage)
                {
                    currentLocationIndex = searchLocations.FindIndex(location => location.PageNumber == currentPage);
                    pdfViewer.Invalidate();
                }

                // Enable/disable button depending on whether there are selections
                clearPageButton.Enabled = hasSelectionsForThisPage;
                UpdateNavigationButtons(currentPage);
                UpdateSelectionNavigationButtons();
                UpdateSearchNavigationButtons();
                //pagesListView.Invalidate();
                pagesListView.Invalidate(selectedItem.Bounds);
                return;
            }

            if (DebugLogEnabled)
            {
                LogDebug("PagesList selected count=0");
            }
        }

        private Font CreatePreviewBadgeFont(float sizeInPoints)
        {
            try
            {
                return new Font("Segoe UI", sizeInPoints, FontStyle.Bold, GraphicsUnit.Point);
            }
            catch
            {
                return new Font(this.Font.FontFamily, sizeInPoints, FontStyle.Bold, GraphicsUnit.Point);
            }
        }

        private void PagesListView_MouseUp(object sender, MouseEventArgs e)
        {
            if (e.Button != MouseButtons.Left)
            {
                return;
            }

            if (pagesListView.Items.Count == 0)
            {
                return;
            }

            ListViewItem hitItem = pagesListView.HitTest(e.Location).Item;
            if (DebugLogEnabled)
            {
                LogDebug(
                    $"PagesList mouseup x={e.X} y={e.Y} hit={DescribePageListItem(hitItem)} selectedBefore={pagesListView.SelectedItems.Count} currentPage={currentPage}");
            }

            // Let native ListView finish processing click first.
            BeginInvoke(new Action(() =>
            {
                if (pagesListView.IsDisposed)
                {
                    return;
                }

                if (pagesListView.SelectedItems.Count > 0)
                {
                    if (DebugLogEnabled)
                    {
                        LogDebug($"PagesList mouseup post selected={DescribePageListItem(pagesListView.SelectedItems[0])}");
                    }
                    return;
                }

                // Keep stable selection for clicks in empty area / non-hit zones.
                ListViewItem target = hitItem
                    ?? FindListViewItemByPageNumber(currentPage)
                    ?? pagesListView.Items[0];

                if (DebugLogEnabled)
                {
                    LogDebug($"PagesList restore selection target={DescribePageListItem(target)}");
                }

                ForcePageListSelection(target);
            }));
        }

        private void ForcePageListSelection(ListViewItem item)
        {
            if (item == null || item.ListView != pagesListView)
            {
                return;
            }

            if (pagesListView.SelectedItems.Count != 1 || pagesListView.SelectedItems[0] != item || !item.Selected)
            {
                pagesListView.SelectedItems.Clear();
                item.Selected = true;
            }

            item.Focused = true;
        }

        private string DescribePageListItem(ListViewItem item)
        {
            if (item == null)
            {
                return "null";
            }

            string page = item.Tag is PageItemStatus status
                ? status.PageNumber.ToString(CultureInfo.InvariantCulture)
                : "?";
            DrawingRectangle bounds = item.Bounds;
            return $"idx={item.Index} page={page} text=\"{item.Text}\" bounds={bounds.Left},{bounds.Top},{bounds.Width},{bounds.Height}";
        }



        private void ZoomAtPanelCenter(bool zoomIn)
        {
            // Assume "panel" is mainAppSplitContainer.Panel2 
            // i ma AutoScroll = true.
            this.Cursor = Cursors.WaitCursor;
            ZoomPanel panel = mainAppSplitContainer.Panel2.Controls[0] as ZoomPanel;

            // (A) Calculate the center of the visible "panel" area in its layout (scroll + half client).
            // Note: panel.HorizontalScroll.Value + panel.ClientSize.Width/2 gives us
            // center *relative to top-left corner* in "ScrollValue" pixels.
            int centerScreenX = panel.HorizontalScroll.Value + (panel.ClientSize.Width / 2);
            int centerScreenY = panel.VerticalScroll.Value + (panel.ClientSize.Height / 2);

            // (B) Transform this to "document" coordinates (before changing scaleFactor).
            // Because docCoordX = screenX / oldScale (assuming pdfViewer.Location = (0,0)).
            float docCoordX = centerScreenX / scaleFactor;
            float docCoordY = centerScreenY / scaleFactor;

            // (C) Change scaleFactor (e.g. +/- 0.2)
            if (zoomIn)
                scaleFactor += percentScaleFactor;
            else
                scaleFactor -= percentScaleFactor;

            CalculateMinScaleFactor(currentPage);
            CalculateMaxScaleFactor();

            if (scaleFactor < minScaleFactor)
            {
                minScaleButton = true;
                maxScaleButton = false;
                scaleFactor = minScaleFactor;
            }
            else
            {
                minScaleButton = false;
            }

            if (scaleFactor > maxScaleFactor)
            {
                minScaleButton = false;
                maxScaleButton = true;
                scaleFactor = maxScaleFactor;
            }
            else
            {
                maxScaleButton = false;
            }


            // (D) Call page re-display
            //     (this method sets pdfViewer.Image = ... and pdfViewer.Size = ...)
            DisplayPdfPage(currentPage);

            // (E) Now we want to set scroll so that docCoordX/docCoordY
            //     is again in the center of the screen.
            int newScrollX = (int)(docCoordX * scaleFactor) - (panel.ClientSize.Width / 2);
            int newScrollY = (int)(docCoordY * scaleFactor) - (panel.ClientSize.Height / 2);

            // Protection against exceeding allowable scroll range
            if (newScrollX < panel.HorizontalScroll.Minimum) newScrollX = panel.HorizontalScroll.Minimum;
            if (newScrollX > panel.HorizontalScroll.Maximum) newScrollX = panel.HorizontalScroll.Maximum;
            if (newScrollY < panel.VerticalScroll.Minimum) newScrollY = panel.VerticalScroll.Minimum;
            if (newScrollY > panel.VerticalScroll.Maximum) newScrollY = panel.VerticalScroll.Maximum;

            // Set scroll:
            panel.AutoScrollPosition = new Point(newScrollX, newScrollY);
            // Or: panel.HorizontalScroll.Value = newScrollX; panel.VerticalScroll.Value = newScrollY;
            this.Cursor = Cursors.Default;
        }



        private void ZoomOutButton_Click(object sender, EventArgs e)
        {
            ZoomAtPanelCenter(false);
        }

        private void ZoomInButton_Click(object sender, EventArgs e)
        {
            ZoomAtPanelCenter(true);
        }


        private void ClearPagesToRemove()
        {
            foreach (int pageNum in pagesToRemove)
            {
                pagesListView.Items[pageNum - 1].BackColor = CurrentTheme.SectionBackColor;
                if (pagesListView.Items[pageNum - 1].ForeColor != System.Drawing.Color.Red)
                {
                    pagesListView.Items[pageNum - 1].ForeColor = CurrentTheme.TextPrimaryColor;
                }
            }
            pagesToRemove.Clear();
            UpdateRemovePageButtonVisual(false);
        }

        private void LoadRedactionBlocks(string inputProjectPathTemp, bool registerAsProject = true)
        {
            if (HasUnsavedProjectContent())
            {
                string msqOutText = Resources.Msg_Confirm_DiscardUnsavedRedactions;
                DialogResult result = MessageBox.Show(this,
                    msqOutText,
                    Resources.Title_Confirmation,
                    MessageBoxButtons.YesNo,
                    MessageBoxIcon.Exclamation,
                    MessageBoxDefaultButton.Button2
                );

                if (result == DialogResult.No)
                {
                    return;
                }
            }

            BeginBusyCursor();
            try
            {

            if (File.Exists(inputProjectPathTemp))
            {
                string json = File.ReadAllText(inputProjectPathTemp);

                try
                {
                    ProjectData projectData = JsonConvert.DeserializeObject<ProjectData>(json);
                    var filePath = projectData.FilePath ?? "";

                    if (filePath !="" && filePath != inputPdfPath)
                    {
                        inputPdfPath = filePath;
                        LoadPdf();
                    }

                    if (filePath == "")
                    {
                        MessageBox.Show(this,
                            Resources.Msg_OpenPdfFirst,
                            Resources.Title_Warning,
                            MessageBoxButtons.OK,
                            MessageBoxIcon.Exclamation
                        );
                        return;
                    }
                    List<RedactionBlock> redactionBlocksJson = projectData.RedactionBlocks ?? new List<RedactionBlock>();
                    List<CommentAnnotation> commentAnnotationsJson = (projectData.CommentAnnotations ?? new List<CommentAnnotation>())
                        .Where(obj => obj != null && obj.PageNumber >= 1 && obj.PageNumber <= numPages)
                        .ToList();
                    HashSet<int> pagesToRemoveJson = projectData.PagesToRemove ?? new HashSet<int>();
                    List<TextAnnotation> textAnnotationsJson = projectData.TextAnnotations ?? new List<TextAnnotation>();
                    List<RasterObject> rasterObjectsJson = (projectData.RasterObjects ?? new List<RasterObject>())
                        .Where(obj => obj != null && obj.PageNumber >= 1 && obj.PageNumber <= numPages)
                        .ToList();
                    List<ArrowObject> arrowObjectsJson = (projectData.ArrowObjects ?? new List<ArrowObject>())
                        .Where(obj => obj != null && obj.PageNumber >= 1 && obj.PageNumber <= numPages)
                        .ToList();
                    List<VectorShapeObject> vectorShapesJson = (projectData.VectorShapes ?? new List<VectorShapeObject>())
                        .Where(obj => obj != null && obj.PageNumber >= 1 && obj.PageNumber <= numPages)
                        .ToList();
                    Dictionary<int, int> rotationOffsetsJson = projectData.PageRotationOffsets ?? new Dictionary<int, int>();
                    List<string> signaturesToRemoveJson = projectData.SignaturesToRemove;
                    string signaturesMode = projectData.SignaturesMode;
                    autoFootnotesEnabled = projectData.AutoFootnotesEnabled ?? Properties.Settings.Default.AutoFootnotesEnabled;
                    if (!string.IsNullOrWhiteSpace(projectData.ExclusionAuthority))
                    {
                        exclusionAuthorityName = projectData.ExclusionAuthority.Trim();
                        SaveExclusionAuthorityUserSetting(exclusionAuthorityName);
                    }
                    ApplyAutomaticFootnotesMenuState();
                    ApplyAddObjectsByPageRotationMenuState();

                    if (redactionBlocksJson.Count > 0)
                    {
                        int maxPageNumber = redactionBlocksJson.Max(rb => rb.PageNumber);
                        if (maxPageNumber > numPages)
                        {
                            MessageBox.Show(this, Resources.Err_SelectValidProjectFile, Resources.Title_Warning, MessageBoxButtons.OK, MessageBoxIcon.Exclamation);
                            return;
                        }
                    }
 
                    ClearRedactionBlocks();
                    redactionBlocks = redactionBlocksJson;
                    foreach (var block in redactionBlocks)
                    {
                        NormalizeRedactionBlockMetadata(block);
                        EnsureRedactionBlockTimestamps(block);
                    }

                    ClearCommentAnnotations();
                    commentAnnotations = commentAnnotationsJson;
                    foreach (var comment in commentAnnotations)
                    {
                        NormalizeCommentAnnotation(comment);
                    }

                    ClearPagesToRemove();
                    pagesToRemove = pagesToRemoveJson;

                    ClearTextAnnotations();
                    textAnnotations = textAnnotationsJson; 
                    foreach (var annotation in textAnnotations)
                    {
                        EnsureTextAnnotationTimestamps(annotation);
                    }

                    ClearRasterObjects();
                    rasterObjects = rasterObjectsJson;
                    foreach (var rasterObject in rasterObjects)
                    {
                        rasterObject.Rotation = NormalizeRotation(rasterObject.Rotation);
                        rasterObject.Opacity = NormalizeOpacity(rasterObject.Opacity);
                        GetResolvedRasterInitialBounds(rasterObject);
                        ConstrainRasterObjectToPage(rasterObject);
                    }

                    ClearArrowObjects();
                    arrowObjects = arrowObjectsJson;
                    foreach (var arrowObject in arrowObjects)
                    {
                        if (string.IsNullOrWhiteSpace(arrowObject.Id))
                        {
                            arrowObject.Id = Guid.NewGuid().ToString("N");
                        }

                        if (!IsArrowColorValid(arrowObject))
                        {
                            arrowObject.LineColorArgb = DefaultArrowColor.ToArgb();
                        }

                        arrowObject.Thickness = NormalizeArrowThickness(arrowObject.Thickness);
                        arrowObject.HeadLength = NormalizeArrowHeadLength(arrowObject.HeadLength);
                        arrowObject.HeadWidth = NormalizeArrowHeadWidth(arrowObject.HeadWidth);
                        ConstrainArrowToPage(arrowObject);
                    }

                    ClearVectorShapes();
                    vectorShapes = vectorShapesJson;
                    foreach (var vectorShape in vectorShapes)
                    {
                        NormalizeVectorShape(vectorShape);
                    }
                    LoadProjectObjectLayerOrder(projectData.ObjectLayers);

                    pageRotationOffsets = rotationOffsetsJson
                        .Where(kvp => kvp.Key >= 1 && kvp.Key <= numPages)
                        .Select(kvp => new KeyValuePair<int, int>(kvp.Key, NormalizeRotation(kvp.Value)))
                        .Where(kvp => kvp.Value != 0)
                        .ToDictionary(kvp => kvp.Key, kvp => kvp.Value);

                    hasCustomSignatureSelection = signaturesToRemoveJson != null;
                    signaturesToRemove = signaturesToRemoveJson ?? new List<string>();
                    SyncSignatureSelectionWithAvailableSignatures();
                    UpdateSignatureSelectionMenuState();

                    ApplySignatureModeFromProject(signaturesMode);

                    if (projectData.CurrentPage > 0)
                    {
                        currentPage = Math.Max(1, Math.Min(projectData.CurrentPage, numPages));
                    }

                    if (projectData.ZoomFactor.HasValue && projectData.ZoomFactor.Value > 0)
                    {
                        scaleFactor = projectData.ZoomFactor.Value;
                        pendingScaleFactor = scaleFactor;
                        minScaleButton = false;
                        maxScaleButton = false;
                    }

                    if (projectData.ScrollX.HasValue || projectData.ScrollY.HasValue)
                    {
                        QueuePendingViewScrollRestore(projectData.ScrollX ?? 0, projectData.ScrollY ?? 0);
                    }

                    foreach (var statusItem in allPageStatuses)
                    {
                        statusItem.HasRotation = false;
                    }
                    foreach (var kvp in pageRotationOffsets)
                    {
                        int pageNum = kvp.Key;
                        allPageStatuses[pageNum - 1].HasRotation = true;
                    }

                    ReloadRefreshCurrentPage();

                    pdfViewer.Invalidate();
                    UpdateSelectionNavigationButtons();

                    PageItemStatus status;

                    foreach (var block in redactionBlocks)
                    {
                        status = allPageStatuses[block.PageNumber - 1];
                        var item = pagesListView.Items[block.PageNumber - 1];
                        //bool hasSearchResults = ((PageItemStatus)item.Tag).HasSearchResults;
                        //bool markedForDeletion = ((PageItemStatus)item.Tag).MarkedForDeletion;
                        //bool hasObjects = ((PageItemStatus)item.Tag).HasObjects;
                        status.HasSelections = true;
                        //allPageStatuses.Add(status);
                        //UpdateItemTag(item, block.PageNumber, true, hasSearchResults, markedForDeletion, hasObjects);
                        UpdateItemTag(item, block.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var block in textAnnotations)
                    {
                        status = allPageStatuses[block.PageNumber - 1];
                        var item = pagesListView.Items[block.PageNumber - 1];
                        //bool hasSelections = ((PageItemStatus)item.Tag).HasSelections;
                        //bool hasSearchResults = ((PageItemStatus)item.Tag).HasSearchResults;
                        //bool markedForDeletion = ((PageItemStatus)item.Tag).MarkedForDeletion;
                        //UpdateItemTag(item, block.PageNumber, hasSelections, hasSearchResults, markedForDeletion, true);
                        status.HasObjects = true;
                        UpdateItemTag(item, block.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var comment in commentAnnotations)
                    {
                        status = allPageStatuses[comment.PageNumber - 1];
                        var item = pagesListView.Items[comment.PageNumber - 1];
                        status.HasObjects = true;
                        UpdateItemTag(item, comment.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var rasterObject in rasterObjects)
                    {
                        status = allPageStatuses[rasterObject.PageNumber - 1];
                        var item = pagesListView.Items[rasterObject.PageNumber - 1];
                        status.HasObjects = true;
                        UpdateItemTag(item, rasterObject.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var arrowObject in arrowObjects)
                    {
                        status = allPageStatuses[arrowObject.PageNumber - 1];
                        var item = pagesListView.Items[arrowObject.PageNumber - 1];
                        status.HasObjects = true;
                        UpdateItemTag(item, arrowObject.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var vectorShape in vectorShapes)
                    {
                        status = allPageStatuses[vectorShape.PageNumber - 1];
                        var item = pagesListView.Items[vectorShape.PageNumber - 1];
                        status.HasObjects = true;
                        UpdateItemTag(item, vectorShape.PageNumber, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (var pageNum in pagesToRemove)
                    {
                        status = allPageStatuses[pageNum - 1];
                        if (pageNum == 1)
                        {
                            UpdateRemovePageButtonVisual(true);
                        }
                        var item = pagesListView.Items[pageNum - 1];

                        //bool hasSelections = ((PageItemStatus)item.Tag).HasSelections;
                        //bool hasSearchResults = ((PageItemStatus)item.Tag).HasSearchResults;
                        //bool hasObjects = ((PageItemStatus)item.Tag).HasObjects;
                        //UpdateItemTag(item, pageNum, hasSelections, hasSearchResults, true, hasObjects);
                        //pagesListView.Invalidate();
                        status.MarkedForDeletion = true;
                        UpdateItemTag(item, pageNum, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    foreach (ListViewItem item in pagesListView.Items)
                    {
                        int pageNum = ((PageItemStatus)item.Tag).PageNumber;
                        PageItemStatus currentStatus = allPageStatuses[pageNum - 1];
                        UpdateItemTag(item, pageNum, currentStatus.HasSelections, currentStatus.HasSearchResults, currentStatus.MarkedForDeletion, currentStatus.HasObjects);
                        pagesListView.Invalidate(item.Bounds);
                    }

                    if (numPages > 0)
                    {
                        if ((string)filterComboBox.SelectedItem == allComboItem)
                        {
                            pagesListView.Items[currentPage - 1].Selected = true;
                            pagesListView.Items[currentPage - 1].EnsureVisible();
                        }
                        else
                        {
                            ListViewItem currentItem = FindListViewItemByPageNumber(currentPage);
                            if (currentItem != null)
                            {
                                currentItem.Selected = true;
                                currentItem.EnsureVisible();
                            }
                            else
                            {
                                pagesListView.SelectedItems.Clear();
                            }
                        }
                    }

                    BeginInvoke(new MethodInvoker(() =>
                    {
                        RestoreRightPanelsViewState(projectData.PagesListTopPage, projectData.ThumbnailsTopPage);
                    }));

                    if (registerAsProject)
                    {
                        inputProjectPath = inputProjectPathTemp;
                        //Properties.Settings.Default.LastPapPath = inputProjectPath;
                        //Properties.Settings.Default.Save();
                        projectWasChangedAfterLastSave = false;
                        ResetUndoRedoHistory(resetSavedStateSignature: true);
                        AddRecentFile(inputProjectPathTemp);
                    }
                    else
                    {
                        inputProjectPath = "";
                        lastSavedProjectName = "";
                        projectWasChangedAfterLastSave = true;
                        ResetUndoRedoHistory();
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                        saveProjectAsButton.Enabled = true;
                        saveProjectAsMenuItem.Enabled = true;
                    }

                    UpdateSelectionNavigationButtons();
                    UpdateWindowTitle();
                }
                catch (Exception)
                {
                    UpdateWindowTitle();
                    MessageBox.Show(this, Resources.Err_InvalidProjectFormat, Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Error);
                    return;
                }
            }
            }
            finally
            {
                EndBusyCursor();
            }
        }

        private void SaveProjectAs()
        {
            using (SaveFileDialog saveFileDialog = new SaveFileDialog())
            {
                string filePapName = "";
                if (lastSavedProjectName != "")
                {
                    filePapName = lastSavedProjectName;
                }
                else if (inputProjectPath != "")
                {
                    filePapName = inputProjectPath;
                }
                else
                {
                    filePapName = inputPdfPath;
                }

                saveFileDialog.Filter = Resources.Dialog_Filter_PAP;
                saveFileDialog.Title = string.Format(Resources.Dialog_Title_SavePap, Branding.ProductName);
                saveFileDialog.FileName = $"{System.IO.Path.GetFileNameWithoutExtension(filePapName)}{ProjectFileExtension}";

                if (saveFileDialog.ShowDialog(this) == DialogResult.OK)
                {
                    try
                    {
                        var jsonSettings = new JsonSerializerSettings
                        {
                            Formatting = Formatting.Indented // prettier, indented format
                        };

                        ProjectData projectData = BuildCurrentProjectDataSnapshot(includeViewState: true);

                        // Serialize list to JSON string
                        string json = JsonConvert.SerializeObject(projectData, jsonSettings);

                        // Write to .app file (plain text)
                        lastSavedProjectName = saveFileDialog.FileName;
                        File.WriteAllText(lastSavedProjectName, json);

                        DialogResult result = MessageBox.Show(this,
                            Resources.Msg_ProjectSaved,
                            Resources.Title_Success,
                            MessageBoxButtons.OK,
                            MessageBoxIcon.Information
                        );
                        projectWasChangedAfterLastSave = false;
            saveProjectButton.Enabled = false;
            saveProjectMenuItem.Enabled = false;
                        MarkCurrentStateAsSavedBaseline();
                        Properties.Settings.Default.LastPapPath = lastSavedProjectName;
                        Properties.Settings.Default.Save();
                        UpdateWindowTitle();
                    }
                    catch (Exception ex)
                    {
                        MessageBox.Show(this, string.Format(Resources.Err_Save, ex.Message), Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Error);
                    }
                }
            }

        }

