            {
                int byIdIndex = target.FindIndex(item => item != null && string.Equals(item.Id?.Trim(), id, StringComparison.OrdinalIgnoreCase));
                if (byIdIndex >= 0)
                {
                    target[byIdIndex] = candidate;
                    return;
