            if (!target.Any(item => AreEquivalentVectorShapes(item, candidate)))
            {
                target.Add(candidate);
            }
        }

        private static bool AreEquivalentRedactionBlocks(RedactionBlock left, RedactionBlock right)
        {
            if (left == null || right == null)
            {
                return false;
            }

            if (left.PageNumber != right.PageNumber ||
                !AreSameRectangle(left.Bounds, right.Bounds) ||
                left.FootnoteNumber != right.FootnoteNumber ||
                !string.Equals(left.ScopeId?.Trim(), right.ScopeId?.Trim(), StringComparison.OrdinalIgnoreCase) ||
                !string.Equals(left.ClassificationSource?.Trim(), right.ClassificationSource?.Trim(), StringComparison.OrdinalIgnoreCase) ||
                !string.Equals(left.MatchedTag?.Trim(), right.MatchedTag?.Trim(), StringComparison.OrdinalIgnoreCase) ||
                !string.Equals(left.InterestSubject?.Trim(), right.InterestSubject?.Trim(), StringComparison.OrdinalIgnoreCase) ||
                left.IsMarkerSelection != right.IsMarkerSelection)
            {
                return false;
            }

            List<string> leftBasis = (left.BasisIds ?? new List<string>()).Select(b => b?.Trim()).Where(b => !string.IsNullOrWhiteSpace(b)).ToList();
            List<string> rightBasis = (right.BasisIds ?? new List<string>()).Select(b => b?.Trim()).Where(b => !string.IsNullOrWhiteSpace(b)).ToList();
            if (leftBasis.Count != rightBasis.Count)
            {
                return false;
            }

            for (int i = 0; i < leftBasis.Count; i++)
            {
                if (!string.Equals(leftBasis[i], rightBasis[i], StringComparison.OrdinalIgnoreCase))
                {
                    return false;
                }
            }

            return true;
        }

        private static bool AreEquivalentCommentAnnotations(CommentAnnotation left, CommentAnnotation right)
        {
            return left != null && right != null &&
                   left.PageNumber == right.PageNumber &&
                   AreSameRectangle(left.Bounds, right.Bounds) &&
                   string.Equals(left.CommentText, right.CommentText, StringComparison.Ordinal) &&
                   left.HighlightColorArgb == right.HighlightColorArgb &&
                   left.TextColorArgb == right.TextColorArgb &&
                   left.IsMarkerSelection == right.IsMarkerSelection &&
                   AreSameNullableFloat(left.NoteX, right.NoteX) &&
                   AreSameNullableFloat(left.NoteY, right.NoteY) &&
                   AreSameNullableFloat(left.NoteWidth, right.NoteWidth) &&
                   AreSameNullableFloat(left.NoteHeight, right.NoteHeight);
        }

        private static bool AreEquivalentTextAnnotations(TextAnnotation left, TextAnnotation right)
        {
            return left != null && right != null &&
                   left.PageNumber == right.PageNumber &&
                   string.Equals(left.AnnotationText, right.AnnotationText, StringComparison.Ordinal) &&
                   AreSameRectangle(left.AnnotationBounds, right.AnnotationBounds) &&
                   left.AnnotationColor.ToArgb() == right.AnnotationColor.ToArgb() &&
                   left.AnnotationBackgroundColorArgb == right.AnnotationBackgroundColorArgb &&
                   string.Equals(left.AnnotationContentMode, right.AnnotationContentMode, StringComparison.OrdinalIgnoreCase) &&
                   string.Equals(left.AnnotationRichText, right.AnnotationRichText, StringComparison.Ordinal) &&
                   left.AnnotationAlignment == right.AnnotationAlignment &&
                   left.AnnotationRotation == right.AnnotationRotation &&
                   left.AnnotationIsLocked == right.AnnotationIsLocked &&
                   AreEquivalentFonts(left.AnnotationFont, right.AnnotationFont);
        }

        private static bool AreEquivalentRasterObjects(RasterObject left, RasterObject right)
        {
            return left != null && right != null &&
                   left.PageNumber == right.PageNumber &&
                   AreSameRectangle(left.Bounds, right.Bounds) &&
                   AreSameRectangle(left.InitialBounds, right.InitialBounds) &&
                   NormalizeRotationStatic(left.Rotation) == NormalizeRotationStatic(right.Rotation) &&
                   AreSameFloat(NormalizeOpacityStatic(left.Opacity), NormalizeOpacityStatic(right.Opacity)) &&
                   left.TransparentBackground == right.TransparentBackground &&
                   left.LockAspect == right.LockAspect &&
                   left.IsLocked == right.IsLocked &&
                   string.Equals(left.SourceType, right.SourceType, StringComparison.OrdinalIgnoreCase) &&
                   string.Equals(left.FilePath, right.FilePath, StringComparison.OrdinalIgnoreCase) &&
                   string.Equals(left.MimeType, right.MimeType, StringComparison.OrdinalIgnoreCase) &&
                   ((left.EmbeddedBytes == null && right.EmbeddedBytes == null) ||
                    (left.EmbeddedBytes != null && right.EmbeddedBytes != null && left.EmbeddedBytes.SequenceEqual(right.EmbeddedBytes)));
        }

        private static bool AreEquivalentArrowObjects(ArrowObject left, ArrowObject right)
        {
            return left != null && right != null &&
                   left.PageNumber == right.PageNumber &&
                   AreSamePoint(left.Start, right.Start) &&
                   AreSamePoint(left.End, right.End) &&
                   left.LineColorArgb == right.LineColorArgb &&
                   AreSameFloat(left.Thickness, right.Thickness) &&
                   AreSameFloat(left.HeadLength, right.HeadLength) &&
                   AreSameFloat(left.HeadWidth, right.HeadWidth) &&
                   left.IsLocked == right.IsLocked;
        }

        private static bool AreEquivalentVectorShapes(VectorShapeObject left, VectorShapeObject right)
        {
            if (left == null || right == null ||
                left.PageNumber != right.PageNumber ||
                !string.Equals(left.ShapeType, right.ShapeType, StringComparison.OrdinalIgnoreCase) ||
                left.StrokeColorArgb != right.StrokeColorArgb ||
                !AreSameFloat(left.StrokeWidth, right.StrokeWidth) ||
                left.FillColorArgb != right.FillColorArgb ||
                left.FillPatternColorArgb != right.FillPatternColorArgb ||
                !AreSameFloat(left.FillOpacity, right.FillOpacity) ||
                !string.Equals(left.StrokeStyle, right.StrokeStyle, StringComparison.OrdinalIgnoreCase) ||
                !string.Equals(left.FillPattern, right.FillPattern, StringComparison.OrdinalIgnoreCase) ||
                left.IsLocked != right.IsLocked)
            {
                return false;
            }

            List<PointF> leftPoints = left.Points ?? new List<PointF>();
            List<PointF> rightPoints = right.Points ?? new List<PointF>();
            if (leftPoints.Count != rightPoints.Count)
            {
                return false;
            }

            for (int i = 0; i < leftPoints.Count; i++)
            {
                if (!AreSamePoint(leftPoints[i], rightPoints[i]))
                {
                    return false;
                }
            }

            return true;
        }

        private static bool AreEquivalentFonts(Font left, Font right)
        {
            if (left == null || right == null)
            {
                return left == right;
            }

            return string.Equals(left.FontFamily?.Name, right.FontFamily?.Name, StringComparison.OrdinalIgnoreCase) &&
                   AreSameFloat(left.SizeInPoints, right.SizeInPoints) &&
                   left.Style == right.Style;
        }

        private static bool IsIncomingObjectNewer(DateTime existingUpdatedAtUtc, DateTime incomingUpdatedAtUtc)
        {
            DateTime existing = NormalizeUtcTimestamp(existingUpdatedAtUtc);
            DateTime incoming = NormalizeUtcTimestamp(incomingUpdatedAtUtc);

            if (existing == DateTime.MinValue)
            {
                return true;
            }

            if (incoming == DateTime.MinValue)
            {
                return false;
            }

            return incoming > existing;
        }

        private static DateTime NormalizeUtcTimestamp(DateTime value)
        {
            if (value == DateTime.MinValue || value == DateTime.MaxValue)
            {
                return DateTime.MinValue;
            }

            if (value.Kind == DateTimeKind.Utc)
            {
                return value;
            }

            if (value.Kind == DateTimeKind.Unspecified)
            {
                return DateTime.SpecifyKind(value, DateTimeKind.Utc);
            }

            return value.ToUniversalTime();
        }

        private static bool AreSameRectangle(RectangleF left, RectangleF right)
        {
            return AreSameFloat(left.X, right.X) &&
                   AreSameFloat(left.Y, right.Y) &&
                   AreSameFloat(left.Width, right.Width) &&
                   AreSameFloat(left.Height, right.Height);
        }

        private static bool AreSamePoint(PointF left, PointF right)
        {
            return AreSameFloat(left.X, right.X) && AreSameFloat(left.Y, right.Y);
        }

        private static bool AreSameNullableFloat(float? left, float? right)
        {
            if (!left.HasValue && !right.HasValue)
            {
                return true;
            }

            if (left.HasValue != right.HasValue)
            {
                return false;
            }

            return AreSameFloat(left.Value, right.Value);
        }

        private static int NormalizeRotationStatic(int rotation)
        {
            int normalized = rotation % 360;
            if (normalized < 0)
            {
                normalized += 360;
            }

            return normalized;
        }

        private static float NormalizeOpacityStatic(float opacity)
        {
            if (float.IsNaN(opacity) || float.IsInfinity(opacity))
            {
                return 1f;
            }

            return Math.Max(0f, Math.Min(1f, opacity));
        }

        private List<int> GetPagesWithBlocks()
        {
            var pagesWithBlocks = redactionBlocks
                .Select(rb => rb.PageNumber)
                .Distinct()
                .OrderBy(page => page)
                .ToList();
            return pagesWithBlocks;
        }


        private void UpdateSelectionNavigationButtons()
        {
            var pagesWithBlocks = GetPagesWithBlocks();
            if (!pagesWithBlocks.Any())
            {
                selectionFirstButton.Enabled = false;
                selectionPrevButton.Enabled = false;
                selectionNextButton.Enabled = false;
                selectionLastButton.Enabled = false;
                clearSelectionButton.Enabled = false;
                clearPageButton.Enabled = false;
                return;
            }

            int firstSelectionPage = pagesWithBlocks.First();
            int lastSelectionPage = pagesWithBlocks.Last();

            // If the current page (currentPage) is less than or equal to the first page with blocks,
            // then you cannot go to the previous selection.
            selectionFirstButton.Enabled = currentPage > firstSelectionPage;
            selectionPrevButton.Enabled = currentPage > firstSelectionPage;

            // If the current page is greater than or equal to the last page with blocks,
            // then you cannot go to the next selection.
            selectionNextButton.Enabled = currentPage < lastSelectionPage;
            selectionLastButton.Enabled = currentPage < lastSelectionPage;

            // Check whether current page has selections
            bool hasSelectionsForThisPage = redactionBlocks.Any(rb => rb.PageNumber == currentPage);
            bool canEditCurrentPage = !IsCurrentPageMarkedForDeletion();

            // Enable/disable button depending on whether there are selections
            clearPageButton.Enabled = hasSelectionsForThisPage && canEditCurrentPage;
            clearSelectionButton.Enabled = true;
        }

        private void UpdateSearchNavigationButtons()
        {
            // If no results found, disable all buttons.
            if (searchLocations == null || searchLocations.Count == 0)
            {
                searchFirstButton.Enabled = false;
                searchPrevButton.Enabled = false;
                searchNextButton.Enabled = false;
                searchLastButton.Enabled = false;
                return;
            }

            // Check if there is a search result on the current page preceding the current result.
            bool hasPrevSamePage = currentLocationIndex > 0 && searchLocations[currentLocationIndex - 1].PageNumber == currentPage;
            // Check if there is a result on earlier pages.
            bool hasPrevOtherPage = searchLocations.Any(loc => loc.PageNumber < currentPage);

            // Check if there is a search result on the current page following the current result.
            bool hasNextSamePage = currentLocationIndex < searchLocations.Count - 1 && searchLocations[currentLocationIndex + 1].PageNumber == currentPage;
            // Check if there is a result on following pages.
            bool hasNextOtherPage = searchLocations.Any(loc => loc.PageNumber > currentPage);

            // "First" is enabled when the current result is not the first globally.
            searchFirstButton.Enabled = currentLocationIndex > 0;
            // "Prev" active when we have a result earlier on the same page or on a previous page.
            searchPrevButton.Enabled = hasPrevSamePage || hasPrevOtherPage;
            // "Next" active when we have another result on the same page or on the next page.
            searchNextButton.Enabled = hasNextSamePage || hasNextOtherPage;
            // "Last" is enabled when the current result is not the last globally.
            searchLastButton.Enabled = currentLocationIndex < searchLocations.Count - 1;
        }


        private void SelectionFirstButton_Click(object sender, EventArgs e)
        {
            var pagesWithBlocks = GetPagesWithBlocks();
            if (!pagesWithBlocks.Any())
            {
                return;
            }
            int firstPage = pagesWithBlocks.First();
            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                pagesListView.Items[firstPage - 1].Selected = true;
                pagesListView.Items[firstPage - 1].EnsureVisible();
            } else
            {
                ListViewItem currentItem = FindListViewItemByPageNumber(firstPage);
                if (currentItem != null)
                {
                    currentItem.Selected = true;
                    currentItem.EnsureVisible();
                }
                else
                {
                    currentPage = firstPage;
                    pagesListView.SelectedItems.Clear();
                }
                ReloadRefreshCurrentPage();
            }
            // Update selection buttons state
            UpdateSelectionNavigationButtons();
        }

        private void SelectionPrevButton_Click(object sender, EventArgs e)
        {
            var pagesWithBlocks = GetPagesWithBlocks();
            if (!pagesWithBlocks.Any())
            {
                return;
            }
            int firstPage = pagesWithBlocks.First();
            int previousPage = pagesWithBlocks
                .Where(p => p < currentPage)
                .DefaultIfEmpty(firstPage)    // in case there is no previous, return firstPage or 0
                .LastOrDefault();
            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                pagesListView.Items[previousPage - 1].Selected = true;
                pagesListView.Items[previousPage - 1].EnsureVisible();
            } else
            {
                ListViewItem currentItem = FindListViewItemByPageNumber(previousPage);

                if (currentItem != null)
                {
                    currentItem.Selected = true;
                    currentItem.EnsureVisible();
                }
                else
                {
                    currentPage = previousPage;
                    pagesListView.SelectedItems.Clear();
                }
                ReloadRefreshCurrentPage();
            }

            // Update selection buttons state
            UpdateSelectionNavigationButtons();
        }

        private void SelectionNextButton_Click(object sender, EventArgs e)
        {
            var pagesWithBlocks = GetPagesWithBlocks();
            if (!pagesWithBlocks.Any())
            {
                return;
            }
            int lastPage = pagesWithBlocks.Last();
            int nextPage = pagesWithBlocks
                .Where(p => p > currentPage)
                .DefaultIfEmpty(lastPage)     // in case of no further pages, return lastPage or 0
                .FirstOrDefault();
            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                pagesListView.Items[nextPage - 1].Selected = true;
                pagesListView.Items[nextPage - 1].EnsureVisible();
            } else
            {
                ListViewItem currentItem = FindListViewItemByPageNumber(nextPage);
                if (currentItem != null)
                {
                    currentItem.Selected = true;
                    currentItem.EnsureVisible();
                }
                else
                {
                    currentPage = nextPage;
                    pagesListView.SelectedItems.Clear();
                }
                ReloadRefreshCurrentPage();
            }

            // Update selection buttons state
            UpdateSelectionNavigationButtons();
        }

        private void SelectionLastButton_Click(object sender, EventArgs e)
        {
            var pagesWithBlocks = GetPagesWithBlocks();
            if (!pagesWithBlocks.Any())
            {
                return;
            }
            int lastPage = pagesWithBlocks.Last();
            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                pagesListView.Items[lastPage - 1].Selected = true;
                pagesListView.Items[lastPage - 1].EnsureVisible();
            } else
            {
                ListViewItem currentItem = FindListViewItemByPageNumber(lastPage);
                if (currentItem != null)
                {
                    currentItem.Selected = true;
                    currentItem.EnsureVisible();
                }
                else
                {
                    currentPage = lastPage;
                    pagesListView.SelectedItems.Clear();
                }
                ReloadRefreshCurrentPage();
            }
            // Update selection buttons state
            UpdateSelectionNavigationButtons();
        }

        private void MainWindow_Closing(object sender, CancelEventArgs e)
        {
            if (!suppressCloseConfirmation)
            {
                if (HasOpenedOrSavedProject() && HasUnsavedProjectContent())
                {
                    CloseProjectDecision decision = PromptSaveProjectChangesOnClose();
                    if (decision == CloseProjectDecision.Cancel)
                    {
                        e.Cancel = true;
                    }
                    else if (decision == CloseProjectDecision.Save)
                    {
                        if (!SaveProjectForClose())
                        {
                            e.Cancel = true;
                        }
                    }
                }
                else
                {
                    // Show dialog box with confirmation question
                    string msqOutText = "";
                    if (HasUnsavedProjectContent())
                    {
                        msqOutText += Resources.Msg_Closing_UnsavedSelectionsPrefix;
                    }
                    msqOutText += Resources.Msg_Confirm_CloseApp;

                    if (!PromptConfirmCloseApplication(msqOutText))
                    {
                        e.Cancel = true;
                    }
                }
            }

            if (!e.Cancel)
            {
                PersistCurrentPageToProjectFile();
                PersistResumeState();
            }

            string autoResumeProjectPath = string.Empty;
            if (!e.Cancel)
            {
                TrySaveAutoResumeProjectSnapshot(out autoResumeProjectPath);
            }

            if (inputPdfPath != "")
            {
                Properties.Settings.Default.LastPdfPath = inputPdfPath;
                Properties.Settings.Default.LastPapPath = "";
            }
            if (lastSavedProjectName != "")
            {
                Properties.Settings.Default.LastPapPath = lastSavedProjectName;
            }
            else if (inputProjectPath != "")
            {
                Properties.Settings.Default.LastPapPath = inputProjectPath;
            }
            else if (!string.IsNullOrWhiteSpace(autoResumeProjectPath))
            {
                Properties.Settings.Default.LastPapPath = autoResumeProjectPath;
            }
            Properties.Settings.Default.Save();
        }

        private void MainWindow_Closed(object sender, FormClosedEventArgs e)
        {
            CancelPreviewRender();
            if (!launchStandaloneInstallerAfterClose || standaloneInstallerLaunchAttempted)
            {
                return;
            }

            standaloneInstallerLaunchAttempted = true;
            string msiPath = pendingStandaloneInstallerPath;
            string logPath = pendingStandaloneInstallerLogPath;
            if (string.IsNullOrWhiteSpace(msiPath))
            {
                return;
            }

            try
            {
                string installerArguments = BuildStandaloneInstallerArguments(msiPath, logPath);
                LogDebug($"Starting standalone installer after app close path={msiPath} logPath={(string.IsNullOrWhiteSpace(logPath) ? "-" : logPath)}");
                var psi = new ProcessStartInfo
                {
                    FileName = "msiexec.exe",
                    Arguments = installerArguments,
                    UseShellExecute = true,
                    Verb = "runas"
                };
                var process = Process.Start(psi);
                if (process == null)
                {
                    throw new InvalidOperationException(LocalizedText("Err_StandaloneUpdate_MsiexecNoProcess"));
                }
                LogDebug($"Standalone installer process started path={msiPath} logPath={(string.IsNullOrWhiteSpace(logPath) ? "-" : logPath)}");
            }
            catch (Exception ex)
            {
                LogDebug("Standalone installer start after close failed: " + ex);
                try
                {
                    MessageBox.Show(
                        LocalizedFormat("Err_StandaloneUpdate_StartInstallerFailed", ex.Message),
                        Resources.Title_Error,
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Error);
                }
                catch
                {
                    // Ignore message errors during shutdown.
                }
            }
        }

        private void SaveProjectButton_Click(object sender, EventArgs e)
        {
            //if (redactionBlocks.Count == 0 && pagesToRemove.Count == 0 && textAnnotations.Count ==0)
            //{
            //    MessageBox.Show(this, "Select content or page to remove.", "Information", MessageBoxButtons.OK, MessageBoxIcon.Information);
            //    return;
            //}

            if (lastSavedProjectName == "" && inputProjectPath == "")
            {
                SaveProjectAs();
            }
            else
            {
                try
                {
                    if (projectWasChangedAfterLastSave)
                    {
                        var jsonSettings = new JsonSerializerSettings
                        {
                            Formatting = Formatting.Indented // prettier, indented format
                        };

                        // Serialize list to JSON string
                        if (lastSavedProjectName == "")
                        {
                            lastSavedProjectName = inputProjectPath;
                        }

                        ProjectData projectData = BuildCurrentProjectDataSnapshot(includeViewState: true);

                        // Serialize list to JSON string
                        string json = JsonConvert.SerializeObject(projectData, jsonSettings);

                        File.WriteAllText(lastSavedProjectName, json);
                        projectWasChangedAfterLastSave = false;
                        saveProjectButton.Enabled = false;
                        saveProjectMenuItem.Enabled = false;
                        MarkCurrentStateAsSavedBaseline();
                    }
                }
                catch (Exception ex)
                {
                    MessageBox.Show(this, string.Format(Resources.Err_Save, ex.Message), Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            }
        }

