        private static string GetRasterMimeTypeFromPath(string filePath)
        {
            string extension = Path.GetExtension(filePath)?.ToLowerInvariant();
            switch (extension)
            {
                case ".png":
                    return "image/png";
                case ".jpg":
                case ".jpeg":
                    return "image/jpeg";
                case ".bmp":
                    return "image/bmp";
                case ".gif":
                    return "image/gif";
                case ".tif":
                case ".tiff":
                    return "image/tiff";
                default:
                    return "application/octet-stream";
            }
        }

        private void ResetRasterInteractionState()
        {
            if (isMovingRasterObject || isRotatingRasterObject || isResizingRasterObject)
            {
                this.Cursor = Cursors.Default;
            }
            rasterObjectToMove = null;
            rasterObjectToRotate = null;
            rasterObjectToResize = null;
            isMovingRasterObject = false;
            isRotatingRasterObject = false;
            isResizingRasterObject = false;
            rasterResizeHandle = RasterResizeHandleType.None;
            rasterMouseActionInProgress = false;
            rasterMoveMouseOffset = PointF.Empty;
            rasterMoveStartBounds = RectangleF.Empty;
            rasterRotateStartBounds = RectangleF.Empty;
            rasterResizeStartBounds = RectangleF.Empty;
            rasterResizeAnchorWorld = PointF.Empty;
            rasterResizeStartRotation = 0;
        }

        private void ResetTextRotationInteractionState()
        {
            if (isRotatingTextAnnotation)
            {
                this.Cursor = Cursors.Default;
            }

            isRotatingTextAnnotation = false;
            textRotationInteractionChanged = false;
            annotationToRotate = null;
            textRotationStartValue = 0;
            textRotationStartAngle = 0f;
            textRotationStartCenterDoc = PointF.Empty;
            textRotationStartBounds = RectangleF.Empty;
        }

        private void ResetArrowInteractionState()
        {
            if (isMovingArrowObject || isAdjustingArrowHandle)
            {
                this.Cursor = Cursors.Default;
            }

            arrowObjectToMove = null;
            arrowObjectToAdjust = null;
            isMovingArrowObject = false;
            isAdjustingArrowHandle = false;
            arrowHandleType = ArrowHandleType.None;
            arrowMouseActionInProgress = false;
            arrowInteractionChanged = false;
            arrowMoveStartMouseDoc = PointF.Empty;
            arrowMoveInitialStart = PointF.Empty;
            arrowMoveInitialEnd = PointF.Empty;
        }

        private void ResetVectorInteractionState()
        {
            if (isMovingVectorShape || isAdjustingVectorHandle || isRotatingVectorShape)
            {
                this.Cursor = Cursors.Default;
            }

            vectorShapeToMove = null;
            vectorShapeToAdjust = null;
            vectorShapeToRotate = null;
            isMovingVectorShape = false;
            isAdjustingVectorHandle = false;
            isRotatingVectorShape = false;
            vectorMouseActionInProgress = false;
            vectorInteractionChanged = false;
            vectorHandlePointIndex = -1;
            vectorMoveStartMouseDoc = PointF.Empty;
            vectorMoveInitialPoints.Clear();
            vectorRotateInitialPoints.Clear();
            vectorRotateCenterDoc = PointF.Empty;
            vectorRotationStartAngle = 0f;
        }

        private static float NormalizeArrowThickness(float value)
        {
            if (float.IsNaN(value) || float.IsInfinity(value))
            {
                return DefaultArrowThickness;
            }
            return Math.Max(1f, Math.Min(24f, value));
        }

        private static float NormalizeArrowHeadLength(float value)
        {
            if (float.IsNaN(value) || float.IsInfinity(value))
            {
                return DefaultArrowHeadLength;
            }
            return Math.Max(4f, Math.Min(120f, value));
        }

        private static float NormalizeArrowHeadWidth(float value)
        {
            if (float.IsNaN(value) || float.IsInfinity(value))
            {
                return DefaultArrowHeadWidth;
            }
            return Math.Max(4f, Math.Min(120f, value));
        }

        private static System.Drawing.Color GetArrowColor(ArrowObject arrowObject)
        {
            if (arrowObject == null)
            {
                return System.Drawing.Color.Red;
            }

            try
            {
                return System.Drawing.Color.FromArgb(arrowObject.LineColorArgb);
            }
            catch
            {
                return System.Drawing.Color.Red;
            }
        }

        private static float NormalizeVectorStrokeWidth(float value)
        {
            if (float.IsNaN(value) || float.IsInfinity(value))
            {
                return 2f;
            }

            return Math.Max(0.5f, Math.Min(24f, value));
        }

        private static float NormalizeVectorFillOpacity(float value)
        {
            if (float.IsNaN(value) || float.IsInfinity(value))
            {
                return 0.18f;
            }

            return Math.Max(0f, Math.Min(1f, value));
        }

        private static VectorShapeType ParseVectorShapeType(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return VectorShapeType.Polyline;
            }

            if (Enum.TryParse(value.Trim(), true, out VectorShapeType parsed))
            {
                return parsed;
            }

            return VectorShapeType.Polyline;
        }

        private static VectorShapeStrokeKind ParseVectorStrokeKind(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return VectorShapeStrokeKind.Solid;
            }

            if (Enum.TryParse(value.Trim(), true, out VectorShapeStrokeKind parsed))
            {
                return parsed;
            }

            return VectorShapeStrokeKind.Solid;
        }

        private static VectorFillPatternKind ParseVectorFillPattern(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return VectorFillPatternKind.Solid;
            }

            if (Enum.TryParse(value.Trim(), true, out VectorFillPatternKind parsed))
            {
                return parsed;
            }

            return VectorFillPatternKind.Solid;
        }

        private static DashStyle ToDrawingDashStyle(VectorShapeStrokeKind strokeKind)
        {
            switch (strokeKind)
            {
                case VectorShapeStrokeKind.Dash:
                    return DashStyle.Dash;
                case VectorShapeStrokeKind.Dot:
                    return DashStyle.Dot;
                case VectorShapeStrokeKind.DashDot:
                    return DashStyle.DashDot;
                case VectorShapeStrokeKind.DashDotDot:
                    return DashStyle.DashDotDot;
                default:
                    return DashStyle.Solid;
            }
        }

        private static HatchStyle ToDrawingHatchStyle(VectorFillPatternKind pattern)
        {
            switch (pattern)
            {
                case VectorFillPatternKind.Diagonal:
                    return HatchStyle.ForwardDiagonal;
                case VectorFillPatternKind.Cross:
                    return HatchStyle.Cross;
                case VectorFillPatternKind.Dot:
                    return HatchStyle.DottedGrid;
                default:
                    return HatchStyle.SolidDiamond;
            }
        }

        private static bool HasVisibleVectorColor(int argb)
        {
            return ((argb >> 24) & 0xFF) > 0;
        }

        private static int GetRequiredPointsForShape(VectorShapeType type)
        {
            switch (type)
            {
                case VectorShapeType.Region:
                    return 3;
                case VectorShapeType.Polyline:
                    return 2;
                case VectorShapeType.Rectangle:
                case VectorShapeType.Ellipse:
                case VectorShapeType.Triangle:
                    return 2;
                case VectorShapeType.Arc:
                    return 3;
                default:
                    return 2;
            }
        }

        private static bool IsShapeClosed(VectorShapeType type)
        {
            return type == VectorShapeType.Region
                   || type == VectorShapeType.Rectangle
                   || type == VectorShapeType.Ellipse
                   || type == VectorShapeType.Triangle;
        }

        private static bool ShapeTypeSupportsFill(VectorShapeType type)
        {
            return type == VectorShapeType.Region
                   || type == VectorShapeType.Rectangle
                   || type == VectorShapeType.Ellipse
                   || type == VectorShapeType.Triangle;
        }

        private static bool ShapeTypeSupportsRotationHandle(VectorShapeType type)
        {
            return type != VectorShapeType.Rectangle
                   && type != VectorShapeType.Ellipse
                   && type != VectorShapeType.Triangle;
        }

        private static bool IsTwoPointConstrainedShape(VectorShapeType type)
        {
            return type == VectorShapeType.Rectangle
                   || type == VectorShapeType.Ellipse
                   || type == VectorShapeType.Triangle;
        }

        private static PointF ApplyAltConstraintToSecondPoint(VectorShapeType shapeType, PointF anchor, PointF candidate)
        {
            float dx = candidate.X - anchor.X;
            float dy = candidate.Y - anchor.Y;
            if (Math.Abs(dx) <= 0.0001f && Math.Abs(dy) <= 0.0001f)
            {
                return candidate;
            }

            float signX = dx >= 0f ? 1f : -1f;
            float signY = dy >= 0f ? 1f : -1f;
            float absX = Math.Abs(dx);
            float absY = Math.Abs(dy);

            switch (shapeType)
            {
                case VectorShapeType.Rectangle:
                case VectorShapeType.Ellipse:
                {
                    float side = Math.Max(absX, absY);
                    return new PointF(anchor.X + (signX * side), anchor.Y + (signY * side));
                }

                case VectorShapeType.Triangle:
                {
                    const float heightRatio = 0.8660254f; // sqrt(3)/2 for an equilateral triangle
                    float targetWidth;
                    float targetHeight;
                    if (absX >= absY)
                    {
                        targetWidth = absX;
                        targetHeight = targetWidth * heightRatio;
                    }
                    else
                    {
                        targetHeight = absY;
                        targetWidth = targetHeight / heightRatio;
                    }

                    return new PointF(anchor.X + (signX * targetWidth), anchor.Y + (signY * targetHeight));
                }

                default:
                    return candidate;
            }
        }

        private PointF NormalizeVectorShapeDraftInputPoint(PointF rawPoint)
        {
            if (!IsTwoPointConstrainedShape(activeVectorShapeType))
            {
                return rawPoint;
            }

            if (vectorShapeDraftPoints.Count == 0)
            {
                return rawPoint;
            }

            if ((Control.ModifierKeys & Keys.Alt) != Keys.Alt)
            {
                return rawPoint;
            }

            return ApplyAltConstraintToSecondPoint(activeVectorShapeType, vectorShapeDraftPoints[0], rawPoint);
        }

        private static RectangleF CreateNormalizedRectangle(PointF a, PointF b)
        {
            float left = Math.Min(a.X, b.X);
            float top = Math.Min(a.Y, b.Y);
            float right = Math.Max(a.X, b.X);
            float bottom = Math.Max(a.Y, b.Y);
            return RectangleF.FromLTRB(left, top, right, bottom);
        }

        private static float NormalizeRadians(float angle)
        {
            const float twoPi = (float)(Math.PI * 2.0);
            while (angle < 0f)
            {
                angle += twoPi;
            }
            while (angle >= twoPi)
            {
                angle -= twoPi;
            }
            return angle;
        }

        private static float PositiveAngleDelta(float from, float to)
        {
            float delta = NormalizeRadians(to) - NormalizeRadians(from);
            if (delta < 0f)
            {
                delta += (float)(Math.PI * 2.0);
            }
            return delta;
        }

        private static List<PointF> BuildArcFromThreePoints(PointF start, PointF end, PointF through)
        {
            var result = new List<PointF>();
            float ax = start.X;
            float ay = start.Y;
            float bx = end.X;
            float by = end.Y;
            float cx = through.X;
            float cy = through.Y;

            float d = 2f * ((ax * (by - cy)) + (bx * (cy - ay)) + (cx * (ay - by)));
            if (Math.Abs(d) < 0.0001f)
            {
                result.Add(start);
                if (DistanceBetweenPoints(start, through) > 0.0001f && DistanceBetweenPoints(end, through) > 0.0001f)
                {
                    result.Add(through);
                }
                if (DistanceBetweenPoints(start, end) > 0.0001f)
                {
                    result.Add(end);
                }
                return result;
            }

            float a2 = (ax * ax) + (ay * ay);
            float b2 = (bx * bx) + (by * by);
            float c2 = (cx * cx) + (cy * cy);
            float ux = ((a2 * (by - cy)) + (b2 * (cy - ay)) + (c2 * (ay - by))) / d;
            float uy = ((a2 * (cx - bx)) + (b2 * (ax - cx)) + (c2 * (bx - ax))) / d;

            float radius = DistanceBetweenPoints(new PointF(ux, uy), start);
            if (radius <= 0.0001f)
            {
                result.Add(start);
                if (DistanceBetweenPoints(start, end) > 0.0001f)
                {
                    result.Add(end);
                }
                return result;
            }

            float angleStart = (float)Math.Atan2(start.Y - uy, start.X - ux);
            float angleEnd = (float)Math.Atan2(end.Y - uy, end.X - ux);
            float angleThrough = (float)Math.Atan2(through.Y - uy, through.X - ux);

            float ccwStartToEnd = PositiveAngleDelta(angleStart, angleEnd);
            float ccwStartToThrough = PositiveAngleDelta(angleStart, angleThrough);
            bool throughOnCcwArc = ccwStartToThrough <= ccwStartToEnd;
            float sweep = throughOnCcwArc
                ? ccwStartToEnd
                : -(float)((Math.PI * 2.0) - ccwStartToEnd);

            int segments = Math.Max(24, (int)Math.Ceiling(Math.Abs(sweep) / (Math.PI / 18.0))); // ~10 deg per segment
            for (int i = 0; i <= segments; i++)
            {
                float t = i / (float)segments;
                float angle = angleStart + (sweep * t);
                float x = ux + (radius * (float)Math.Cos(angle));
                float y = uy + (radius * (float)Math.Sin(angle));
                result.Add(new PointF(x, y));
            }

            return result;
        }

        private static List<PointF> BuildVectorShapeRenderPoints(VectorShapeType shapeType, IList<PointF> points)
        {
            var result = new List<PointF>();
            if (points == null || points.Count == 0)
            {
                return result;
            }

            switch (shapeType)
            {
                case VectorShapeType.Polyline:
                case VectorShapeType.Region:
                    result.AddRange(points);
                    return result;

                case VectorShapeType.Rectangle:
                {
                    if (points.Count < 2)
                    {
                        return result;
                    }

                    RectangleF rect = CreateNormalizedRectangle(points[0], points[points.Count - 1]);
                    if (rect.Width <= 0.0001f || rect.Height <= 0.0001f)
                    {
                        return result;
                    }

                    result.Add(new PointF(rect.Left, rect.Top));
                    result.Add(new PointF(rect.Right, rect.Top));
                    result.Add(new PointF(rect.Right, rect.Bottom));
                    result.Add(new PointF(rect.Left, rect.Bottom));
                    return result;
                }

                case VectorShapeType.Triangle:
                {
                    if (points.Count < 2)
                    {
                        return result;
                    }

                    RectangleF rect = CreateNormalizedRectangle(points[0], points[points.Count - 1]);
                    if (rect.Width <= 0.0001f || rect.Height <= 0.0001f)
                    {
                        return result;
                    }

                    result.Add(new PointF(rect.Left + (rect.Width / 2f), rect.Top));
                    result.Add(new PointF(rect.Right, rect.Bottom));
                    result.Add(new PointF(rect.Left, rect.Bottom));
                    return result;
                }

                case VectorShapeType.Ellipse:
                {
                    if (points.Count < 2)
                    {
                        return result;
                    }

                    RectangleF rect = CreateNormalizedRectangle(points[0], points[points.Count - 1]);
                    if (rect.Width <= 0.0001f || rect.Height <= 0.0001f)
                    {
                        return result;
                    }

                    float centerX = rect.Left + (rect.Width / 2f);
                    float centerY = rect.Top + (rect.Height / 2f);
                    float radiusX = rect.Width / 2f;
                    float radiusY = rect.Height / 2f;
                    int segments = shapeType == VectorShapeType.Ellipse ? 48 : 24;
                    float startAngle = shapeType == VectorShapeType.Ellipse ? 0f : 180f;
                    float sweepAngle = shapeType == VectorShapeType.Ellipse ? 360f : -180f;

                    for (int i = 0; i <= segments; i++)
                    {
                        float t = i / (float)segments;
                        float angleDeg = startAngle + (sweepAngle * t);
                        float angleRad = (float)(Math.PI * angleDeg / 180.0);
                        float x = centerX + (radiusX * (float)Math.Cos(angleRad));
                        float y = centerY + (radiusY * (float)Math.Sin(angleRad));
                        result.Add(new PointF(x, y));
                    }

                    return result;
                }

                case VectorShapeType.Arc:
                {
                    if (points.Count >= 3)
                    {
                        return BuildArcFromThreePoints(points[0], points[1], points[2]);
                    }

                    // Backward compatibility for older projects that stored arc as two points.
                    if (points.Count < 2)
                    {
                        return result;
                    }

                    RectangleF rect = CreateNormalizedRectangle(points[0], points[points.Count - 1]);
                    if (rect.Width <= 0.0001f || rect.Height <= 0.0001f)
                    {
                        return result;
                    }

                    float centerX = rect.Left + (rect.Width / 2f);
                    float centerY = rect.Top + (rect.Height / 2f);
                    float radiusX = rect.Width / 2f;
                    float radiusY = rect.Height / 2f;
                    const int segments = 24;
                    const float startAngle = 180f;
                    const float sweepAngle = -180f;

                    for (int i = 0; i <= segments; i++)
                    {
                        float t = i / (float)segments;
                        float angleDeg = startAngle + (sweepAngle * t);
                        float angleRad = (float)(Math.PI * angleDeg / 180.0);
                        float x = centerX + (radiusX * (float)Math.Cos(angleRad));
                        float y = centerY + (radiusY * (float)Math.Sin(angleRad));
                        result.Add(new PointF(x, y));
                    }

                    return result;
                }

                default:
                    result.AddRange(points);
                    return result;
            }
        }

        private void NormalizeVectorShape(VectorShapeObject vectorShape)
        {
            if (vectorShape == null)
            {
                return;
            }

            if (string.IsNullOrWhiteSpace(vectorShape.Id))
            {
                vectorShape.Id = Guid.NewGuid().ToString("N");
            }

            VectorShapeType parsedType = ParseVectorShapeType(vectorShape.ShapeType);
            vectorShape.ShapeType = parsedType.ToString();
            vectorShape.StrokeWidth = NormalizeVectorStrokeWidth(vectorShape.StrokeWidth);
            vectorShape.FillOpacity = NormalizeVectorFillOpacity(vectorShape.FillOpacity);
            vectorShape.StrokeStyle = ParseVectorStrokeKind(vectorShape.StrokeStyle).ToString();
            vectorShape.FillPattern = ParseVectorFillPattern(vectorShape.FillPattern).ToString();
            System.Drawing.Color patternColor = System.Drawing.Color.FromArgb(vectorShape.FillPatternColorArgb);
            vectorShape.FillPatternColorArgb = System.Drawing.Color.FromArgb(patternColor.A, patternColor.R, patternColor.G, patternColor.B).ToArgb();
            vectorShape.Points = (vectorShape.Points ?? new List<PointF>())
                .Where(p => !float.IsNaN(p.X) && !float.IsInfinity(p.X) && !float.IsNaN(p.Y) && !float.IsInfinity(p.Y))
                .ToList();

            if (parsedType == VectorShapeType.Arc && vectorShape.Points.Count > 3)
            {
                vectorShape.Points = vectorShape.Points.Take(3).ToList();
            }

            if (!ShapeTypeSupportsFill(parsedType))
            {
                vectorShape.FillOpacity = 0f;
                System.Drawing.Color fillColor = System.Drawing.Color.FromArgb(vectorShape.FillColorArgb);
                vectorShape.FillColorArgb = System.Drawing.Color.FromArgb(0, fillColor.R, fillColor.G, fillColor.B).ToArgb();
                vectorShape.FillPatternColorArgb = System.Drawing.Color.FromArgb(0, patternColor.R, patternColor.G, patternColor.B).ToArgb();
            }
        }

        private PointF GetArrowScreenPoint(PointF viewPoint)
        {
            return new PointF(viewPoint.X * scaleFactor, viewPoint.Y * scaleFactor);
        }

        private bool TryGetVectorHandleRects(VectorShapeObject vectorShape, out Dictionary<int, RectangleF> handleRects)
        {
            handleRects = null;
            if (vectorShape == null || vectorShape.PageNumber != currentPage || vectorShape.Points == null || vectorShape.Points.Count == 0)
            {
                return false;
            }

            var result = new Dictionary<int, RectangleF>();
            for (int i = 0; i < vectorShape.Points.Count; i++)
            {
                PointF point = vectorShape.Points[i];
                if (float.IsNaN(point.X) || float.IsInfinity(point.X) || float.IsNaN(point.Y) || float.IsInfinity(point.Y))
                {
                    continue;
                }

                PointF screenPoint = new PointF(point.X * scaleFactor, point.Y * scaleFactor);
                result[i] = BuildHandleRect(screenPoint, RasterResizeHandleSize);
            }

            if (result.Count == 0)
            {
                return false;
            }

            handleRects = result;
            return true;
        }

        private bool TryGetVectorHandleAtPoint(VectorShapeObject vectorShape, Point location, out int pointIndex)
        {
            pointIndex = -1;
            if (!TryGetVectorHandleRects(vectorShape, out Dictionary<int, RectangleF> handleRects))
            {
                return false;
            }

            float bestDistanceSq = float.MaxValue;
            foreach (var kvp in handleRects)
            {
                RectangleF hitRect = kvp.Value;
                hitRect.Inflate(2f, 2f);
                if (!hitRect.Contains(location))
                {
                    continue;
                }

                PointF center = new PointF(
                    kvp.Value.X + (kvp.Value.Width / 2f),
                    kvp.Value.Y + (kvp.Value.Height / 2f));
                float dx = location.X - center.X;
                float dy = location.Y - center.Y;
                float distanceSq = (dx * dx) + (dy * dy);
                if (distanceSq < bestDistanceSq)
                {
                    bestDistanceSq = distanceSq;
                    pointIndex = kvp.Key;
                }
            }

            return pointIndex >= 0;
        }

        private static bool SupportsVectorNodeEditing(VectorShapeType shapeType)
        {
            return shapeType == VectorShapeType.Polyline || shapeType == VectorShapeType.Region;
        }

        private static int GetMinNodeCountForVectorShape(VectorShapeType shapeType)
        {
            return shapeType == VectorShapeType.Region ? 3 : 2;
        }

        private bool TryGetVectorSegmentAtPoint(VectorShapeObject vectorShape, Point location, out int insertIndex)
        {
            insertIndex = -1;
            if (vectorShape == null || vectorShape.PageNumber != currentPage || vectorShape.Points == null)
            {
                return false;
            }

            VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
            if (!SupportsVectorNodeEditing(shapeType) || vectorShape.Points.Count < 2)
            {
                return false;
            }

            float tolerance = Math.Max(8f, NormalizeVectorStrokeWidth(vectorShape.StrokeWidth) * scaleFactor + 3f);
            float bestDistance = float.MaxValue;
            int bestSegmentIndex = -1;

            int segmentCount = shapeType == VectorShapeType.Region
                ? vectorShape.Points.Count
                : vectorShape.Points.Count - 1;

            for (int i = 0; i < segmentCount; i++)
            {
                int next = (i + 1) % vectorShape.Points.Count;
                PointF start = new PointF(vectorShape.Points[i].X * scaleFactor, vectorShape.Points[i].Y * scaleFactor);
                PointF end = new PointF(vectorShape.Points[next].X * scaleFactor, vectorShape.Points[next].Y * scaleFactor);
                float distance = DistancePointToSegment(location, start, end);
                if (distance > tolerance || distance >= bestDistance)
                {
                    continue;
                }

                bestDistance = distance;
                bestSegmentIndex = i;
            }

            if (bestSegmentIndex < 0)
            {
                return false;
            }

            insertIndex = bestSegmentIndex + 1;
            if (shapeType == VectorShapeType.Region && bestSegmentIndex == vectorShape.Points.Count - 1)
            {
                // Inserting after the closing segment (last -> first) means append at end.
                insertIndex = vectorShape.Points.Count;
            }

            return true;
        }

        private bool InsertVectorNode(VectorShapeObject vectorShape, int insertIndex, Point location)
        {
            if (vectorShape == null || vectorShape.Points == null)
            {
                return false;
            }

            VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
            if (!SupportsVectorNodeEditing(shapeType))
            {
                return false;
            }

            BeginUndoCapture("Edit shape");

            var points = vectorShape.Points.ToList();
            insertIndex = Math.Max(0, Math.Min(points.Count, insertIndex));

            PointF newPoint = new PointF(location.X / scaleFactor, location.Y / scaleFactor);
            if (snapToGridEnabled)
            {
                newPoint = SnapPointToGrid(newPoint);
            }

            var pageSize = GetPageSizeWithOffset(vectorShape.PageNumber);
            if (pageSize.Width > 0f && pageSize.Height > 0f)
            {
                newPoint = new PointF(
                    Math.Max(0f, Math.Min(pageSize.Width, newPoint.X)),
                    Math.Max(0f, Math.Min(pageSize.Height, newPoint.Y)));
            }

            points.Insert(insertIndex, newPoint);
            vectorShape.Points = points;
            NormalizeVectorShape(vectorShape);
            ConstrainVectorShapeToPage(vectorShape);
            vectorShape.UpdatedAtUtc = DateTime.UtcNow;

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
            CommitUndoCapture();
            return true;
        }

        private bool RemoveVectorNode(VectorShapeObject vectorShape, int nodeIndex)
        {
            if (vectorShape == null || vectorShape.Points == null || nodeIndex < 0 || nodeIndex >= vectorShape.Points.Count)
            {
                return false;
            }

            VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
            if (!SupportsVectorNodeEditing(shapeType))
            {
                return false;
            }

            int minNodeCount = GetMinNodeCountForVectorShape(shapeType);
            if (vectorShape.Points.Count <= minNodeCount)
            {
                return false;
            }

            BeginUndoCapture("Edit shape");

            var points = vectorShape.Points.ToList();
            points.RemoveAt(nodeIndex);
            vectorShape.Points = points;
            NormalizeVectorShape(vectorShape);
            ConstrainVectorShapeToPage(vectorShape);
            vectorShape.UpdatedAtUtc = DateTime.UtcNow;

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
            CommitUndoCapture();
            return true;
        }

        private bool TryShowVectorNodeContextMenu(Point location)
        {
            if (!EnsureCurrentPageEditable(false))
            {
                return false;
            }

            if (GetTotalSelectedObjectsCount() > 1)
            {
                return false;
            }

            VectorShapeObject target = null;
            if (selectedVectorShape != null &&
                selectedVectorShape.PageNumber == currentPage &&
                IsPointNearVectorShape(selectedVectorShape, location))
            {
                target = selectedVectorShape;
            }
            else if (TryGetHitVectorShapeAtPoint(location, out VectorShapeObject hitVectorShape))
            {
                target = hitVectorShape;
            }

            if (target == null || target.IsLocked)
            {
                return false;
            }

            VectorShapeType shapeType = ParseVectorShapeType(target.ShapeType);
            if (!SupportsVectorNodeEditing(shapeType))
            {
                return false;
            }

            bool hasSegment = TryGetVectorSegmentAtPoint(target, location, out int insertIndex);
            bool hasHandle = TryGetVectorHandleAtPoint(target, location, out int nodeIndex);
            int minNodeCount = GetMinNodeCountForVectorShape(shapeType);
            bool canRemove = hasHandle && target.Points != null && target.Points.Count > minNodeCount;

            if (!hasSegment && !hasHandle)
            {
                return false;
            }

            EnsureVectorShapeId(target);
            selectedVectorShape = target;
            ClearGroupSelection();

            var menu = new ContextMenuStrip();
            var addNodeItem = new ToolStripMenuItem(LocalizedText("Vector_Context_AddNode"))
            {
                Enabled = hasSegment
            };
            addNodeItem.Click += (_, __) => InsertVectorNode(target, insertIndex, location);
            menu.Items.Add(addNodeItem);

            var removeNodeItem = new ToolStripMenuItem(LocalizedText("Vector_Context_RemoveNode"))
            {
                Enabled = canRemove
            };
            removeNodeItem.Click += (_, __) => RemoveVectorNode(target, nodeIndex);
            menu.Items.Add(removeNodeItem);

            menu.Items.Add(new ToolStripSeparator());
            var copyObjectItem = new ToolStripMenuItem(Resources.Menu_CopyToClipboard);
            copyObjectItem.Click += (_, __) => TryCopySelectedObjectsToInternalClipboard();
            menu.Items.Add(copyObjectItem);
            var cutObjectItem = new ToolStripMenuItem(GetCutObjectContextMenuText());
            cutObjectItem.Click += (_, __) => CutSelectedObjectsFromContext(useGroupSelection: false, hitObject: target);
            menu.Items.Add(cutObjectItem);
            menu.Items.Add(new ToolStripSeparator());
            var duplicateObjectItem = new ToolStripMenuItem(GetDuplicateObjectContextMenuText())
            {
                Enabled = numPages > 1
            };
            duplicateObjectItem.Click += (_, __) => DuplicateVectorShapeAcrossPages(target);
            menu.Items.Add(duplicateObjectItem);
            var deleteDuplicatedObjectsItem = new ToolStripMenuItem(GetDeleteDuplicatedObjectsContextMenuText())
            {
                Enabled = !string.IsNullOrWhiteSpace(target.DuplicateGroupId)
            };
            deleteDuplicatedObjectsItem.Click += (_, __) => DeleteDuplicatedObjectsByGroupId(target.DuplicateGroupId, target.PageNumber);
            menu.Items.Add(deleteDuplicatedObjectsItem);
            menu.Items.Add(GetDeleteObjectContextMenuText(), null, (_, __) => DeleteObjectFromContext(target));

            menu.Show(pdfViewer, location);
            return true;
        }

        private string GetDuplicateGroupIdForObject(object obj)
        {
            switch (obj)
            {
                case RedactionBlock block:
                    return string.IsNullOrWhiteSpace(block.DuplicateGroupId) ? null : block.DuplicateGroupId.Trim();
                case TextAnnotation textAnnotation:
                    return string.IsNullOrWhiteSpace(textAnnotation.DuplicateGroupId) ? null : textAnnotation.DuplicateGroupId.Trim();
                case CommentAnnotation commentAnnotation:
                    return string.IsNullOrWhiteSpace(commentAnnotation.DuplicateGroupId) ? null : commentAnnotation.DuplicateGroupId.Trim();
                case RasterObject rasterObject:
                    return string.IsNullOrWhiteSpace(rasterObject.DuplicateGroupId) ? null : rasterObject.DuplicateGroupId.Trim();
                case ArrowObject arrowObject:
                    return string.IsNullOrWhiteSpace(arrowObject.DuplicateGroupId) ? null : arrowObject.DuplicateGroupId.Trim();
                case VectorShapeObject vectorShapeObject:
                    return string.IsNullOrWhiteSpace(vectorShapeObject.DuplicateGroupId) ? null : vectorShapeObject.DuplicateGroupId.Trim();
                default:
                    return null;
            }
        }

        private void DeleteObjectFromContext(object hitObject)
        {
            if (hitObject == null)
            {
                return;
            }

            if (hitObject is TextAnnotation textAnnotation)
            {
                DeleteTextObjectWithConfirmation(textAnnotation);
                return;
            }

            if (hitObject is RasterObject rasterObject)
            {
                DeleteRasterObjectWithConfirmation(rasterObject);
                return;
            }

            if (hitObject is ArrowObject arrowObject)
            {
                DeleteArrowObjectWithConfirmation(arrowObject);
                return;
            }

            if (hitObject is VectorShapeObject vectorShapeObject)
            {
                DeleteVectorShapeWithConfirmation(vectorShapeObject);
                return;
            }

            if (hitObject is CommentAnnotation commentAnnotation)
            {
                if (!EnsureCurrentPageEditable(true))
                {
                    return;
                }

                RemoveCommentAnnotation(commentAnnotation);
            }
        }

        private void DeleteDuplicatedObjectsByGroupId(string duplicateGroupId, int sourcePage)
        {
            if (string.IsNullOrWhiteSpace(duplicateGroupId))
            {
                return;
            }

            sourcePage = Math.Max(1, Math.Min(numPages, sourcePage));

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            if (!PromptForDuplicateSelectionOptions(numPages, GetDeleteDuplicatedObjectsDialogTitle(), out int fromPage, out int toPage))
            {
                return;
            }

            int rangeStart = Math.Max(1, Math.Min(fromPage, toPage));
            int rangeEnd = Math.Min(numPages, Math.Max(fromPage, toPage));
            bool IsPageInDeleteRange(int pageNumber)
            {
                return pageNumber >= rangeStart && pageNumber <= rangeEnd;
            }

            string normalizedGroupId = duplicateGroupId.Trim();

            List<TextAnnotation> textToRemove = textAnnotations
                .Where(obj => obj != null &&
                              IsPageInDeleteRange(obj.PageNumber) &&
                              string.Equals(obj.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase))
                .ToList();
            List<RasterObject> rasterToRemove = rasterObjects
                .Where(obj => obj != null &&
                              IsPageInDeleteRange(obj.PageNumber) &&
                              string.Equals(obj.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase))
                .ToList();
            List<ArrowObject> arrowsToRemove = arrowObjects
                .Where(obj => obj != null &&
                              IsPageInDeleteRange(obj.PageNumber) &&
                              string.Equals(obj.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase))
                .ToList();
            List<VectorShapeObject> vectorToRemove = vectorShapes
                .Where(obj => obj != null &&
                              IsPageInDeleteRange(obj.PageNumber) &&
                              string.Equals(obj.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase))
                .ToList();
            List<CommentAnnotation> commentsToRemove = commentAnnotations
                .Where(obj => obj != null &&
                              IsPageInDeleteRange(obj.PageNumber) &&
                              string.Equals(obj.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase))
                .ToList();
            List<RedactionBlock> redactionsToRemove = redactionBlocks
                .Where(obj => obj != null &&
                              IsPageInDeleteRange(obj.PageNumber) &&
                              string.Equals(obj.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase))
                .ToList();

            int totalToRemove =
                textToRemove.Count +
                rasterToRemove.Count +
                arrowsToRemove.Count +
                vectorToRemove.Count +
                commentsToRemove.Count +
                redactionsToRemove.Count;
            if (totalToRemove <= 0)
            {
                return;
            }

            var changedPages = new HashSet<int>();
            foreach (TextAnnotation text in textToRemove) { changedPages.Add(text.PageNumber); }
            foreach (RasterObject raster in rasterToRemove) { changedPages.Add(raster.PageNumber); }
            foreach (ArrowObject arrow in arrowsToRemove) { changedPages.Add(arrow.PageNumber); }
            foreach (VectorShapeObject vectorShape in vectorToRemove) { changedPages.Add(vectorShape.PageNumber); }
            foreach (CommentAnnotation comment in commentsToRemove) { changedPages.Add(comment.PageNumber); }
            foreach (RedactionBlock block in redactionsToRemove) { changedPages.Add(block.PageNumber); }

            var removedTextIds = new HashSet<string>(textToRemove.Where(t => !string.IsNullOrWhiteSpace(t.Id)).Select(t => t.Id), StringComparer.Ordinal);
            var removedRasterIds = new HashSet<string>(rasterToRemove.Where(r => !string.IsNullOrWhiteSpace(r.Id)).Select(r => r.Id), StringComparer.Ordinal);
            var removedArrowIds = new HashSet<string>(arrowsToRemove.Where(a => !string.IsNullOrWhiteSpace(a.Id)).Select(a => a.Id), StringComparer.Ordinal);
            var removedVectorIds = new HashSet<string>(vectorToRemove.Where(v => !string.IsNullOrWhiteSpace(v.Id)).Select(v => v.Id), StringComparer.Ordinal);

            if (redactionsToRemove.Count > 0)
            {
                redactionBlocks.RemoveAll(block =>
                    block != null &&
                    IsPageInDeleteRange(block.PageNumber) &&
                    string.Equals(block.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase));
                UpdateSelectionNavigationButtons();
            }
            if (textToRemove.Count > 0)
            {
                textAnnotations.RemoveAll(obj =>
                    obj != null &&
                    IsPageInDeleteRange(obj.PageNumber) &&
                    string.Equals(obj.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase));
            }
            if (rasterToRemove.Count > 0)
            {
                rasterObjects.RemoveAll(obj =>
                    obj != null &&
                    IsPageInDeleteRange(obj.PageNumber) &&
                    string.Equals(obj.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase));
            }
            if (arrowsToRemove.Count > 0)
            {
                arrowObjects.RemoveAll(obj =>
                    obj != null &&
                    IsPageInDeleteRange(obj.PageNumber) &&
                    string.Equals(obj.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase));
            }
            if (vectorToRemove.Count > 0)
            {
                vectorShapes.RemoveAll(obj =>
                    obj != null &&
                    IsPageInDeleteRange(obj.PageNumber) &&
                    string.Equals(obj.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase));
            }
            if (commentsToRemove.Count > 0)
            {
                commentAnnotations.RemoveAll(obj =>
                    obj != null &&
                    IsPageInDeleteRange(obj.PageNumber) &&
                    string.Equals(obj.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase));
            }

            EnsureObjectLayerOrder();
            objectLayerOrder.RemoveAll(entry =>
                entry != null &&
                ((entry.Type == LayerObjectType.Text && removedTextIds.Contains(entry.Id)) ||
                 (entry.Type == LayerObjectType.Raster && removedRasterIds.Contains(entry.Id)) ||
                 (entry.Type == LayerObjectType.Arrow && removedArrowIds.Contains(entry.Id)) ||
                 (entry.Type == LayerObjectType.VectorShape && removedVectorIds.Contains(entry.Id))));

            if (selectedTextAnnotation != null &&
                string.Equals(selectedTextAnnotation.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase))
            {
                selectedTextAnnotation = null;
            }
            if (selectedRasterObject != null &&
                string.Equals(selectedRasterObject.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase))
            {
                selectedRasterObject = null;
            }
            if (selectedArrowObject != null &&
                string.Equals(selectedArrowObject.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase))
            {
                selectedArrowObject = null;
            }
            if (selectedVectorShape != null &&
                string.Equals(selectedVectorShape.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase))
            {
                selectedVectorShape = null;
            }

            selectedTextAnnotations.RemoveWhere(annotation =>
                annotation != null && string.Equals(annotation.DuplicateGroupId, normalizedGroupId, StringComparison.OrdinalIgnoreCase));
            selectedRasterObjectIds.RemoveWhere(id => removedRasterIds.Contains(id));
            selectedArrowObjectIds.RemoveWhere(id => removedArrowIds.Contains(id));
            selectedVectorShapeIds.RemoveWhere(id => removedVectorIds.Contains(id));

            bool refreshCommentOverlay = commentsToRemove.Count > 0;
            if (refreshCommentOverlay)
            {
                ResetCommentNoteMoveState();
            }

            foreach (int page in changedPages)
            {
                if (page < 1 || page > allPageStatuses.Count)
                {
                    continue;
                }

                allPageStatuses[page - 1].HasSelections = redactionBlocks.Any(block => block != null && block.PageNumber == page);
            }

            FinalizeDuplicatedObjectsOnPages(changedPages, refreshCommentOverlay);
            UpdateCurrentPageObjectsMarker();
        }

        private string CreateDuplicateGroupId()
        {
            duplicationGroupSequence++;
            return string.Format(
                CultureInfo.InvariantCulture,
                "dup-{0}-{1:D6}",
                duplicationSessionId,
                duplicationGroupSequence);
        }

        private void DuplicateRedactionBlock(RedactionBlock sourceBlock)
        {
            if (sourceBlock == null || numPages <= 1)
            {
                return;
            }

            if (!PromptForDuplicateSelectionOptions(numPages, GetDuplicateSelectionDialogTitle(), out int fromPage, out int toPage))
            {
                return;
            }

            List<int> targetPages = BuildDuplicateSelectionTargetPages(sourceBlock.PageNumber, numPages, fromPage, toPage);
            if (targetPages.Count == 0)
            {
                return;
            }

            string duplicateGroupId = CreateDuplicateGroupId();
            HashSet<int> changedPages = new HashSet<int>();
            foreach (int targetPage in targetPages)
            {
                var duplicateBlock = CloneRedactionBlockForPage(sourceBlock, targetPage, duplicateGroupId);
                redactionBlocks.Add(duplicateBlock);
                changedPages.Add(targetPage);
            }

            if (changedPages.Count == 0)
            {
                return;
            }

            foreach (int page in changedPages)
            {
                if (page < 1 || page > allPageStatuses.Count)
                {
                    continue;
                }

                allPageStatuses[page - 1].HasSelections = true;
            }

            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                foreach (int page in changedPages.OrderBy(p => p))
                {
                    if (page < 1 || page > pagesListView.Items.Count)
                    {
                        continue;
                    }

                    PageItemStatus status = allPageStatuses[page - 1];
                    ListViewItem pageItem = pagesListView.Items[page - 1];
                    UpdateItemTag(pageItem, page, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                    pagesListView.Invalidate(pageItem.Bounds);
                }
            }
            else
            {
                ApplyFilter((string)filterComboBox.SelectedItem);
            }

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            UpdateSelectionNavigationButtons();
            renderTimer.Stop();
            renderTimer.Start();
            pdfViewer.Invalidate();
        }

