        private bool ConstrainArrowToPage(ArrowObject arrowObject)
        {
            if (arrowObject == null)
            {
                return false;
            }

            var pageSize = GetPageSizeWithOffset(arrowObject.PageNumber);
            if (pageSize.Width <= 0f || pageSize.Height <= 0f)
            {
                return false;
            }

            PointF start = arrowObject.Start;
            PointF end = arrowObject.End;
            PointF clampedStart = new PointF(
                Math.Max(0f, Math.Min(pageSize.Width, start.X)),
                Math.Max(0f, Math.Min(pageSize.Height, start.Y)));
            PointF clampedEnd = new PointF(
                Math.Max(0f, Math.Min(pageSize.Width, end.X)),
                Math.Max(0f, Math.Min(pageSize.Height, end.Y)));

            bool changed =
                Math.Abs(clampedStart.X - start.X) > 0.001f ||
                Math.Abs(clampedStart.Y - start.Y) > 0.001f ||
                Math.Abs(clampedEnd.X - end.X) > 0.001f ||
                Math.Abs(clampedEnd.Y - end.Y) > 0.001f;

            if (changed)
            {
                arrowObject.Start = clampedStart;
                arrowObject.End = clampedEnd;
            }

            return changed;
        }

        private static bool TryBuildArrowHead(
            PointF startPoint,
            PointF endPoint,
            float headLength,
            float headWidth,
            out PointF leftPoint,
            out PointF rightPoint,
            out PointF lineEndPoint)
        {
            leftPoint = PointF.Empty;
            rightPoint = PointF.Empty;
            lineEndPoint = endPoint;

            float dx = endPoint.X - startPoint.X;
            float dy = endPoint.Y - startPoint.Y;
            float length = (float)Math.Sqrt((dx * dx) + (dy * dy));
            if (length <= 0.001f)
            {
                return false;
            }

            float ux = dx / length;
            float uy = dy / length;
            float actualHeadLength = Math.Min(headLength, length * 0.9f);
            float halfWidth = headWidth / 2f;
            PointF basePoint = new PointF(
                endPoint.X - (ux * actualHeadLength),
                endPoint.Y - (uy * actualHeadLength));
            PointF perp = new PointF(-uy * halfWidth, ux * halfWidth);
            leftPoint = new PointF(basePoint.X + perp.X, basePoint.Y + perp.Y);
            rightPoint = new PointF(basePoint.X - perp.X, basePoint.Y - perp.Y);
            lineEndPoint = new PointF(
                endPoint.X - (ux * actualHeadLength * 0.85f),
                endPoint.Y - (uy * actualHeadLength * 0.85f));
            return true;
        }

        private static float NormalizeAngleDelta(float value)
        {
            while (value > 180f)
            {
                value -= 360f;
            }
            while (value < -180f)
            {
                value += 360f;
            }
            return value;
        }

        private static PointF RotateVector(PointF vector, int angleDegrees)
        {
            double radians = (Math.PI / 180d) * angleDegrees;
            float cos = (float)Math.Cos(radians);
            float sin = (float)Math.Sin(radians);
            return new PointF(
                (vector.X * cos) - (vector.Y * sin),
                (vector.X * sin) + (vector.Y * cos));
        }

        private static string FormatRectFInvariant(RectangleF rect)
        {
            return string.Format(
                CultureInfo.InvariantCulture,
                "{{X={0:0.###},Y={1:0.###},W={2:0.###},H={3:0.###}}}",
                rect.X,
                rect.Y,
                rect.Width,
                rect.Height);
        }

        private static string FormatPointFInvariant(PointF point)
        {
            return string.Format(
                CultureInfo.InvariantCulture,
                "{{X={0:0.###},Y={1:0.###}}}",
                point.X,
                point.Y);
        }

        private RectangleF GetRasterObjectScreenBounds(RasterObject rasterObject)
        {
            return new RectangleF(
                rasterObject.Bounds.X * scaleFactor,
                rasterObject.Bounds.Y * scaleFactor,
                rasterObject.Bounds.Width * scaleFactor,
                rasterObject.Bounds.Height * scaleFactor);
        }

        private RectangleF GetRasterObjectScreenFrameBounds(RasterObject rasterObject)
        {
            RectangleF bounds = GetRasterObjectScreenBounds(rasterObject);
            if (bounds.Width <= 0f || bounds.Height <= 0f)
            {
                return RectangleF.Empty;
            }

            PointF center = new PointF(bounds.X + (bounds.Width / 2f), bounds.Y + (bounds.Height / 2f));
            int rotation = NormalizeRotation(rasterObject.Rotation);
            PointF vx = RotateVector(new PointF(bounds.Width / 2f, 0f), rotation);
            PointF vy = RotateVector(new PointF(0f, bounds.Height / 2f), rotation);

            PointF[] corners = new[]
            {
                new PointF(center.X - vx.X - vy.X, center.Y - vx.Y - vy.Y),
                new PointF(center.X + vx.X - vy.X, center.Y + vx.Y - vy.Y),
                new PointF(center.X + vx.X + vy.X, center.Y + vx.Y + vy.Y),
                new PointF(center.X - vx.X + vy.X, center.Y - vx.Y + vy.Y)
            };

            float minX = corners.Min(p => p.X);
            float maxX = corners.Max(p => p.X);
            float minY = corners.Min(p => p.Y);
            float maxY = corners.Max(p => p.Y);
            return new RectangleF(minX, minY, Math.Max(0f, maxX - minX), Math.Max(0f, maxY - minY));
        }

        private PointF GetRasterObjectScreenCenter(RasterObject rasterObject)
        {
            RectangleF bounds = GetRasterObjectScreenBounds(rasterObject);
            return new PointF(bounds.X + (bounds.Width / 2f), bounds.Y + (bounds.Height / 2f));
        }

        private bool TryGetVectorShapeScreenBounds(VectorShapeObject vectorShape, out RectangleF bounds)
        {
            bounds = RectangleF.Empty;
            if (vectorShape == null || vectorShape.PageNumber != currentPage || vectorShape.Points == null || vectorShape.Points.Count < 2)
            {
                return false;
            }

            PointF[] points = BuildVectorShapeRenderPoints(ParseVectorShapeType(vectorShape.ShapeType), vectorShape.Points)
                .Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor))
                .ToArray();
            if (points.Length < 2)
            {
                return false;
            }

            float minX = points.Min(p => p.X);
            float maxX = points.Max(p => p.X);
            float minY = points.Min(p => p.Y);
            float maxY = points.Max(p => p.Y);
            float width = Math.Max(0f, maxX - minX);
            float height = Math.Max(0f, maxY - minY);
            if (width <= 0.0001f && height <= 0.0001f)
            {
                return false;
            }

            bounds = new RectangleF(minX, minY, Math.Max(1f, width), Math.Max(1f, height));
            return true;
        }

        private bool TryGetVectorRotationHandleRect(VectorShapeObject vectorShape, out RectangleF handleRect, out PointF connectorPoint)
        {
            handleRect = RectangleF.Empty;
            connectorPoint = PointF.Empty;
            VectorShapeType shapeType = ParseVectorShapeType(vectorShape?.ShapeType);
            if (!ShapeTypeSupportsRotationHandle(shapeType))
            {
                return false;
            }

            if (!TryGetVectorShapeScreenBounds(vectorShape, out RectangleF bounds))
            {
                return false;
            }

            PointF center = new PointF(bounds.X + (bounds.Width / 2f), bounds.Y + (bounds.Height / 2f));
            connectorPoint = new PointF(center.X, bounds.Top);
            PointF handleCenter = new PointF(center.X, bounds.Top - RasterRotateHandleOffset);
            handleRect = new RectangleF(
                handleCenter.X - (RasterRotateHandleSize / 2f),
                handleCenter.Y - (RasterRotateHandleSize / 2f),
                RasterRotateHandleSize,
                RasterRotateHandleSize);
            return true;
        }

        private static PointF GetVectorShapeCenterDoc(VectorShapeObject vectorShape)
        {
            if (vectorShape == null || vectorShape.Points == null || vectorShape.Points.Count == 0)
            {
                return PointF.Empty;
            }

            float minX = vectorShape.Points.Min(p => p.X);
            float maxX = vectorShape.Points.Max(p => p.X);
            float minY = vectorShape.Points.Min(p => p.Y);
            float maxY = vectorShape.Points.Max(p => p.Y);
            return new PointF((minX + maxX) / 2f, (minY + maxY) / 2f);
        }

        private static bool TryGetCircumcenter(PointF a, PointF b, PointF c, out PointF center)
        {
            center = PointF.Empty;
            float d = 2f * ((a.X * (b.Y - c.Y)) + (b.X * (c.Y - a.Y)) + (c.X * (a.Y - b.Y)));
            if (Math.Abs(d) < 0.0001f)
            {
                return false;
            }

            float a2 = (a.X * a.X) + (a.Y * a.Y);
            float b2 = (b.X * b.X) + (b.Y * b.Y);
            float c2 = (c.X * c.X) + (c.Y * c.Y);
            float ux = ((a2 * (b.Y - c.Y)) + (b2 * (c.Y - a.Y)) + (c2 * (a.Y - b.Y))) / d;
            float uy = ((a2 * (c.X - b.X)) + (b2 * (a.X - c.X)) + (c2 * (b.X - a.X))) / d;
            center = new PointF(ux, uy);
            return true;
        }

        private static PointF GetVectorShapeRotationCenterDoc(VectorShapeObject vectorShape)
        {
            if (vectorShape == null || vectorShape.Points == null || vectorShape.Points.Count == 0)
            {
                return PointF.Empty;
            }

            VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
            if (shapeType == VectorShapeType.Arc && vectorShape.Points.Count >= 3)
            {
                if (TryGetCircumcenter(vectorShape.Points[0], vectorShape.Points[1], vectorShape.Points[2], out PointF arcCenter))
                {
                    return arcCenter;
                }
            }

            return GetVectorShapeCenterDoc(vectorShape);
        }

        private bool IsPointInsideRasterObject(RasterObject rasterObject, Point location)
        {
            RectangleF frameBounds = GetRasterObjectScreenFrameBounds(rasterObject);
            if (frameBounds.Width <= 0f || frameBounds.Height <= 0f)
            {
                return false;
            }

            return frameBounds.Contains(location);
        }

        private bool TryGetRasterRotationHandleRect(RasterObject rasterObject, out RectangleF handleRect, out PointF connectorPoint)
        {
            handleRect = RectangleF.Empty;
            connectorPoint = PointF.Empty;
            if (rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return false;
            }

            RectangleF bounds = GetRasterObjectScreenBounds(rasterObject);
            if (bounds.Width <= 0f || bounds.Height <= 0f)
            {
                return false;
            }

            PointF center = GetRasterObjectScreenCenter(rasterObject);
            PointF topVector = RotateVector(new PointF(0f, -(bounds.Height / 2f)), NormalizeRotation(rasterObject.Rotation));
            PointF handleVector = RotateVector(new PointF(0f, -(bounds.Height / 2f + RasterRotateHandleOffset)), NormalizeRotation(rasterObject.Rotation));

            connectorPoint = new PointF(center.X + topVector.X, center.Y + topVector.Y);
            PointF handleCenter = new PointF(center.X + handleVector.X, center.Y + handleVector.Y);
            handleRect = new RectangleF(
                handleCenter.X - (RasterRotateHandleSize / 2f),
                handleCenter.Y - (RasterRotateHandleSize / 2f),
                RasterRotateHandleSize,
                RasterRotateHandleSize);

            return true;
        }

        private static RectangleF BuildHandleRect(PointF center, float size)
        {
            return new RectangleF(center.X - (size / 2f), center.Y - (size / 2f), size, size);
        }

        private static bool HasPositiveSize(RectangleF rect)
        {
            return rect.Width > 0f && rect.Height > 0f;
        }

        private static RectangleF InflateRect(RectangleF rect, float padding)
        {
            return new RectangleF(
                rect.X - padding,
                rect.Y - padding,
                rect.Width + (padding * 2f),
                rect.Height + (padding * 2f));
        }

        private static void DrawGroupSelectionOutline(Graphics graphics, RectangleF rect)
        {
            if (graphics == null || rect.Width <= 0f || rect.Height <= 0f)
            {
                return;
            }

            RectangleF outlineRect = InflateRect(rect, 4f);
            using (var pen = new Pen(GroupSelectionColor, 2f))
            {
                pen.DashStyle = System.Drawing.Drawing2D.DashStyle.Dash;
                graphics.DrawRectangle(pen, outlineRect.X, outlineRect.Y, outlineRect.Width, outlineRect.Height);
            }
        }

        private static float NormalizeOpacity(float opacity)
        {
            if (float.IsNaN(opacity) || float.IsInfinity(opacity))
            {
                return 1f;
            }

            if (opacity < 0f)
            {
                return 0f;
            }

            if (opacity > 1f)
            {
                return 1f;
            }

            return opacity;
        }

        private static RectangleF GetResolvedRasterInitialBounds(RasterObject rasterObject)
        {
            if (rasterObject == null)
            {
                return RectangleF.Empty;
            }

            if (!HasPositiveSize(rasterObject.InitialBounds))
            {
                rasterObject.InitialBounds = rasterObject.Bounds;
            }

            return rasterObject.InitialBounds;
        }

