        private void DuplicateRasterObject(RasterObject source)
        {
            if (source == null || source.PageNumber != currentPage)
            {
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            var now = DateTime.UtcNow;
            string duplicateGroupId = CreateDuplicateGroupId();
            RectangleF copyBounds = source.Bounds;
            copyBounds.Offset(12f, 12f);
            var copy = new RasterObject
            {
                Id = Guid.NewGuid().ToString("N"),
                PageNumber = currentPage,
                Bounds = copyBounds,
                InitialBounds = copyBounds,
                Rotation = source.Rotation,
                Opacity = source.Opacity,
                TransparentBackground = source.TransparentBackground,
                LockAspect = source.LockAspect,
                IsLocked = source.IsLocked,
                SourceType = source.SourceType,
                FilePath = source.FilePath,
                EmbeddedBytes = source.EmbeddedBytes == null ? null : (byte[])source.EmbeddedBytes.Clone(),
                MimeType = source.MimeType,
                CreatedAtUtc = now,
                UpdatedAtUtc = now,
                DuplicateGroupId = duplicateGroupId
            };

            ConstrainRasterObjectToPage(copy);
            copy.InitialBounds = copy.Bounds;
            rasterObjects.Add(copy);
            ClearGroupSelection();
            selectedRasterObject = copy;
            selectedTextAnnotation = null;
            selectedArrowObject = null;
            if (currentPage >= 1 && currentPage <= allPageStatuses.Count)
            {
                PageItemStatus status = allPageStatuses[currentPage - 1];
                status.HasObjects = HasAnyObjectsOnPage(currentPage);
                if ((string)filterComboBox.SelectedItem == allComboItem)
                {
                    ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                    UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                    pagesListView.Invalidate(currentItem.Bounds);
                }
                else
                {
                    ApplyFilter((string)filterComboBox.SelectedItem);
                }
            }
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
        }

        private void DuplicateArrowObject(ArrowObject source)
        {
            if (source == null || source.PageNumber != currentPage)
            {
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            PointF start = new PointF(source.Start.X + 12f, source.Start.Y + 12f);
            PointF end = new PointF(source.End.X + 12f, source.End.Y + 12f);
            var now = DateTime.UtcNow;
            string duplicateGroupId = CreateDuplicateGroupId();
            var copy = new ArrowObject
            {
                Id = Guid.NewGuid().ToString("N"),
                PageNumber = currentPage,
                Start = start,
                End = end,
                LineColorArgb = source.LineColorArgb,
                Thickness = NormalizeArrowThickness(source.Thickness),
                HeadLength = NormalizeArrowHeadLength(source.HeadLength),
                HeadWidth = NormalizeArrowHeadWidth(source.HeadWidth),
                IsLocked = source.IsLocked,
                CreatedAtUtc = now,
                UpdatedAtUtc = now,
                DuplicateGroupId = duplicateGroupId
            };

            ConstrainArrowToPage(copy);
            arrowObjects.Add(copy);
            ClearGroupSelection();
            selectedArrowObject = copy;
            selectedRasterObject = null;
            selectedTextAnnotation = null;
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            UpdateCurrentPageObjectsMarker();
            pdfViewer.Invalidate();
        }

        private static bool AreSameFloat(float a, float b)
        {
            return Math.Abs(a - b) < 0.001f;
        }

        private bool RasterObjectChanged(
            RasterObject rasterObject,
            RectangleF newBounds,
            int newRotation,
            float newOpacity,
            bool newTransparentBackground,
            bool newLockAspect,
            bool newIsLocked,
            string newFilePath)
        {
            if (!AreSameFloat(rasterObject.Bounds.X, newBounds.X) ||
                !AreSameFloat(rasterObject.Bounds.Y, newBounds.Y) ||
                !AreSameFloat(rasterObject.Bounds.Width, newBounds.Width) ||
                !AreSameFloat(rasterObject.Bounds.Height, newBounds.Height))
            {
                return true;
            }

            if (NormalizeRotation(rasterObject.Rotation) != NormalizeRotation(newRotation))
            {
                return true;
            }

            if (!AreSameFloat(NormalizeOpacity(rasterObject.Opacity), NormalizeOpacity(newOpacity)))
            {
                return true;
            }

            if (rasterObject.TransparentBackground != newTransparentBackground)
            {
                return true;
            }

            if (rasterObject.LockAspect != newLockAspect || rasterObject.IsLocked != newIsLocked)
            {
                return true;
            }

            if (!string.Equals(rasterObject.FilePath ?? string.Empty, newFilePath ?? string.Empty, StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }

            return false;
        }

